def profession_xp_to_next(skill: int) -> int:
    s = max(1, int(skill))
    return 44 + s * 4


def profession_rank_name(skill: int) -> str:
    s = int(skill)
    if s >= 120:
        return "Master"
    if s >= 90:
        return "Artisan"
    if s >= 60:
        return "Expert"
    if s >= 30:
        return "Journeyman"
    return "Apprentice"


