    pygame.draw.polygon(surface, (120, 150, 170), pts)
    pygame.draw.polygon(surface, (70, 90, 110), pts, 1)
    pygame.draw.line(surface, (200, 210, 220), (x, y - h + 4), (x, y + 4), 1)


