    for ang in range(0, 360, 60):
        rad = math.radians(ang)
        gx = x + int(math.cos(rad) * (r + 3))
        gy = y + int(math.sin(rad) * (r + 3))
        pygame.draw.circle(surface, (140, 140, 150), (gx, gy), max(1, int(2 * scale)))


