def _shop_offset(facing: int) -> Vector2:
    offset_x = -140 if facing >= 0 else 140
    return Vector2(offset_x, 8)


def vendor_shop_position(role_key: str, vendor_pos: Vector2, facing: int) -> Vector2:
    role = role_key.strip().lower()
    if role == "blacksmith":
        return vendor_pos + Vector2(-220 if facing >= 0 else 220, 12)
    return vendor_pos + _shop_offset(facing)


def find_vendor_shop_pos(
    role_key: str,
    vendor_pos: Vector2,
    facing: int,
    walk_bounds: pygame.Rect,
    obstacles: List[pygame.Rect],
) -> Vector2:
    role = role_key.strip().lower()
    base = vendor_shop_position(role_key, vendor_pos, facing)
    radius = VENDOR_SHOP_COLLISION_RADIUS if role == "blacksmith" else 70.0

    offsets = [
        Vector2(0, 0),
        Vector2(60, 0), Vector2(-60, 0),
        Vector2(0, 60), Vector2(0, -60),
        Vector2(90, 40), Vector2(-90, 40),
        Vector2(90, -40), Vector2(-90, -40),
    ]
    if role == "blacksmith":
        offsets = [
            Vector2(0, 0),
            Vector2(120, 0), Vector2(-120, 0),
            Vector2(0, 80), Vector2(0, -80),
            Vector2(160, 60), Vector2(-160, 60),
            Vector2(160, -60), Vector2(-160, -60),
        ]

    for off in offsets:
        cand = base + off
        if is_walkable(cand, walk_bounds, obstacles, radius):
            return cand

    return nearest_walkable(base, walk_bounds, obstacles, radius)


def build_shop_patrol_points(
    shop_pos: Vector2,
    walk_bounds: pygame.Rect,
    obstacles: List[pygame.Rect],
) -> List[Vector2]:
    """Patrol just in front of the shop — left, center, and right waypoints.

    Always returns at least one point (the shop position itself as a last
    resort) so callers can safely index ``[0]`` without risk of IndexError.
    """
    sx = float(shop_pos.x)
    front_y = float(shop_pos.y) + 96.0
    candidates = [
        Vector2(sx - 120.0, front_y),
        Vector2(sx, front_y),
        Vector2(sx + 120.0, front_y),
    ]
    points: List[Vector2] = []
    for c in candidates:
        try:
            points.append(nearest_walkable(c, walk_bounds, obstacles, VENDOR_COLLISION_RADIUS))
        except (TypeError, ValueError):
            points.append(Vector2(c))
    # Guarantee at least one entry so [0] never fails.
    if not points:
        points.append(Vector2(shop_pos))
    return points


# Keep old name as alias so existing call-sites don't break.
build_blacksmith_patrol_points = build_shop_patrol_points


def blacksmith_shop_collision_rects(shop_pos: Vector2) -> List[pygame.Rect]:
    x = int(shop_pos.x)
    ground = int(shop_pos.y)
    # Block the shop footprint while leaving a strip in front for the vendor.
    main = pygame.Rect(x - 200, ground - 180, 420, 170)
    return [main]

def spell_collision_obstacles(spell_effects: List[Dict[str, object]]) -> List[pygame.Rect]:
    blockers: List[pygame.Rect] = []
    for effect in spell_effects:
        if not isinstance(effect, dict):
            continue
        if str(effect.get("kind", "")) != "pillar":
            continue
        if float(effect.get("life", 0.0)) <= 0.0:
            continue
        pos = effect.get("pos")
        if not isinstance(pos, Vector2):
            continue
        size = max(32.0, float(effect.get("size", 64.0)))
        width = int(size)
        height = max(18, int(size * 0.55))
        blockers.append(pygame.Rect(int(pos.x - width * 0.5), int(pos.y - height * 0.5), width, height))
    return blockers


def _seeded_barrel(surface: pygame.Surface, x: int, y: int, seed: int) -> pygame.Rect:
    state = random.getstate()
    random.seed(seed)
    rect = draw_hd_barrel(surface, x, y)
    random.setstate(state)
    return rect


def _draw_blacksmith_shop(surface: pygame.Surface, pos: Vector2, ticks: int, seed: int) -> None:
    x = int(pos.x)
    ground = int(pos.y)


    # ── Back wall: timber-frame with stone lower half ──
    wall = pygame.Rect(x - 190, ground - 180, 380, 160)
    # stone lower section
    stone = pygame.Rect(wall.left, wall.top + 60, wall.width, wall.height - 60)
    for row in range(stone.top, stone.bottom, 12):
        offset = 8 if ((row - stone.top) // 12) % 2 else 0
        for col in range(stone.left + offset, stone.right - 4, 24):
            bw = min(22, stone.right - col)
            bh = min(11, stone.bottom - row)
            shade = 56 + (row * 3 + col * 7 + seed) % 18
            pygame.draw.rect(surface, (shade, shade - 6, shade - 10), (col, row, bw, bh))
            pygame.draw.rect(surface, (shade - 20, shade - 26, shade - 30), (col, row, bw, bh), 1)
    # timber upper section
    upper = pygame.Rect(wall.left, wall.top, wall.width, 62)
    pygame.draw.rect(surface, (62, 48, 36), upper)
    # horizontal beams
    for by in (wall.top, wall.top + 30, wall.top + 60, wall.bottom):
        pygame.draw.rect(surface, (80, 62, 44), (wall.left, by - 3, wall.width, 6))
        pygame.draw.rect(surface, (50, 38, 28), (wall.left, by - 3, wall.width, 6), 1)
    # vertical beams
    for bx in (wall.left, wall.left + 95, wall.centerx, wall.right - 95, wall.right):
        pygame.draw.rect(surface, (80, 62, 44), (bx - 3, wall.top, 6, wall.height))
        pygame.draw.rect(surface, (50, 38, 28), (bx - 3, wall.top, 6, wall.height), 1)
    # cross braces in upper panels
    for px in (wall.left + 3, wall.left + 98, wall.centerx + 3, wall.right - 92):
        pw = 89
        pygame.draw.line(surface, (72, 56, 40), (px, wall.top + 3), (px + pw, wall.top + 57), 2)
        pygame.draw.line(surface, (72, 56, 40), (px + pw, wall.top + 3), (px, wall.top + 57), 2)
    pygame.draw.rect(surface, (42, 34, 26), wall, 2)

    # ── Roof: steep A-frame with overhang ──
    roof_peak = ground - 240
    roof_l = x - 210
    roof_r = x + 210
    roof_base_y = ground - 176
    # roof fill
    roof_pts = [(roof_l, roof_base_y), (x, roof_peak), (roof_r, roof_base_y)]
    pygame.draw.polygon(surface, (52, 44, 36), roof_pts)
    # shingle rows
    for ry in range(roof_peak + 12, roof_base_y, 10):
        t_row = (ry - roof_peak) / max(1, roof_base_y - roof_peak)
