        # Snake (Row 7, Col 0)
        predators.append(make_creature("Snake", 7, 0, 48, radius=10.0, hp_mult=0.6, dmg_mult=1.1))
        # Boar (Row 9, Col 7)
        predators.append(make_creature("Boar", 9, 7, 64, radius=16.0, hp_mult=1.2, dmg_mult=1.1))

        # Passive (Forest Biome)
        # Beaver (Row 5, Col 1)
