def load_ice_archetypes() -> Tuple[List[Dict[str, object]], List[Dict[str, object]]]:
    """Return (ice_predators, ice_passives) using the animals.png sheet with arctic names/stats."""
    try:
        sheet = pygame.image.load("assets/animals.png").convert_alpha()
        tile_size = 32

        def get_sprite(row: int, col: int, scale: int = 64, frost: bool = False):
            if row * tile_size >= sheet.get_height() or col * tile_size >= sheet.get_width():
                return pygame.Surface((scale, scale), pygame.SRCALPHA), pygame.Surface((scale, scale), pygame.SRCALPHA)
            s = extract_sheet_tile(sheet, row, col, tile_size)
            s = pygame.transform.scale(s, (scale, scale))
            # Only apply a very subtle breath-of-frost overlay for non-white animals
            # — no BLEND_RGBA_MULT (that was making every animal look frozen/dead)
            if frost:
                overlay = pygame.Surface((scale, scale), pygame.SRCALPHA)
                overlay.fill((200, 230, 255, 28))
                s.blit(overlay, (0, 0))
            return s, pygame.transform.flip(s, True, False)

        def make_ice(name: str, row: int, col: int, scale: int, frost: bool = False, **extra: object) -> Dict[str, object]:
            sprite, sprite_left = get_sprite(row, col, scale, frost=frost)
            payload: Dict[str, object] = {
                "name": name,
                "sprite": sprite,
                "sprite_left": sprite_left,
                "anim_frames": None,
            }
            payload.update(extra)
            return payload

        ice_predators = [
            make_ice("Arctic Wolf",  3,  4, 64, frost=True,  radius=16.0, hp_mult=1.2,  dmg_mult=1.15),  # r03c04 grey wolf
            make_ice("Frost Bear",   0,  2, 80, frost=False, radius=20.0, hp_mult=1.8,  dmg_mult=1.5),   # r00c02 polar bear (already white)
            make_ice("Ice Lynx",     3,  2, 64, frost=True,  radius=16.0, hp_mult=1.0,  dmg_mult=1.5),   # r03c02 cougar/lynx
            make_ice("Tundra Fox",   4,  5, 56, frost=True,  radius=14.0, hp_mult=0.7,  dmg_mult=0.85),  # r04c05 pale arctic canid
        ]
        ice_passives = [
            # All naturally arctic animals — no heavy tint needed, they look alive
            make_ice("Arctic Hare",    6,  7, 40, frost=False, radius=10.0, speed=170.0, max_hp=14.0),  # r06c07 white hare
            make_ice("Caribou",       15,  1, 72, frost=False, radius=16.0, speed=118.0, max_hp=44.0),  # r15c01 white reindeer
            make_ice("Mountain Goat", 15,  0, 68, frost=False, radius=15.0, speed=105.0, max_hp=38.0),  # r15c00 white goat
            make_ice("Tundra Yak",    10,  3, 80, frost=True,  radius=18.0, speed=95.0,  max_hp=72.0),  # r10c03 yak (cold-weather ungulate)
            make_ice("Snowy Crane",   11,  0, 52, frost=False, radius=12.0, speed=120.0, max_hp=22.0),  # r11c00 grey/white crane
            make_ice("Penguin",       13,  0, 44, frost=False, radius=11.0, speed=88.0,  max_hp=18.0),  # r13c00 penguin
            make_ice("Snow Goose",    14,  3, 46, frost=False, radius=11.0, speed=130.0, max_hp=16.0),  # r14c03 white goose
            make_ice("Snowy Owl",      5,  4, 48, frost=False, radius=11.0, speed=145.0, max_hp=20.0),  # r05c04 owl
            make_ice("Arctic Fox",     4,  3, 52, frost=True,  radius=12.0, speed=155.0, max_hp=22.0),  # r04c03 pale fox variant
            make_ice("Musk Ox",       10,  1, 84, frost=True,  radius=20.0, speed=80.0,  max_hp=88.0),  # r10c01 heavy bovine
        ]
        return ice_predators, ice_passives
    except (pygame.error, FileNotFoundError):
        return load_menacing_archetypes(), load_passive_archetypes()


# ---------------------------------------------------------------------------
# LPC Animated Sprite Sheet Loaders
# ---------------------------------------------------------------------------

LPC_FRAME_W: int = 64
LPC_FRAME_H: int = 64
# LPC standard row layout: anim -> (start_row, frames_per_direction, num_directions)
LPC_ANIMS: Dict[str, Tuple[int, int, int]] = {
    "spellcast": (0,  7, 4),
    "thrust":    (4,  8, 4),
    "walk":      (8,  9, 4),
    "slash":     (12, 6, 4),
    "shoot":     (16, 13, 4),
    "hurt":      (20, 6,  1),
}
LPC_DIRS: List[str] = ["up", "left", "down", "right"]

WOLF_ANIMS: List[str] = ["walk", "run", "bite", "howl", "die"]
def _build_anim_frames(
    sprite: pygame.Surface,
    x_offsets: List[int],
    y_offsets: List[int],
    scales: List[float],
) -> Tuple[List[pygame.Surface], List[pygame.Surface]]:
    """Generate right-facing and left-facing frame lists from offset/scale tables."""
    w, h = sprite.get_size()
    count = len(x_offsets)
    right_frames: List[pygame.Surface] = []
    for idx in range(count):
        canvas = pygame.Surface((w, h), pygame.SRCALPHA)
        factor = scales[idx % len(scales)]
        draw_h = max(1, int(round(h * factor)))
        frame = sprite
        if draw_h != h:
            frame = pygame.transform.scale(sprite, (w, draw_h))
        rect = frame.get_rect(midbottom=(w // 2 + x_offsets[idx], h + y_offsets[idx]))
        canvas.blit(frame, rect)
        right_frames.append(canvas)
    left_frames = [pygame.transform.flip(f, True, False) for f in right_frames]
    return right_frames, left_frames


def build_sprite_idle_cycle(sprite: pygame.Surface, frame_count: int = 4) -> Dict[str, Dict[str, List[pygame.Surface]]]:
    w, h = sprite.get_size()
    if w <= 0 or h <= 0:
        blank = pygame.Surface((max(1, w), max(1, h)), pygame.SRCALPHA)
        dirs = {"right": [blank], "left": [blank], "down": [blank], "up": [blank]}
        return {"idle": dirs, "walk": dict(dirs)}

    # Idle: gentle breathing bob (subtle scale shifts, no lateral sway)
    idle_x = [0, 0, 0, 0]
    idle_y = [0, -1, 0, 0]
    idle_s = [1.0, 0.99, 1.0, 0.995]
    idle_r, idle_l = _build_anim_frames(sprite, idle_x, idle_y, idle_s)

    # Walk: pronounced stepping bounce with lateral lean
    walk_x = [0, 2, 0, -2]
    walk_y = [0, -3, 0, -3]
    walk_s = [1.0, 0.97, 1.0, 0.97]
    walk_r, walk_l = _build_anim_frames(sprite, walk_x, walk_y, walk_s)

    return {
        "idle": {"right": idle_r, "left": idle_l, "down": idle_r, "up": idle_r},
        "walk": {"right": walk_r, "left": walk_l, "down": walk_r, "up": walk_r},
    }


def cardinal_anim_direction(delta: Vector2, fallback: str = "down") -> str:
    dx = float(delta.x)
    dy = float(delta.y)
    if abs(dx) <= 0.001 and abs(dy) <= 0.001:
        return fallback
    if abs(dx) >= abs(dy):
        return "right" if dx >= 0.0 else "left"
    return "down" if dy >= 0.0 else "up"


def warrior_visual_tier_for_level(player_level: int) -> int:
    level_value = max(1, int(player_level))
    for min_level, tier in WARRIOR_TIER_LEVEL_THRESHOLDS:
        if level_value >= min_level:
            return tier
    return 1


def load_directional_sprite_rows(path: str, target_size: int = 96) -> Optional[Dict[str, List[pygame.Surface]]]:
    try:
        sheet = pygame.image.load(path).convert_alpha()
    except (pygame.error, FileNotFoundError, OSError):
        return None

    row_count = len(WARRIOR_ROW_TO_DIRECTION)
    if row_count <= 0 or sheet.get_height() < row_count:
        return None

    frame_h = sheet.get_height() // row_count
    frame_w = frame_h
    if frame_w <= 0:
        return None

    col_count = sheet.get_width() // frame_w
    if col_count <= 0:
        return None

    frames: Dict[str, List[pygame.Surface]] = {}
    for row_index, dir_key in enumerate(WARRIOR_ROW_TO_DIRECTION):
        row_frames: List[pygame.Surface] = []
        for col in range(col_count):
            rect = pygame.Rect(col * frame_w, row_index * frame_h, frame_w, frame_h)
            if rect.right > sheet.get_width() or rect.bottom > sheet.get_height():
                break
            tile = pygame.Surface((frame_w, frame_h), pygame.SRCALPHA)
            tile.blit(sheet, (0, 0), rect)
            if tile.get_bounding_rect(min_alpha=1).width <= 0:
                continue
            if target_size != frame_w or target_size != frame_h:
                tile = pygame.transform.scale(tile, (target_size, target_size))
            row_frames.append(tile)
        if row_frames:
            frames[dir_key] = row_frames
    return frames if frames else None


def load_warrior_class_visuals(target_size: int = 96) -> Dict[int, Dict[str, object]]:
    visuals: Dict[int, Dict[str, object]] = {}
    fps_map = {
        "idle": 6.0,
        "walk": 7.0,
        "run": 9.0,
        "attack": 11.0,
        "walk_attack": 9.0,
        "run_attack": 11.0,
        "hurt": 11.0,
        "death": 8.0,
    }

    for tier in (1, 2, 3):
        tier_root = os.path.join(WARRIOR_ASSET_ROOT, f"Swordsman_lvl{tier}", "Without_shadow")
        if not os.path.isdir(tier_root):
            continue

        anim_frames: Dict[str, Dict[str, List[pygame.Surface]]] = {}
        anim_fps: Dict[str, float] = {}
        anim_durations: Dict[str, float] = {}

        for anim_name, suffix in WARRIOR_SPRITE_ACTION_FILES:
            path = os.path.join(tier_root, f"Swordsman_lvl{tier}_{suffix}_without_shadow.png")
            frames = load_directional_sprite_rows(path, target_size=target_size)
            if not frames:
                continue
            fps = float(fps_map.get(anim_name, 8.0))
            anim_frames[anim_name] = frames
            anim_fps[anim_name] = fps
            frame_count = max((len(dir_frames) for dir_frames in frames.values()), default=1)
            anim_durations[anim_name] = max(0.05, float(frame_count) / max(0.1, fps))

        idle_frames = anim_frames.get("idle", {})
        left_idle = idle_frames.get("left") or idle_frames.get("down") or idle_frames.get("right") or idle_frames.get("up") or []
        right_idle = idle_frames.get("right") or idle_frames.get("down") or idle_frames.get("left") or idle_frames.get("up") or []
        preview_frames = idle_frames.get("down") or right_idle or left_idle
        if not left_idle or not right_idle or not preview_frames:
            continue

        preview_src = preview_frames[0]
        if preview_src.get_width() == 72 and preview_src.get_height() == 72:
            preview = preview_src
        else:
            preview = pygame.transform.smoothscale(preview_src, (72, 72))

        visuals[tier] = {
            "name": f"warrior tier {tier}",
            "sprite": left_idle[0],
            "sprite_left": right_idle[0],
            "preview": preview,
            "anim_frames": anim_frames,
            "anim_fps": anim_fps,
            "anim_durations": anim_durations,
            "tier": tier,
        }

    return visuals


def resolve_class_visual_entry(
    class_visuals: Dict[str, Dict[str, object]],
    class_id: str,
    player_level: int = 1,
    fallback: Optional[Dict[str, object]] = None,
) -> Dict[str, object]:
    entry = class_visuals.get(class_id)
    if isinstance(entry, dict):
        variants = entry.get("variants")
        if class_id == "warrior" and isinstance(variants, dict):
            preferred_tier = warrior_visual_tier_for_level(player_level)
            for tier in (preferred_tier, 3, 2, 1):
                variant = variants.get(tier)
                if isinstance(variant, dict):
                    return variant
        return entry
    if isinstance(fallback, dict):
        return fallback
    return {}


def load_lpc_spritesheet(path: str, target_size: int = 96) -> Optional[Dict[str, Dict[str, List[pygame.Surface]]]]:
    """Load a LPC-format sprite sheet PNG and return animation frames dict.

    Returns {anim_name: {direction: [Surface, ...]}} or None on failure.
    Directions are "up", "left", "down", "right".
    Falls back to None so callers can use the existing single-sprite path.
    """
    try:
        sheet = pygame.image.load(path).convert_alpha()
    except (pygame.error, FileNotFoundError, OSError):
        return None
    frames: Dict[str, Dict[str, List[pygame.Surface]]] = {}
    for anim, (start_row, n_frames, n_dirs) in LPC_ANIMS.items():
        frames[anim] = {}
        for d in range(n_dirs):
            dir_key = LPC_DIRS[d] if n_dirs > 1 else "all"
            row = start_row + d
            row_frames: List[pygame.Surface] = []
            for col in range(n_frames):
                sx = col * LPC_FRAME_W
                sy = row * LPC_FRAME_H
                if sx + LPC_FRAME_W > sheet.get_width() or sy + LPC_FRAME_H > sheet.get_height():
                    break
                tile = sheet.subsurface((sx, sy, LPC_FRAME_W, LPC_FRAME_H))
                if target_size != LPC_FRAME_W:
                    tile = pygame.transform.scale(tile, (target_size, target_size))
                row_frames.append(tile)
            if row_frames:
                frames[anim][dir_key] = row_frames
    return frames if frames else None


def load_wolf_spritesheet(path: str, target_size: int = 64) -> Optional[Dict[str, Dict[str, List[pygame.Surface]]]]:
    """Load the OpenGameArt LPC Wolf animated sprite sheet (wolfsheet1.png).

    Actual sheet layout (640x384, 64x64 frames, 10 cols x 6 rows):
      Row 0: Walk south/down  (7 frames)
      Row 1: Walk west/left   (10 frames)
      Row 2: Walk east/right  (10 frames)
      Row 3: Walk north/up    (9 frames)
      Row 4: Run/chase        (10 frames, east-facing — mirrored for west)
      Row 5: Die              (5 frames at columns 5-9)

    Returns {anim: {direction: [Surface, ...]}} or None on failure.
    """
    try:
        sheet = pygame.image.load(path).convert_alpha()
    except (pygame.error, FileNotFoundError, OSError):
        return None

    fw = fh = 64
    w, h = sheet.get_size()
    n_cols = w // fw

    def get_row(row: int, start_col: int = 0, max_frames: int | None = None) -> List[pygame.Surface]:
        limit = n_cols if max_frames is None else min(n_cols, start_col + max_frames)
        out: List[pygame.Surface] = []
        for col in range(start_col, limit):
            if (row + 1) * fh > h or (col + 1) * fw > w:
                break
            tile = sheet.subsurface((col * fw, row * fh, fw, fh))
            if target_size != fw:
                tile = pygame.transform.scale(tile, (target_size, target_size))
            out.append(tile)
        return out

    walk_down  = get_row(0)
    walk_left  = get_row(1)
    walk_right = get_row(2)
    walk_up    = get_row(3)
    run_right  = get_row(4)
    run_left   = [pygame.transform.flip(f, True, False) for f in run_right]
    die_frames = get_row(5, start_col=5)   # only cols 5-9 have content

    frames: Dict[str, Dict[str, List[pygame.Surface]]] = {
        "walk": {
            "down":  walk_down,
            "left":  walk_left,
            "right": walk_right,
            "up":    walk_up,
        },
        "run": {
            "right": run_right,
            "left":  run_left,
            "down":  walk_down,
            "up":    walk_up,
        },
        "bite": {
            "right": run_right,
            "left":  run_left,
            "down":  walk_down,
            "up":    walk_up,
        },
        "die": {
            "right": die_frames if die_frames else walk_right,
            "left":  [pygame.transform.flip(f, True, False) for f in die_frames] if die_frames else walk_left,
            "down":  die_frames if die_frames else walk_down,
            "up":    die_frames if die_frames else walk_up,
        },
    }
    return frames


def get_lpc_frame(
    frames: Optional[Dict[str, Dict[str, List[pygame.Surface]]]],
    anim: str,
    direction: str,
    anim_timer: float,
    fps: float = 8.0,
) -> Optional[pygame.Surface]:
    """Return the current animation frame Surface, or None if frames is unavailable.

    direction should be one of: "left", "right", "up", "down".
    anim_timer is an accumulating float (seconds); fps controls playback speed.
    """
    if frames is None:
        return None
    anim_data = frames.get(anim) or frames.get("walk") or {}
    dir_frames = anim_data.get(direction) or anim_data.get("down") or []
    if not dir_frames:
        return None
    idx = int(anim_timer * fps) % len(dir_frames)
    return dir_frames[idx]


def get_directional_anim_frame(
    frames: Optional[Dict[str, Dict[str, List[pygame.Surface]]]],
    anim: str,
    direction: str,
    anim_timer: float,
    fps: float = 8.0,
    loop: bool = True,
) -> Optional[pygame.Surface]:
    if frames is None:
        return None
    anim_data = frames.get(anim) or frames.get("idle") or frames.get("walk") or {}
    dir_frames = (
        anim_data.get(direction)
        or anim_data.get("down")
        or anim_data.get("right")
        or next((value for value in anim_data.values() if value), [])
    )
    if not dir_frames:
        return None
    safe_fps = max(0.1, float(fps))
    if loop:
        idx = int(max(0.0, anim_timer) * safe_fps) % len(dir_frames)
    else:
        idx = min(len(dir_frames) - 1, int(max(0.0, anim_timer) * safe_fps))
    return dir_frames[idx]


def load_resource_bar_assets() -> Dict[str, pygame.Surface]:
    global _RESOURCE_BAR_ASSETS
    if _RESOURCE_BAR_ASSETS is not None:
        return _RESOURCE_BAR_ASSETS
    _RESOURCE_BAR_ASSETS = {}
    return _RESOURCE_BAR_ASSETS


def is_walkable(pos: Vector2, bounds: pygame.Rect, obstacles: List[pygame.Rect], radius: float = 0.0) -> bool:
    r = int(radius)
    test_rect = pygame.Rect(int(pos.x) - r, int(pos.y) - r, r * 2, r * 2)
    if not bounds.contains(test_rect):
        return False
    for obs in obstacles:
        if test_rect.colliderect(obs):
            return False
    return True


def nearest_walkable(target: Vector2, bounds: pygame.Rect, obstacles: List[pygame.Rect], radius: float = 0.0) -> Vector2:
    if is_walkable(target, bounds, obstacles, radius):
        return target
    for r in range(10, 600, 10):
        for theta in range(0, 360, 30):
            rad = math.radians(theta)
            p = target + Vector2(math.cos(rad), math.sin(rad)) * r
            if is_walkable(p, bounds, obstacles, radius):
                return p
    return target


def move_with_collision(start: Vector2, end: Vector2, step: float, bounds: pygame.Rect, obstacles: List[pygame.Rect], radius: float, extra_obstacles: Optional[List[pygame.Rect]] = None) -> Vector2:
    direction = end - start
    dist = direction.length()
    if dist <= 0.001: return start
    move = direction.normalize() * step if dist > step else direction
    target = start + move
    all_obs = obstacles + (extra_obstacles if extra_obstacles else [])
    if is_walkable(target, bounds, all_obs, radius): return target
    if abs(move.x) > 0.001 and is_walkable(start + Vector2(move.x, 0), bounds, all_obs, radius): return start + Vector2(move.x, 0)
    if abs(move.y) > 0.001 and is_walkable(start + Vector2(0, move.y), bounds, all_obs, radius): return start + Vector2(0, move.y)
    return start


def find_path_astar(start: Vector2, end: Vector2, bounds: pygame.Rect, obstacles: List[pygame.Rect], cell_size: int = 32, actor_radius: float = 0.0, max_expansions: int = 1000) -> List[Tuple[float, float]]:
    return [(start.x, start.y), (end.x, end.y)]


def draw_ornate_panel(surface: pygame.Surface, rect: pygame.Rect) -> None:
    img = get_ui_panel_img()
    if img:
        draw_nine_slice(surface, img, rect, corner=24)
    else:
        draw_ornate_panel_backup(surface, rect)


def draw_ornate_panel_backup(surface: pygame.Surface, rect: pygame.Rect) -> None:
    """Draws a Steam-like ornate panel background (Backup)."""
    pygame.draw.rect(surface, (20, 22, 26), rect, border_radius=6)
    pygame.draw.rect(surface, (30, 32, 38), rect.inflate(-4, -4), border_radius=6)
    inner = rect.inflate(-8, -8)
    pygame.draw.rect(surface, (14, 14, 18), inner, border_radius=4)
    pygame.draw.rect(surface, (100, 84, 50), rect, 1, border_radius=6)
    pygame.draw.rect(surface, (180, 150, 80), rect.inflate(-2, -2), 1, border_radius=6)
    corner_len = 12
    corner_col = (220, 190, 110)
    for x, y in [(rect.left, rect.top), (rect.right - 1, rect.top), (rect.left, rect.bottom - 1), (rect.right - 1, rect.bottom - 1)]:
        dx = 1 if x == rect.left else -1
        dy = 1 if y == rect.top else -1
        pygame.draw.line(surface, corner_col, (x, y), (x + dx * corner_len, y), 2)
        pygame.draw.line(surface, corner_col, (x, y), (x, y + dy * corner_len), 2)
        pygame.draw.circle(surface, corner_col, (x, y), 2)


def draw_ui_tab(surface: pygame.Surface, rect: pygame.Rect, active: bool = False, text: str = "", font: Optional[pygame.font.Font] = None, color: Tuple[int,int,int]=(200,200,200)) -> None:
    img = UI_ASSETS.get("tab_active" if active else "tab")
    if img:
        draw_nine_slice(surface, img, rect, corner=8)
    else:
        bg = (52, 48, 36) if active else (32, 32, 38)
        border = (200, 170, 80) if active else (80, 80, 90)
        pygame.draw.rect(surface, bg, rect, border_radius=6)
        pygame.draw.rect(surface, border, rect, 1, border_radius=6)
    
    if text and font:
        ts = font.render(text, True, (230, 220, 180) if active else (160, 155, 140))
        surface.blit(ts, (rect.centerx - ts.get_width() // 2, rect.centery - ts.get_height() // 2))


def draw_ui_button(surface: pygame.Surface, rect: pygame.Rect, hovered: bool = False, text: str = "", font: Optional[pygame.font.Font] = None, color: Tuple[int,int,int]=(200,200,200)) -> None:
    img = UI_ASSETS.get("button_hover" if hovered else "button")
    if img:
        draw_nine_slice(surface, img, rect, corner=8)
    else:
        bg = (52, 48, 36) if hovered else (32, 32, 38)
        border = (220, 190, 100) if hovered else (100, 96, 80)
        pygame.draw.rect(surface, bg, rect, border_radius=6)
        pygame.draw.rect(surface, border, rect, 1, border_radius=6)

    if text and font:
        ts = font.render(text, True, color)
        surface.blit(ts, (rect.centerx - ts.get_width() // 2, rect.centery - ts.get_height() // 2))


def level_decor_asset_layer(asset_entry: Optional[Dict[str, object]]) -> str:
    if not isinstance(asset_entry, dict):
        return "OBJECT"
    return str(asset_entry.get("layer", "OBJECT")).upper()


def level_decor_asset_preview_surface(asset_entry: Dict[str, object], animated: bool = False) -> Optional[pygame.Surface]:
    if not isinstance(asset_entry, dict):
        return None
    frames = asset_entry.get("animation_surfaces", [])
    if animated and isinstance(frames, list) and frames:
        fps = max(1, int(asset_entry.get("animation_fps", 8)))
        idx = (pygame.time.get_ticks() // max(1, int(1000 / fps))) % len(frames)
        frame = frames[idx]
        if isinstance(frame, pygame.Surface):
            return frame
    surface = asset_entry.get("surface")
    return surface if isinstance(surface, pygame.Surface) else None


def level_decor_asset_uses_tile_brush(asset_entry: Optional[Dict[str, object]]) -> bool:
    if not isinstance(asset_entry, dict):
        return False
    tags = asset_entry.get("tags", [])
    if isinstance(tags, list) and any(str(tag).lower() == "tile" for tag in tags):
        return True
    category = str(asset_entry.get("category", asset_entry.get("group", ""))).lower()
    return category in ("terrain", "roads", "water", "frozen terrain", "frozen roads")


def level_decor_asset_uses_scatter(asset_entry: Optional[Dict[str, object]]) -> bool:
    if not isinstance(asset_entry, dict):
        return False
    category = str(asset_entry.get("category", asset_entry.get("group", ""))).lower()
    tags = asset_entry.get("tags", [])
    tag_blob = " ".join(str(tag).lower() for tag in tags) if isinstance(tags, list) else ""
    return category in ("nature", "ice nature") or "nature" in tag_blob


def snap_editor_point_to_grid(world_pos: Vector2, grid_size: int = DECOR_EDITOR_GRID_SIZE) -> Vector2:
    gx = math.floor(world_pos.x / float(grid_size)) * grid_size + grid_size * 0.5
    gy = math.floor(world_pos.y / float(grid_size)) * grid_size + grid_size * 0.5
    return Vector2(gx, gy)


def road_autotile_id_for_mask(mask: Set[str]) -> str:
    mapping = {
        frozenset({"n", "s", "w", "e"}): "road_cross",
        frozenset({"n", "w", "e"}): "road_t_nwe",
        frozenset({"n", "s", "e"}): "road_t_nse",
        frozenset({"n", "s", "w"}): "road_t_nsw",
        frozenset({"s", "w", "e"}): "road_t_swe",
        frozenset({"n", "s"}): "road_straight_ns",
        frozenset({"w", "e"}): "road_straight_we",
        frozenset({"n", "e"}): "road_corner_ne",
        frozenset({"n", "w"}): "road_corner_nw",
        frozenset({"s", "e"}): "road_corner_se",
        frozenset({"s", "w"}): "road_corner_sw",
        frozenset({"n"}): "road_end_n",
        frozenset({"s"}): "road_end_s",
        frozenset({"w"}): "road_end_w",
        frozenset({"e"}): "road_end_e",
    }
    return mapping.get(frozenset(mask), "road_cross")


