def get_level_decor_instance_surface(
    instance: Dict[str, object],
    level_decor_assets: Dict[str, object],
    render_cache: Dict[Tuple[str, int, int], pygame.Surface],
) -> Optional[pygame.Surface]:
    asset_id = str(instance.get("asset_id", "")).strip()
    if not asset_id:
        return None
    asset_entry = level_decor_asset_lookup(level_decor_assets, asset_id)
    if asset_entry is None:
        return None
    source = level_decor_asset_preview_surface(asset_entry, animated=True)
    if not isinstance(source, pygame.Surface):
        return None
    try:
        scale = float(instance.get("scale", 1.0))
    except (TypeError, ValueError):
        scale = 1.0
    try:
        rotation = float(instance.get("rotation", 0.0))
    except (TypeError, ValueError):
        rotation = 0.0
    scale = max(0.25, min(4.0, scale))
    rotation = rotation % 360.0
    cache_key = (asset_id, int(round(scale * 100.0)), int(round(rotation)))
    cached = render_cache.get(cache_key)
    if isinstance(cached, pygame.Surface):
        return cached
    transformed = pygame.transform.rotozoom(source, -rotation, scale)
    render_cache[cache_key] = transformed
    return transformed


def get_level_decor_instance_anchor(
    instance: Dict[str, object],
    asset_entry: Dict[str, object],
    transformed_surface: pygame.Surface,
) -> Tuple[float, float]:
    source = asset_entry.get("surface")
    if not isinstance(source, pygame.Surface):
        return (transformed_surface.get_width() * 0.5, float(transformed_surface.get_height()))
    try:
        scale = float(instance.get("scale", 1.0))
    except (TypeError, ValueError):
        scale = 1.0
    try:
        rotation = float(instance.get("rotation", 0.0))
    except (TypeError, ValueError):
        rotation = 0.0
    scale = max(0.25, min(4.0, scale))
    rotation = rotation % 360.0
    try:
        source_anchor_offset = float(asset_entry.get("anchor_offset", 0.0))
    except (TypeError, ValueError):
        source_anchor_offset = 0.0
    source_w = float(source.get_width())
    source_h = float(source.get_height())
    anchor_y = source_h - source_anchor_offset
    vector_y = (anchor_y - source_h * 0.5) * scale
    theta = math.radians(-rotation)
    dx = -vector_y * math.sin(theta)
    dy = vector_y * math.cos(theta)
    return (
        transformed_surface.get_width() * 0.5 + dx,
        transformed_surface.get_height() * 0.5 + dy,
    )


def get_level_decor_instance_rect(
    instance: Dict[str, object],
    level_decor_assets: Dict[str, object],
    render_cache: Dict[Tuple[str, int, int], pygame.Surface],
    camera: Optional[Vector2] = None,
) -> Optional[pygame.Rect]:
    transformed_surface = get_level_decor_instance_surface(instance, level_decor_assets, render_cache)
    asset_id = str(instance.get("asset_id", "")).strip()
    asset_entry = level_decor_asset_lookup(level_decor_assets, asset_id)
    if transformed_surface is None or asset_entry is None:
        return None
    try:
        x = int(round(float(instance.get("x", 0.0))))
        y = int(round(float(instance.get("y", 0.0))))
    except (TypeError, ValueError):
        return None
    if isinstance(camera, Vector2):
        x -= int(camera.x)
        y -= int(camera.y)
    anchor_x, anchor_y = get_level_decor_instance_anchor(instance, asset_entry, transformed_surface)
    rect = transformed_surface.get_rect()
    rect.left = int(round(float(x) - anchor_x))
    rect.top = int(round(float(y) - anchor_y))
    return rect


def draw_level_decor_instance(
    surface: pygame.Surface,
    instance: Dict[str, object],
    level_decor_assets: Dict[str, object],
    render_cache: Dict[Tuple[str, int, int], pygame.Surface],
    camera: Vector2,
    alpha: int = 255,
    highlight: bool = False,
    show_anchor: bool = False,
) -> Optional[pygame.Rect]:
    sprite = get_level_decor_instance_surface(instance, level_decor_assets, render_cache)
    rect = get_level_decor_instance_rect(instance, level_decor_assets, render_cache, camera)
    if sprite is None or rect is None:
        return None
    try:
        anchor_screen_x = int(round(float(instance.get("x", 0.0)) - float(camera.x)))
        anchor_screen_y = int(round(float(instance.get("y", 0.0)) - float(camera.y)))
    except (TypeError, ValueError):
        anchor_screen_x = rect.centerx
        anchor_screen_y = rect.bottom
    if not rect.colliderect(pygame.Rect(-140, -140, SCREEN_WIDTH + 280, SCREEN_HEIGHT + 280)):
        return rect
    shadow_w = max(20, int(sprite.get_width() * 0.42))
    shadow_h = max(8, int(sprite.get_width() * 0.12))
    shadow = pygame.Surface((shadow_w, shadow_h), pygame.SRCALPHA)
    pygame.draw.ellipse(shadow, (0, 0, 0, 72 if alpha >= 220 else 48), shadow.get_rect())
    shadow_rect = shadow.get_rect(midtop=(anchor_screen_x, anchor_screen_y - max(2, shadow_h // 3)))
    surface.blit(shadow, shadow_rect)
    if alpha >= 250:
        surface.blit(sprite, rect)
    else:
        faded = sprite.copy()
        faded.set_alpha(max(20, min(255, alpha)))
        surface.blit(faded, rect)
    if highlight:
        glow = rect.inflate(12, 10)
        glow_surf = pygame.Surface((glow.width, glow.height), pygame.SRCALPHA)
        pygame.draw.rect(glow_surf, (228, 202, 132, 44), glow_surf.get_rect(), border_radius=10)
        pygame.draw.rect(glow_surf, (240, 220, 160, 170), glow_surf.get_rect(), 1, border_radius=10)
        surface.blit(glow_surf, glow.topleft)
    if show_anchor:
        pygame.draw.line(surface, (240, 218, 160), (anchor_screen_x - 7, anchor_screen_y), (anchor_screen_x + 7, anchor_screen_y), 2)
        pygame.draw.line(surface, (240, 218, 160), (anchor_screen_x, anchor_screen_y - 8), (anchor_screen_x, anchor_screen_y + 4), 2)
    return rect


def draw_level_decor_editor_overlay(
    surface: pygame.Surface,
    current_level: str,
    available_assets: List[Dict[str, object]],
    selected_asset_id: Optional[str],
    asset_pack_mode: str,
    catalog_filter: str,
    category_filter: str,
    search_text: str,
    search_active: bool,
    placement_mode: str,
    selected_scale: float,
    selected_rotation: float,
    scroll_offset: int,
    title_font: pygame.font.Font,
    body_font: pygame.font.Font,
    small_font: pygame.font.Font,
    placed_count: int,
    dirty: bool,
    generate_seed: int,
    collision_preview: bool,
    ai_prompt: str = "",
    ai_input_active: bool = False,
    ai_generating: bool = False,
    ai_scope: str = "shared",
    clear_pending: bool = False,
    panel_side: str = "right",
) -> Dict[str, object]:
    mouse_pos = pygame.mouse.get_pos()

    # ── Panel geometry (compact) ──────────────────────────────────────────────
    _PW = DECOR_EDITOR_PANEL_WIDTH
    if panel_side == "left":
        panel_x = 8
    else:
        panel_x = SCREEN_WIDTH - _PW - 8
    panel_rect = pygame.Rect(panel_x, 8, _PW, SCREEN_HEIGHT - 16)
    if panel_side == "left":
        world_rect = pygame.Rect(panel_rect.right + 8, 8, max(220, SCREEN_WIDTH - panel_rect.right - 16), SCREEN_HEIGHT - 16)
    else:
        world_rect = pygame.Rect(8, 8, max(220, panel_rect.left - 16), SCREEN_HEIGHT - 16)
    inner_left = panel_rect.left + 8
    inner_w = panel_rect.width - 16

    # ── Section geometry ─────────────────────────────────────────────────────
    _GAP = 4
    _BOTTOM_H = 84

    _y = panel_rect.top + 6
    header_rect = pygame.Rect(inner_left, _y, inner_w, 28)
    _y = header_rect.bottom + _GAP

    # Mode buttons row (right below header)
    mode_row_rect = pygame.Rect(inner_left, _y, inner_w, 22)
    _y = mode_row_rect.bottom + _GAP

    # Category tabs row
    cat_row_rect = pygame.Rect(inner_left, _y, inner_w, 22)
    _y = cat_row_rect.bottom + _GAP

    # Search bar
    search_rect = pygame.Rect(inner_left, _y, inner_w - 38, 22)
    clear_search_rect = pygame.Rect(search_rect.right + 3, _y, 35, 22)
    _y = search_rect.bottom + _GAP

    # Asset grid
    grid_rect = pygame.Rect(inner_left, _y, inner_w, panel_rect.bottom - _BOTTOM_H - _GAP - _y)
    bottom_rect = pygame.Rect(inner_left, panel_rect.bottom - _BOTTOM_H - 2, inner_w, _BOTTOM_H)

    # ── Background ───────────────────────────────────────────────────────────
    draw_ornate_panel(surface, panel_rect)
    overlay_glow = pygame.Surface(world_rect.size, pygame.SRCALPHA)
    pygame.draw.rect(overlay_glow, (8, 10, 16, 22), overlay_glow.get_rect(), border_radius=8)
    pygame.draw.rect(overlay_glow, (190, 168, 108, 44), overlay_glow.get_rect(), 1, border_radius=8)
    surface.blit(overlay_glow, world_rect.topleft)

    # ── World guide hint ─────────────────────────────────────────────────────
    guide = small_font.render("LMB: place/drag  RMB: erase anything  R: rotate  Wheel: scale", True, (184, 178, 168))
    guide_bg = pygame.Rect(world_rect.left + 8, world_rect.top + 6, min(world_rect.width - 16, guide.get_width() + 14), 22)
    pygame.draw.rect(surface, (12, 12, 18), guide_bg, border_radius=6)
    pygame.draw.rect(surface, (118, 110, 92), guide_bg, 1, border_radius=6)
    surface.blit(guide, (guide_bg.left + 7, guide_bg.top + 3))

    # ── Header (compact single row) ──────────────────────────────────────────
    title_surf = small_font.render("Level Editor", True, (242, 232, 202))
    surface.blit(title_surf, (header_rect.left, header_rect.top + 4))

    _status_col = (230, 180, 100) if dirty else (140, 200, 148)
    _status_dot = small_font.render("\u25cf", True, _status_col)
    surface.blit(_status_dot, (header_rect.left + title_surf.get_width() + 6, header_rect.top + 4))

    _placed_txt = small_font.render(f"{placed_count} | {current_level.title()}", True, (168, 162, 148))
    surface.blit(_placed_txt, (header_rect.left + title_surf.get_width() + 20, header_rect.top + 4))

    save_rect = pygame.Rect(header_rect.right - 40, header_rect.top + 2, 40, 22)
    reload_rect = pygame.Rect(save_rect.left - 44, header_rect.top + 2, 42, 22)
    clear_rect = pygame.Rect(reload_rect.left - 44, header_rect.top + 2, 42, 22)
    _save_col = (180, 230, 160) if dirty else (190, 200, 178)
    draw_ui_button(surface, save_rect, hovered=save_rect.collidepoint(mouse_pos), text="Save", font=small_font, color=_save_col)
    draw_ui_button(surface, reload_rect, hovered=reload_rect.collidepoint(mouse_pos), text="Rld", font=small_font, color=(210, 210, 200))
    draw_ui_button(
        surface,
        clear_rect,
        hovered=clear_rect.collidepoint(mouse_pos),
        text="OK?" if clear_pending else "Clr",
        font=small_font,
        color=(240, 188, 172) if clear_pending else (220, 206, 188),
    )

    # ── Mode buttons row ─────────────────────────────────────────────────────
    mode_rects: Dict[str, pygame.Rect] = {}
    _mode_defs = [("single", "Paint"), ("scatter", "Scatter"), ("move", "Move")]
    _mode_cols = {"single": (190, 230, 190), "scatter": (190, 210, 240), "delete": (240, 180, 180), "move": (240, 220, 160)}
    _mx = mode_row_rect.left
    for _mid, _mlbl in _mode_defs:
        _mw = small_font.size(_mlbl)[0] + 14
        _mrect = pygame.Rect(_mx, mode_row_rect.top, _mw, mode_row_rect.height)
        _mact = (_mid == placement_mode)
        draw_ui_button(surface, _mrect, hovered=_mrect.collidepoint(mouse_pos), text=_mlbl, font=small_font, color=_mode_cols[_mid] if _mact else (160, 156, 146))
        mode_rects[_mid] = _mrect
        _mx += _mw + 4

    # ── Category tab bar (compact, scrollable if needed) ─────────────────────
    _CAT_DISPLAY: Dict[str, str] = {
        "all": "All", "terrain": "Ter", "roads": "Rd", "water": "Wtr",
        "nature": "Nat", "containers": "Ctn", "furniture": "Fur",
        "houses": "Str", "vfx": "FX",
        "scene": "Scn", "props": "Prp", "structures": "Str", "relics": "Rel",
    }
    _cat_ids = (
        ["all", "terrain", "roads", "water", "nature", "containers", "furniture", "houses", "vfx"]
        if asset_pack_mode == "medieval_generated"
        else ["all", "scene", "props", "structures", "nature", "relics"]
    )
    category_rects: Dict[str, pygame.Rect] = {}
    _cat_x = inner_left
    for _ci, _cat in enumerate(_cat_ids):
        _lbl = _CAT_DISPLAY.get(_cat, _cat[:3].title())
        _bw = small_font.size(_lbl)[0] + 10
        _brect = pygame.Rect(_cat_x, cat_row_rect.top, _bw, cat_row_rect.height)
        if _brect.right > inner_left + inner_w:
            break
        _active = (_cat == category_filter) or (_cat == "all" and not category_filter)
        pygame.draw.rect(surface, (54, 46, 28) if _active else (20, 18, 14), _brect, border_radius=4)
        pygame.draw.rect(surface, (220, 194, 118) if _active else (72, 68, 56), _brect, 1, border_radius=4)
        _lt = small_font.render(_lbl, True, (240, 230, 200) if _active else (172, 166, 152))
        surface.blit(_lt, (_brect.left + (_bw - _lt.get_width()) // 2, _brect.top + (_brect.height - _lt.get_height()) // 2))
        category_rects[_cat] = _brect
        _cat_x += _bw + 3

    # ── Search bar ───────────────────────────────────────────────────────────
    pygame.draw.rect(surface, (12, 12, 18), search_rect, border_radius=6)
    pygame.draw.rect(surface, (140, 118, 78) if search_active else (72, 66, 54), search_rect, 1, border_radius=6)
    _slbl = (search_text + ("|" if search_active else "")) if (search_text or search_active) else "Search..."
    _scol = (232, 224, 206) if (search_text or search_active) else (116, 112, 102)
    surface.blit(small_font.render(ellipsize_text(small_font, _slbl, search_rect.width - 10), True, _scol), (search_rect.left + 5, search_rect.top + 4))
    draw_ui_button(surface, clear_search_rect, hovered=clear_search_rect.collidepoint(mouse_pos), text="X", font=small_font, color=(200, 194, 176))

    # ── Asset grid (compact 3 columns) ───────────────────────────────────────
    pygame.draw.rect(surface, (10, 10, 14), grid_rect, border_radius=8)
    pygame.draw.rect(surface, (68, 64, 54), grid_rect, 1, border_radius=8)
    asset_rects: Dict[str, pygame.Rect] = {}
    _COLS = 3
    _CGAP = 4
    _CW = (grid_rect.width - (_COLS - 1) * _CGAP - 8) // _COLS
    _THUMB = 48
    _CH = _THUMB + 20
    _rows = (len(available_assets) + _COLS - 1) // _COLS
    content_height = max(0, _rows * (_CH + _CGAP) - _CGAP + 6)
    scroll_offset = max(0, int(scroll_offset))

    _prev_clip = surface.get_clip()
    surface.set_clip(grid_rect.inflate(-2, -2))
    if available_assets:
        for _ai, _asset in enumerate(available_assets):
            _row = _ai // _COLS
            _col = _ai % _COLS
            _cx = grid_rect.left + 4 + _col * (_CW + _CGAP)
            _cy = grid_rect.top + 4 + _row * (_CH + _CGAP) - scroll_offset
            _cell = pygame.Rect(_cx, _cy, _CW, _CH)
            if _cell.bottom < grid_rect.top or _cell.top > grid_rect.bottom:
                continue
            _aid = str(_asset.get("id", ""))
            _sel = _aid == str(selected_asset_id or "")
            _hov = _cell.collidepoint(mouse_pos)
            pygame.draw.rect(surface, (46, 40, 28) if _sel else (20, 18, 24), _cell, border_radius=6)
            pygame.draw.rect(surface, (220, 194, 118) if _sel else ((118, 106, 80) if _hov else (56, 54, 66)), _cell, 1, border_radius=6)
            _tbox = pygame.Rect(_cell.centerx - _THUMB // 2, _cell.top + 3, _THUMB, _THUMB)
            pygame.draw.rect(surface, (24, 22, 30), _tbox, border_radius=4)
            _tsurf = level_decor_asset_preview_surface(_asset, animated=_hov)
            if isinstance(_tsurf, pygame.Surface):
                _t = _scale_surface_to_fit(_tsurf, _THUMB - 4)
                surface.blit(_t, _t.get_rect(center=_tbox.center))
            _ntxt = small_font.render(ellipsize_text(small_font, str(_asset.get("name", "Obj")), _CW - 4), True, (234, 226, 210) if _sel else (186, 180, 166))
            surface.blit(_ntxt, (_cell.centerx - _ntxt.get_width() // 2, _cell.bottom - _ntxt.get_height() - 2))
            asset_rects[_aid] = _cell
    else:
        _em1 = small_font.render("No assets loaded.", True, (180, 174, 160))
        _em2 = small_font.render("Click Generate below.", True, (160, 154, 140))
        surface.blit(_em1, (grid_rect.centerx - _em1.get_width() // 2, grid_rect.top + 20))
        surface.blit(_em2, (grid_rect.centerx - _em2.get_width() // 2, grid_rect.top + 40))
    surface.set_clip(_prev_clip)

    # Scrollbar
    if content_height > grid_rect.height:
        _tr = pygame.Rect(grid_rect.right - 6, grid_rect.top + 3, 3, grid_rect.height - 6)
        pygame.draw.rect(surface, (24, 24, 30), _tr, border_radius=2)
        _ms = max(1, content_height - grid_rect.height)
        _hh = max(24, int(_tr.height * (grid_rect.height / float(content_height))))
        _hy = _tr.top + int((_tr.height - _hh) * (scroll_offset / float(_ms)))
        pygame.draw.rect(surface, (158, 138, 90), pygame.Rect(_tr.left, _hy, _tr.width, _hh), border_radius=2)

    # Generate pack button (visible only when no assets)
    generate_rect = pygame.Rect(grid_rect.centerx - 60, grid_rect.top + 62, 120, 24)
    if not available_assets:
        draw_ui_button(surface, generate_rect, hovered=generate_rect.collidepoint(mouse_pos), text="Generate Pack", font=small_font, color=(240, 220, 155))

    # ── Bottom bar: selected asset + controls ────────────────────────────────
    pygame.draw.rect(surface, (16, 14, 12), bottom_rect, border_radius=8)
    pygame.draw.rect(surface, (108, 94, 62), bottom_rect, 1, border_radius=8)

    _ICON = 42
    icon_rect = pygame.Rect(bottom_rect.left + 6, bottom_rect.top + 6, _ICON, _ICON)
    pygame.draw.rect(surface, (28, 26, 34), icon_rect, border_radius=6)
    pygame.draw.rect(surface, (96, 86, 68), icon_rect, 1, border_radius=6)
    selected_asset = next((a for a in available_assets if str(a.get("id")) == str(selected_asset_id)), None)
    if selected_asset:
        _psurf = level_decor_asset_preview_surface(selected_asset, animated=True)
        if isinstance(_psurf, pygame.Surface):
            _p = _scale_surface_to_fit(_psurf, _ICON - 4)
            surface.blit(_p, _p.get_rect(center=icon_rect.center))

    _info_x = icon_rect.right + 6
    _info_avail_w = inner_w - _ICON - 18

    if selected_asset:
        _aname = str(selected_asset.get("name", "Object"))
    else:
        _aname = "No selection"
    _nsurf = small_font.render(ellipsize_text(small_font, _aname, _info_avail_w), True, (242, 234, 216))
    surface.blit(_nsurf, (_info_x, bottom_rect.top + 6))

    # Scale / Rotate (compact single row)
    _ctrl_y = bottom_rect.top + 24
    scale_minus_rect = pygame.Rect(_info_x, _ctrl_y, 18, 18)
    scale_plus_rect = pygame.Rect(_info_x + 74, _ctrl_y, 18, 18)
    draw_ui_button(surface, scale_minus_rect, hovered=scale_minus_rect.collidepoint(mouse_pos), text="-", font=small_font, color=(200, 196, 178))
    draw_ui_button(surface, scale_plus_rect, hovered=scale_plus_rect.collidepoint(mouse_pos), text="+", font=small_font, color=(200, 196, 178))
    _sc_lbl = small_font.render(f"S {selected_scale:.1f}x", True, (196, 190, 172))
    surface.blit(_sc_lbl, (_info_x + 20, _ctrl_y + 2))

    rot_minus_rect = pygame.Rect(_info_x + 100, _ctrl_y, 18, 18)
    rot_plus_rect = pygame.Rect(_info_x + 174, _ctrl_y, 18, 18)
    draw_ui_button(surface, rot_minus_rect, hovered=rot_minus_rect.collidepoint(mouse_pos), text="-", font=small_font, color=(200, 196, 178))
    draw_ui_button(surface, rot_plus_rect, hovered=rot_plus_rect.collidepoint(mouse_pos), text="+", font=small_font, color=(200, 196, 178))
    _rot_lbl = small_font.render(f"R {int(round(selected_rotation))}\u00b0", True, (196, 190, 172))
    surface.blit(_rot_lbl, (_info_x + 120, _ctrl_y + 2))

    # ── 8-direction nudge pad for shops (compact) ────────────────────────────
    _nudge_size = 18
    _nudge_gap = 1
    _nudge_step = _nudge_size + _nudge_gap
    _nudge_ox = bottom_rect.left + 6
    _nudge_oy = bottom_rect.top + 54
    _nudge_dirs = {
        "nw": (-1, -1), "n": (0, -1), "ne": (1, -1),
        "w":  (-1,  0),                "e":  (1,  0),
        "sw": (-1,  1), "s": (0,  1),  "se": (1,  1),
    }
    _nudge_grid = {
        "nw": (0, 0), "n": (1, 0), "ne": (2, 0),
        "w":  (0, 1),              "e":  (2, 1),
        "sw": (0, 2), "s": (1, 2), "se": (2, 2),
    }
    _arrow_chars = {"nw": "\u2196", "n": "\u2191", "ne": "\u2197", "w": "\u2190", "e": "\u2192", "sw": "\u2199", "s": "\u2193", "se": "\u2198"}
    nudge_rects: Dict[str, pygame.Rect] = {}
    _nlbl = small_font.render("Nudge", True, (150, 144, 130))
    surface.blit(_nlbl, (_nudge_ox + _nudge_step * 3 + 4, _nudge_oy + _nudge_step))
    for _nid, (_gx, _gy) in _nudge_grid.items():
        _nr = pygame.Rect(_nudge_ox + _gx * _nudge_step, _nudge_oy + _gy * _nudge_step, _nudge_size, _nudge_size)
        draw_ui_button(surface, _nr, hovered=_nr.collidepoint(mouse_pos), text=_arrow_chars[_nid], font=small_font, color=(210, 200, 170))
        nudge_rects[_nid] = _nr

    # ── Offscreen dummy rects for removed features ────────────────────────────
    _off = pygame.Rect(-9999, -9999, 1, 1)
    inspector_rects: Dict[str, pygame.Rect] = {}

    return {
        "panel_rect": panel_rect,
        "world_rect": world_rect,
        "save_rect": save_rect,
        "reload_rect": reload_rect,
        "clear_rect": clear_rect,
        "generate_rect": generate_rect,
        "demo_rect": _off,
        "seed_minus_rect": _off,
        "seed_plus_rect": _off,
        "pack_rects": {},
        "filter_rects": {},
        "category_rects": category_rects,
        "mode_rects": mode_rects,
        "collision_rect": _off,
        "inspector_rects": inspector_rects,
        "asset_rects": asset_rects,
        "search_rect": search_rect,
        "clear_search_rect": clear_search_rect,
        "content_height": content_height,
        "ai_prompt_rect": _off,
        "ai_generate_btn_rect": _off,
        "ai_scope_rects": {},
        "scale_minus_rect": scale_minus_rect,
        "scale_plus_rect": scale_plus_rect,
        "rot_minus_rect": rot_minus_rect,
        "rot_plus_rect": rot_plus_rect,
        "nudge_rects": nudge_rects,
    }


_RESOURCE_BAR_ASSETS: Optional[Dict[str, pygame.Surface]] = None



class DayNightCycle:
    def __init__(self) -> None:
        self.time = 8.0  # Start at 8 AM
        self.day_duration = 300.0  # Seconds per day

    def update(self, dt: float) -> None:
        self.time = (self.time + (dt / self.day_duration) * 24.0) % 24.0

    def get_tint(self) -> tuple[int, int, int, int]:
        # Simple 4-phase cycle: Day, Dusk, Night, Dawn.
        # Night alpha is deliberately kept moderate (was 160) so the detailed
        # buildings/ground stay readable instead of crushing to near-black.
        if 6.0 <= self.time < 18.0:  # Day
            return (0, 0, 0, 0)
        elif 18.0 <= self.time < 20.0:  # Dusk
            alpha = int(96 * ((self.time - 18.0) / 2.0))
            return (104, 62, 24, alpha)
        elif 20.0 <= self.time or self.time < 5.0:  # Night
            return (16, 18, 40, 112)
        else:  # Dawn (5.0 to 6.0)
            alpha = int(96 * (1.0 - (self.time - 5.0)))
            return (104, 62, 24, alpha)


class WeatherSystem:
    PROFILES: Dict[str, Dict[str, object]] = {
        "clear": {
            "label": "Clear",
            "cloud": 0.08,
            "rain": 0.0,
            "fog": 0.0,
            "wind": 16.0,
            "ui_color": (196, 218, 228),
        },
        "cloudy": {
            "label": "Overcast",
            "cloud": 0.44,
            "rain": 0.0,
            "fog": 0.06,
            "wind": 24.0,
            "ui_color": (188, 194, 208),
        },
        "rain": {
            "label": "Rain",
            "cloud": 0.64,
            "rain": 0.68,
            "fog": 0.14,
            "wind": 48.0,
            "ui_color": (154, 184, 214),
        },
        "storm": {
            "label": "Storm",
            "cloud": 0.84,
            "rain": 1.0,
            "fog": 0.26,
            "wind": 78.0,
            "ui_color": (236, 214, 164),
        },
        "fog": {
            "label": "Fog",
            "cloud": 0.26,
            "rain": 0.0,
            "fog": 0.82,
            "wind": 10.0,
            "ui_color": (216, 220, 224),
        },
    }

    def __init__(self, initial_level: str = "town", day_time: float = 8.0) -> None:
        self.rng = random.Random(random.randrange(1_000_000_000))
        self.state = "clear"
        self.current_level = str(initial_level)
        self.transition_timer = 0.0
        self.cloud_cover = 0.0
        self.precipitation = 0.0
        self.fog_density = 0.0
        self.wind = 0.0
        self.target_cloud_cover = 0.0
        self.target_precipitation = 0.0
        self.target_fog_density = 0.0
        self.target_wind = 0.0
        self.flash_timer = 0.0
        self.flash_cooldown = 0.0
        self.rain_streaks: List[Dict[str, float]] = [self._spawn_rain_streak(initial=True) for _ in range(96)]
        self.fog_banks: List[Dict[str, float]] = [self._spawn_fog_bank(initial=True) for _ in range(10)]
        self.snow_flakes: List[Dict[str, float]] = [self._spawn_snow_flake(initial=True) for _ in range(120)]
        self._apply_profile(self._choose_next_state(initial_level, day_time), immediate=True)
        self.transition_timer = self._next_duration(self.state)

    def _spawn_snow_flake(self, initial: bool = False) -> Dict[str, float]:
        x = self.rng.uniform(-30.0, SCREEN_WIDTH + 30.0)
        y = self.rng.uniform(-SCREEN_HEIGHT, SCREEN_HEIGHT) if initial else self.rng.uniform(-20.0, -4.0)
        return {
            "x": x,
            "y": y,
            "size": self.rng.uniform(1.5, 4.0),
            "speed": self.rng.uniform(55.0, 130.0),
            "drift": self.rng.uniform(-18.0, 18.0),
            "wobble": self.rng.uniform(0.0, math.tau),
            "wobble_speed": self.rng.uniform(0.8, 2.2),
            "alpha": self.rng.uniform(140.0, 230.0),
        }

    def _spawn_rain_streak(self, initial: bool = False) -> Dict[str, float]:
        if initial:
            x = self.rng.uniform(-50.0, SCREEN_WIDTH + 50.0)
            y = self.rng.uniform(-SCREEN_HEIGHT, SCREEN_HEIGHT)
        else:
            x = self.rng.uniform(-50.0, SCREEN_WIDTH + 50.0)
            y = self.rng.uniform(-140.0, -12.0)
            if self.wind < -22.0 and self.rng.random() < 0.35:
                x = SCREEN_WIDTH + self.rng.uniform(12.0, 80.0)
                y = self.rng.uniform(-20.0, SCREEN_HEIGHT * 0.65)
            elif self.wind > 22.0 and self.rng.random() < 0.35:
                x = -self.rng.uniform(12.0, 80.0)
                y = self.rng.uniform(-20.0, SCREEN_HEIGHT * 0.65)
        return {
            "x": x,
            "y": y,
            "length": self.rng.uniform(11.0, 24.0),
            "speed": self.rng.uniform(480.0, 920.0),
            "drift": self.rng.uniform(-8.0, 8.0),
            "alpha": self.rng.uniform(88.0, 164.0),
        }

    def _spawn_fog_bank(self, initial: bool = False) -> Dict[str, float]:
        if initial:
            x = self.rng.uniform(-220.0, SCREEN_WIDTH + 220.0)
        elif self.wind >= 0.0:
            x = -260.0 - self.rng.uniform(0.0, 120.0)
        else:
            x = SCREEN_WIDTH + 260.0 + self.rng.uniform(0.0, 120.0)
        return {
            "x": x,
            "y": self.rng.uniform(HORIZON_Y - 40.0, SCREEN_HEIGHT + 40.0),
            "radius": self.rng.uniform(110.0, 220.0),
            "pulse": self.rng.uniform(0.42, 1.08),
            "alpha": self.rng.uniform(0.55, 1.0),
            "drift": self.rng.uniform(-4.0, 4.0),
            "phase": self.rng.uniform(0.0, math.tau),
        }

    def _next_duration(self, state: str) -> float:
        ranges = {
            "clear": (24.0, 52.0),
            "cloudy": (20.0, 40.0),
            "rain": (18.0, 34.0),
            "storm": (14.0, 26.0),
            "fog": (16.0, 30.0),
        }
        low, high = ranges.get(state, (20.0, 36.0))
        return self.rng.uniform(low, high)

    def _choose_next_state(self, level: str, day_time: float) -> str:
        level_key = "wilderness" if str(level).strip().lower() == "wilderness" else "town"
        hour = float(day_time) % 24.0
        weights = {
            "clear": 32,
            "cloudy": 28,
            "rain": 20,
            "storm": 8,
            "fog": 12,
        }
        if level_key == "town":
            weights["clear"] += 8
            weights["storm"] = max(3, weights["storm"] - 3)
            weights["rain"] = max(10, weights["rain"] - 4)
        else:
            weights["rain"] += 6
            weights["storm"] += 4
        if 4.0 <= hour < 8.0:
            weights["fog"] += 24
            weights["clear"] = max(6, weights["clear"] - 8)
        elif 17.0 <= hour < 21.0:
            weights["cloudy"] += 10
            weights["rain"] += 6
            weights["storm"] += 4
        elif hour >= 21.0 or hour < 4.0:
            weights["fog"] += 8
            weights["storm"] += 6
            weights["clear"] = max(6, weights["clear"] - 10)
        total = float(sum(max(1, weight) for weight in weights.values()))
        roll = self.rng.uniform(0.0, total)
        cursor = 0.0
        for key in ("clear", "cloudy", "rain", "storm", "fog"):
            cursor += float(max(1, weights.get(key, 1)))
            if roll <= cursor:
                return key
        return "clear"

    def _apply_profile(self, state: str, immediate: bool = False) -> None:
        state_key = state if state in self.PROFILES else "clear"
        profile = self.PROFILES[state_key]
        self.state = state_key
        self.target_cloud_cover = clamp(float(profile["cloud"]) * self.rng.uniform(0.9, 1.08), 0.0, 1.0)
        self.target_precipitation = clamp(float(profile["rain"]) * self.rng.uniform(0.88, 1.1), 0.0, 1.0)
        self.target_fog_density = clamp(float(profile["fog"]) * self.rng.uniform(0.88, 1.12), 0.0, 1.0)
        wind_dir = -1.0 if self.rng.random() < 0.32 else 1.0
        self.target_wind = float(profile["wind"]) * wind_dir * self.rng.uniform(0.82, 1.18)
        if immediate:
            self.cloud_cover = self.target_cloud_cover
            self.precipitation = self.target_precipitation
            self.fog_density = self.target_fog_density
            self.wind = self.target_wind
        self.flash_timer = 0.0
        self.flash_cooldown = self.rng.uniform(2.4, 5.8)

    def _update_rain_streaks(self, dt: float) -> None:
        drift = self.wind * 0.56
        for streak in self.rain_streaks:
            streak["x"] += (drift + streak["drift"]) * dt
            streak["y"] += streak["speed"] * dt
            if (
                streak["y"] > SCREEN_HEIGHT + 44.0
                or streak["x"] < -90.0
                or streak["x"] > SCREEN_WIDTH + 90.0
            ):
                streak.clear()
                streak.update(self._spawn_rain_streak())

    def _update_fog_banks(self, dt: float) -> None:
        drift = self.wind * 0.08
        for bank in self.fog_banks:
            bank["x"] += (drift + bank["drift"]) * dt
            bank["phase"] = (bank["phase"] + bank["pulse"] * dt) % math.tau
            if bank["x"] < -360.0 or bank["x"] > SCREEN_WIDTH + 360.0:
                bank.clear()
                bank.update(self._spawn_fog_bank())

    def _update_snow_flakes(self, dt: float) -> None:
        drift_base = self.wind * 0.22
        for flake in self.snow_flakes:
            flake["wobble"] = (flake["wobble"] + flake["wobble_speed"] * dt) % math.tau
            flake["x"] += (drift_base + flake["drift"] + math.sin(flake["wobble"]) * 8.0) * dt
            flake["y"] += flake["speed"] * dt
            if flake["y"] > SCREEN_HEIGHT + 10.0 or flake["x"] < -60.0 or flake["x"] > SCREEN_WIDTH + 60.0:
                flake.clear()
                flake.update(self._spawn_snow_flake())

    def update(self, dt: float, level: str, day_time: float) -> bool:
        if dt <= 0.0:
            return False
        self.current_level = str(level)
        weather_changed = False
        self.transition_timer -= dt
        if self.transition_timer <= 0.0:
            next_state = self._choose_next_state(level, day_time)
            weather_changed = next_state != self.state
            self._apply_profile(next_state)
            self.transition_timer = self._next_duration(self.state)
        blend = min(1.0, dt * 0.42)
        wind_blend = min(1.0, dt * 0.26)
        self.cloud_cover += (self.target_cloud_cover - self.cloud_cover) * blend
        self.precipitation += (self.target_precipitation - self.precipitation) * blend
        self.fog_density += (self.target_fog_density - self.fog_density) * blend
        self.wind += (self.target_wind - self.wind) * wind_blend
        self._update_rain_streaks(dt)
        self._update_fog_banks(dt)
        if self.current_level == "ice_biome":
            self._update_snow_flakes(dt)
        self.flash_timer = max(0.0, self.flash_timer - dt)
        self.flash_cooldown = max(0.0, self.flash_cooldown - dt)
        if self.state == "storm" and self.precipitation > 0.58 and self.flash_cooldown <= 0.0:
            flash_chance = dt * (0.22 + max(0.0, self.precipitation - 0.58) * 0.5)
            if self.rng.random() < flash_chance:
                self.flash_timer = self.rng.uniform(0.08, 0.18)
                self.flash_cooldown = self.rng.uniform(3.2, 7.2)
        return weather_changed

    def get_display_name(self) -> str:
        profile = self.PROFILES.get(self.state, self.PROFILES["clear"])
        return str(profile["label"])

    def get_ui_color(self) -> Tuple[int, int, int]:
        profile = self.PROFILES.get(self.state, self.PROFILES["clear"])
        return tuple(int(v) for v in profile["ui_color"])

    def get_speed_multiplier(self, level: str) -> float:
        lv = str(level).strip().lower()
        if lv == "town":
            return 1.0
        slowdown = self.precipitation * 0.08 + max(0.0, self.fog_density - 0.45) * 0.05
        if lv == "ice_biome":
            slowdown += 0.10  # permanent cold-wind penalty
        return clamp(1.0 - slowdown, 0.75 if lv == "ice_biome" else 0.88, 1.0)

    def get_hud_detail(self, level: str) -> str:
        lv = str(level).strip().lower()
        if lv == "ice_biome":
            move_pct = int(round(self.get_speed_multiplier(level) * 100.0))
            if move_pct < 100:
                return f"Blizzard rages — {move_pct}% speed"
            return "Frost hangs heavy"
        if lv == "wilderness":
            move_pct = int(round(self.get_speed_multiplier(level) * 100.0))
            if move_pct < 100:
                return f"Move speed {move_pct}%"
            if self.fog_density >= 0.48:
                return "Visibility reduced"
        if self.precipitation >= 0.45:
            return "Ground is slick"
        if self.fog_density >= 0.45:
            return "Mist hangs low"
        if self.cloud_cover >= 0.45:
            return "Heavy cloud cover"
        return "Calm air"

    def render(self, surface: pygame.Surface) -> None:
        cloud_alpha = int(92 * clamp(self.cloud_cover, 0.0, 1.0))
        if cloud_alpha > 0:
            cloud_surface = pygame.Surface((SCREEN_WIDTH, SCREEN_HEIGHT), pygame.SRCALPHA)
            if self.state == "storm":
                cloud_color = (18, 22, 34, cloud_alpha)
            elif self.state == "rain":
                cloud_color = (24, 30, 40, cloud_alpha)
            else:
                cloud_color = (28, 32, 38, cloud_alpha)
            cloud_surface.fill(cloud_color)
            surface.blit(cloud_surface, (0, 0))

        if self.fog_density > 0.04:
            fog_surface = pygame.Surface((SCREEN_WIDTH, SCREEN_HEIGHT), pygame.SRCALPHA)
            base_alpha = int(110 * clamp(self.fog_density, 0.0, 1.0))
            fog_band_top = max(0, HORIZON_Y - 24)
            pygame.draw.rect(
                fog_surface,
                (214, 218, 224, int(base_alpha * 0.22)),
                pygame.Rect(0, fog_band_top, SCREEN_WIDTH, SCREEN_HEIGHT - fog_band_top),
            )
            for bank in self.fog_banks:
                wobble = math.sin(bank["phase"]) * 18.0
                radius = int(bank["radius"] * (0.72 + 0.12 * math.sin(bank["phase"] * 0.6 + 0.4)))
                alpha = int(base_alpha * bank["alpha"] * 0.3)
                if radius < 8 or alpha <= 0:
                    continue
                center = (int(bank["x"]), int(bank["y"] + wobble))
                pygame.draw.circle(fog_surface, (214, 218, 224, alpha), center, radius)
                pygame.draw.circle(
                    fog_surface,
                    (214, 218, 224, max(0, alpha - 12)),
                    (center[0] + radius // 3, center[1]),
                    max(8, radius * 2 // 3),
                )
            surface.blit(fog_surface, (0, 0))

        if self.precipitation > 0.02:
            rain_surface = pygame.Surface((SCREEN_WIDTH, SCREEN_HEIGHT), pygame.SRCALPHA)
            drop_count = max(8, int(len(self.rain_streaks) * clamp(self.precipitation, 0.0, 1.0)))
            slant = int(self.wind * 0.028)
            for idx in range(drop_count):
                streak = self.rain_streaks[idx]
                start_x = int(streak["x"])
                start_y = int(streak["y"])
                end_x = start_x + slant
                end_y = int(streak["y"] + streak["length"])
                alpha = int(streak["alpha"] * (0.35 + 0.65 * self.precipitation))
                pygame.draw.line(rain_surface, (178, 196, 220, alpha), (start_x, start_y), (end_x, end_y), 1)
                if (
                    self.precipitation > 0.35
                    and start_y > HORIZON_Y + 80
                    and self.rng.random() < 0.025 * self.precipitation
                ):
                    splash_y = min(SCREEN_HEIGHT - 3, end_y)
                    pygame.draw.line(
                        rain_surface,
                        (190, 205, 224, max(18, alpha // 4)),
                        (start_x - 2, splash_y),
                        (start_x + 2, splash_y),
                        1,
                    )
            if self.precipitation > 0.18:
                mist = pygame.Surface((SCREEN_WIDTH, SCREEN_HEIGHT), pygame.SRCALPHA)
                mist.fill((52, 64, 76, int(36 * self.precipitation)))
                rain_surface.blit(mist, (0, 0))
            surface.blit(rain_surface, (0, 0))

        if self.flash_timer > 0.0:
            flash_surface = pygame.Surface((SCREEN_WIDTH, SCREEN_HEIGHT), pygame.SRCALPHA)
            flash_alpha = int(150 * min(1.0, self.flash_timer / 0.18))
            flash_surface.fill((228, 236, 255, flash_alpha))
            surface.blit(flash_surface, (0, 0), special_flags=pygame.BLEND_RGBA_ADD)

        # Ice biome: always render snowfall
        if self.current_level == "ice_biome":
            snow_surf = pygame.Surface((SCREEN_WIDTH, SCREEN_HEIGHT), pygame.SRCALPHA)
            for flake in self.snow_flakes:
                sx = int(flake["x"])
                sy = int(flake["y"])
                if sy < -6 or sy > SCREEN_HEIGHT + 6:
                    continue
                r = max(1, int(flake["size"]))
                a = int(flake["alpha"])
                pygame.gfxdraw.filled_circle(snow_surf, sx, sy, r, (235, 244, 255, a))
                if r > 2:
                    pygame.gfxdraw.filled_circle(snow_surf, sx, sy, r - 1, (255, 255, 255, min(255, a + 30)))
            surface.blit(snow_surf, (0, 0))


def damage_wolf_entity(
    wolf: Dict[str, object],
    damage: float,
    damage_numbers: Optional[List[Dict[str, object]]] = None,
    hit_pos: Optional[Vector2] = None,
) -> float:
    amount = max(0.0, float(damage))
    if amount <= 0.0:
        return 0.0
    hp_before = max(0.0, float(wolf.get("hp", 0.0)))
    if hp_before <= 0.0:
        return 0.0
    wolf["hp"] = max(0.0, hp_before - amount)
    dealt = min(hp_before, amount)
    if dealt > 0.0:
        wolf["chasing"] = True
        wolf["aggro_timer"] = max(float(wolf.get("aggro_timer", 0.0)), 3.5)
        if isinstance(damage_numbers, list):
            pos = hit_pos
            if not isinstance(pos, Vector2):
                pos_raw = wolf.get("pos")
                if isinstance(pos_raw, Vector2):
                    pos = Vector2(pos_raw)
            if isinstance(pos, Vector2):
                spawn_damage_number(damage_numbers, pos, dealt, kind="outgoing")
    return dealt


def draw_point_light(
    surface: pygame.Surface,
    sx: int,
    sy: int,
    color: Tuple[int, int, int],
    inner_radius: int,
    outer_radius: int,
    alpha: int = 80,
) -> None:
    """Draw a soft radial glow at screen coords (sx, sy) with additive-style blending."""
    if outer_radius <= 0:
        return
    glow = pygame.Surface((outer_radius * 2, outer_radius * 2), pygame.SRCALPHA)
    steps = max(4, outer_radius // 6)
    for i in range(steps, 0, -1):
        r = int(outer_radius * i / steps)
        t = 1.0 - (i / steps)  # 0 at edge, 1 at center
        a = int(alpha * (t ** 1.6))
        pygame.gfxdraw.filled_circle(glow, outer_radius, outer_radius, r, (color[0], color[1], color[2], a))
    # Bright core
    core_r = max(1, inner_radius)
    pygame.gfxdraw.filled_circle(glow, outer_radius, outer_radius, core_r, (min(255, color[0] + 60), min(255, color[1] + 50), min(255, color[2] + 30), min(255, alpha + 60)))
    surface.blit(glow, (sx - outer_radius, sy - outer_radius), special_flags=pygame.BLEND_RGBA_ADD)


def point_segment_distance_sq(point: Vector2, start: Vector2, end: Vector2) -> float:
    seg = end - start
    seg_len_sq = seg.length_squared()
    if seg_len_sq <= 1e-6:
        return point.distance_squared_to(start)
    t = clamp((point - start).dot(seg) / seg_len_sq, 0.0, 1.0)
    nearest = start + seg * t
    return point.distance_squared_to(nearest)


def circle_hits_segment(center: Vector2, radius: float, start: Vector2, end: Vector2) -> bool:
    rr = max(0.0, float(radius))
    return point_segment_distance_sq(center, start, end) <= rr * rr


class ParticleEmitter:
    def __init__(self) -> None:
        self.particles: List[Dict[str, object]] = []

    def burst(
        self,
        origin: Vector2,
        primary: Tuple[int, int, int],
        secondary: Tuple[int, int, int],
        count: int = 12,
        speed_min: float = 80.0,
        speed_max: float = 220.0,
        life_min: float = 0.16,
        life_max: float = 0.42,
        size_start: float = 4.0,
        size_end: float = 0.6,
        spread: float = math.tau,
        direction: Optional[Vector2] = None,
        gravity: float = 0.0,
        drag: float = 0.0,
        shape: str = "orb",
        alpha: int = 220,
        streak: float = 12.0,
    ) -> None:
        if count <= 0:
            return
        base_dir: Optional[Vector2] = None
        if isinstance(direction, Vector2) and direction.length_squared() > 1e-6:
            base_dir = direction.normalize()
        for _ in range(int(count)):
            if isinstance(base_dir, Vector2):
                if spread < math.tau - 0.001:
                    ang = random.uniform(-spread * 0.5, spread * 0.5)
                    vel_dir = rotate_vec(base_dir, ang)
                else:
                    vel_dir = rotate_vec(base_dir, random.uniform(0.0, math.tau))
            else:
                ang = random.uniform(0.0, math.tau)
                vel_dir = Vector2(math.cos(ang), math.sin(ang))
            speed = random.uniform(speed_min, speed_max)
            life = random.uniform(life_min, life_max)
            self.particles.append(
                {
                    "pos": Vector2(origin),
                    "vel": vel_dir * speed,
                    "life": life,
                    "duration": life,
                    "size0": max(0.4, size_start * random.uniform(0.82, 1.18)),
                    "size1": max(0.2, size_end * random.uniform(0.8, 1.2)),
                    "primary": primary,
                    "secondary": secondary,
                    "gravity": gravity,
                    "drag": max(0.0, drag),
                    "shape": shape,
                    "alpha": int(clamp(float(alpha) * random.uniform(0.78, 1.0), 12.0, 255.0)),
                    "streak": max(4.0, float(streak) * random.uniform(0.75, 1.25)),
                }
            )

    def update(self, dt: float) -> None:
        if dt <= 0.0 or not self.particles:
            return
        keep: List[Dict[str, object]] = []
        for particle in self.particles:
            life = float(particle.get("life", 0.0)) - dt
            if life <= 0.0:
                continue
            pos = particle.get("pos")
            vel = particle.get("vel")
            if not isinstance(pos, Vector2) or not isinstance(vel, Vector2):
                continue
            drag = max(0.0, float(particle.get("drag", 0.0)))
            if drag > 0.0:
                vel *= max(0.0, 1.0 - drag * dt)
            gravity = float(particle.get("gravity", 0.0))
            if gravity != 0.0:
                vel.y += gravity * dt
            pos += vel * dt
            particle["life"] = life
            particle["pos"] = pos
            particle["vel"] = vel
            keep.append(particle)
        self.particles = keep

    def draw(self, surface: pygame.Surface, camera: Vector2) -> None:
        for particle in self.particles:
            pos = particle.get("pos")
            vel = particle.get("vel")
            if not isinstance(pos, Vector2):
                continue
            life = float(particle.get("life", 0.0))
            duration = max(0.001, float(particle.get("duration", 1.0)))
            fade = clamp(life / duration, 0.0, 1.0)
            sx = int(pos.x - camera.x)
            sy = int(pos.y - camera.y)
            if sx < -40 or sx > SCREEN_WIDTH + 40 or sy < -40 or sy > SCREEN_HEIGHT + 40:
                continue
            c0 = particle.get("primary", (220, 220, 220))
            c1 = particle.get("secondary", (140, 140, 140))
            if not (isinstance(c0, tuple) and len(c0) == 3):
                c0 = (220, 220, 220)
            if not (isinstance(c1, tuple) and len(c1) == 3):
                c1 = (140, 140, 140)
            blend = 1.0 - fade
            color = (
                int(c0[0] + (c1[0] - c0[0]) * blend),
                int(c0[1] + (c1[1] - c0[1]) * blend),
                int(c0[2] + (c1[2] - c0[2]) * blend),
            )
            alpha = max(10, int(float(particle.get("alpha", 220)) * fade))
            rr = max(
                1,
                int(
                    float(particle.get("size1", 0.6))
                    + (float(particle.get("size0", 4.0)) - float(particle.get("size1", 0.6))) * fade
                ),
            )
            shape = str(particle.get("shape", "orb"))
            if shape == "spark" and isinstance(vel, Vector2) and vel.length_squared() > 1e-5:
                tail = vel.normalize() * max(4.0, float(particle.get("streak", 12.0))) * (0.45 + 0.55 * fade)
                ex = int(sx - tail.x)
                ey = int(sy - tail.y)
                pygame.draw.line(surface, color, (sx, sy), (ex, ey), 2 if rr > 2 else 1)
                pygame.gfxdraw.filled_circle(surface, sx, sy, max(1, rr - 1), (color[0], color[1], color[2], alpha))
            elif shape == "diamond":
                diamond = pygame.Surface((rr * 4, rr * 4), pygame.SRCALPHA)
                cx = diamond.get_width() // 2
                cy = diamond.get_height() // 2
                pts = [(cx, cy - rr), (cx + rr, cy), (cx, cy + rr), (cx - rr, cy)]
                pygame.draw.polygon(diamond, (color[0], color[1], color[2], alpha), pts)
                surface.blit(diamond, (sx - cx, sy - cy))
            else:
                pygame.gfxdraw.filled_circle(surface, sx, sy, rr + 2, (color[0], color[1], color[2], max(8, alpha // 4)))
                pygame.gfxdraw.filled_circle(surface, sx, sy, rr, (color[0], color[1], color[2], alpha))

    def alive(self) -> bool:
        return bool(self.particles)


class StatusEffect:
    def __init__(
        self,
        kind: str,
        duration: float,
        potency: float = 0.0,
        tick_interval: float = 0.0,
        color: Tuple[int, int, int] = (220, 220, 220),
    ) -> None:
        self.kind = str(kind)
        self.duration = max(0.0, float(duration))
        self.potency = float(potency)
        self.tick_interval = max(0.0, float(tick_interval))
        self.tick_timer = self.tick_interval
        self.color = color


class StatusEffectSystem:
    PLAYER_KEY = "player"

    def __init__(self) -> None:
        self.effects: Dict[str, List[StatusEffect]] = {}

    def wolf_key(self, wolf: Dict[str, object]) -> str:
        return f"wolf:{id(wolf)}"

    def add_effect(self, target_key: str, effect: StatusEffect) -> None:
        if effect.duration <= 0.0:
            return
        effects = self.effects.setdefault(str(target_key), [])
        if effect.kind == "burn":
            burns = [entry for entry in effects if entry.kind == "burn"]
            if len(burns) >= 3:
                weakest = min(burns, key=lambda entry: entry.potency * max(0.15, entry.duration))
                weakest.duration = max(weakest.duration, effect.duration)
                weakest.potency = max(weakest.potency, effect.potency)
                weakest.tick_interval = effect.tick_interval if effect.tick_interval > 0.0 else weakest.tick_interval
                weakest.tick_timer = min(weakest.tick_timer, max(0.01, weakest.tick_interval))
                weakest.color = effect.color
                return
            effects.append(effect)
            return
        for existing in effects:
            if existing.kind != effect.kind:
                continue
            if effect.kind == "shield":
                existing.potency += max(0.0, effect.potency)
                existing.duration = max(existing.duration, effect.duration)
            else:
                existing.potency = max(existing.potency, effect.potency)
                existing.duration = max(existing.duration, effect.duration)
                if effect.tick_interval > 0.0:
                    if existing.tick_interval <= 0.0:
                        existing.tick_interval = effect.tick_interval
                    else:
                        existing.tick_interval = min(existing.tick_interval, effect.tick_interval)
                    existing.tick_timer = min(existing.tick_timer, existing.tick_interval)
            existing.color = effect.color
            return
        effects.append(effect)

    def get_effects(self, target_key: str) -> List[StatusEffect]:
        return self.effects.get(str(target_key), [])

    def consume_effect(self, target_key: str, kind: str) -> Optional[StatusEffect]:
        effects = self.effects.get(str(target_key), [])
        for idx, effect in enumerate(effects):
            if effect.kind != kind:
                continue
            consumed = effects.pop(idx)
            if effects:
                self.effects[str(target_key)] = effects
            else:
                self.effects.pop(str(target_key), None)
            return consumed
        return None

    def move_multiplier(self, target_key: str) -> float:
        mult = 1.0
        for effect in self.get_effects(target_key):
            if effect.kind == "slow":
                mult *= clamp(1.0 - effect.potency, 0.15, 1.0)
            elif effect.kind == "freeze":
                mult = 0.0
        return clamp(mult, 0.0, 1.0)

    def is_disabled(self, target_key: str) -> bool:
        for effect in self.get_effects(target_key):
            if effect.kind in ("stun", "freeze"):
                return True
        return False

    def shield_value(self, target_key: str) -> float:
        total = 0.0
        for effect in self.get_effects(target_key):
            if effect.kind == "shield":
                total += max(0.0, effect.potency)
        return total

    def consume_shield(self, target_key: str, amount: float) -> float:
        remaining = max(0.0, float(amount))
        if remaining <= 0.0:
            return 0.0
        absorbed = 0.0
        effects = self.effects.get(str(target_key), [])
        for effect in effects:
            if effect.kind != "shield" or remaining <= 0.0:
                continue
            block = min(max(0.0, effect.potency), remaining)
            if block <= 0.0:
                continue
            effect.potency -= block
            remaining -= block
            absorbed += block
        self.effects[str(target_key)] = [
            entry for entry in effects if entry.duration > 0.0 and not (entry.kind == "shield" and entry.potency <= 0.0)
        ]
        if not self.effects[str(target_key)]:
            self.effects.pop(str(target_key), None)
        return absorbed

    def update(
        self,
        dt: float,
        wolves: List[Dict[str, object]],
        damage_numbers: Optional[List[Dict[str, object]]] = None,
        spell_effects: Optional[List[Dict[str, object]]] = None,
    ) -> None:
        live_wolves: Dict[str, Dict[str, object]] = {}
        for wolf in wolves:
            if float(wolf.get("hp", 0.0)) <= 0.0:
                continue
            live_wolves[self.wolf_key(wolf)] = wolf
        for target_key in list(self.effects.keys()):
            if target_key != self.PLAYER_KEY and target_key not in live_wolves:
                self.effects.pop(target_key, None)
        if dt < 0.0:
            dt = 0.0
        if dt > 0.0:
            for target_key, effects in list(self.effects.items()):
                target_wolf = live_wolves.get(target_key)
                keep: List[StatusEffect] = []
                for effect in effects:
                    effect.duration = max(0.0, effect.duration - dt)
                    if effect.duration <= 0.0:
                        continue
                    if effect.kind == "burn" and effect.tick_interval > 0.0 and isinstance(target_wolf, dict):
                        effect.tick_timer -= dt
                        while effect.tick_timer <= 0.0 and effect.duration > 0.0:
                            pos_raw = target_wolf.get("pos")
                            hit_pos = Vector2(pos_raw) if isinstance(pos_raw, Vector2) else None
                            dealt = damage_wolf_entity(target_wolf, effect.potency, damage_numbers, hit_pos)
                            if dealt > 0.0 and isinstance(spell_effects, list) and isinstance(hit_pos, Vector2):
                                # Fire tick — rising flame sparks
                                spawn_particle_burst(
                                    spell_effects, hit_pos,
                                    effect.color, (255, 240, 180),
                                    count=5, speed_min=30.0, speed_max=100.0,
                                    life_min=0.12, life_max=0.34,
                                    size_start=3.2, size_end=0.4,
                                    spread=math.tau,
                                    gravity=-40.0, drag=1.4,
                                    vfx_scale=0.8,
                                )
                                # Ember sparks arcing up
                                spawn_particle_burst(
                                    spell_effects,
                                    Vector2(hit_pos.x, hit_pos.y - 8),
                                    (255, 200, 80), (255, 140, 40),
                                    count=3, speed_min=60.0, speed_max=160.0,
                                    life_min=0.08, life_max=0.22,
                                    size_start=1.8, size_end=0.2,
                                    spread=1.2,
                                    direction=Vector2(0, -1),
                                    gravity=50.0, drag=2.2,
                                    vfx_scale=0.6,
                                )
                            effect.tick_timer += max(0.01, effect.tick_interval)
                    if effect.kind == "shield" and effect.potency <= 0.0:
                        continue
                    keep.append(effect)
                if keep:
                    self.effects[target_key] = keep
                else:
                    self.effects.pop(target_key, None)
        for wolf in wolves:
            wolf["status_move_mult"] = 1.0
            wolf["status_disabled"] = False
            if float(wolf.get("hp", 0.0)) <= 0.0:
                wolf.pop("freeze_anchor", None)
                continue
            key = self.wolf_key(wolf)
            if key not in self.effects:
                wolf.pop("freeze_anchor", None)
                continue
            active = self.effects.get(key, [])
            is_frozen = any(entry.kind == "freeze" for entry in active)
            wolf["status_move_mult"] = self.move_multiplier(key)
            wolf["status_disabled"] = self.is_disabled(key)
            if is_frozen:
                pos_raw = wolf.get("pos")
                anchor_raw = wolf.get("freeze_anchor")
                if not isinstance(anchor_raw, Vector2) and isinstance(pos_raw, Vector2):
                    wolf["freeze_anchor"] = Vector2(pos_raw)
                    anchor_raw = wolf["freeze_anchor"]
                if isinstance(anchor_raw, Vector2):
                    wolf["pos"] = Vector2(anchor_raw)
                wolf["queued_strike"] = False
                wolf["attack_state"] = "idle"
                wolf["attack_timer"] = 0.0
                wolf["attack_visual"] = 0.0
            else:
                wolf.pop("freeze_anchor", None)

    def clear(self, wolves: Optional[List[Dict[str, object]]] = None) -> None:
        self.effects.clear()
        if isinstance(wolves, list):
            for wolf in wolves:
                wolf["status_move_mult"] = 1.0
                wolf["status_disabled"] = False
                wolf.pop("freeze_anchor", None)


class ScreenEffectController:
    def __init__(self) -> None:
        self.flashes: List[Dict[str, object]] = []

    def flash(
        self,
        color: Tuple[int, int, int],
        alpha: int = 100,
        duration: float = 0.16,
        additive: bool = True,
    ) -> None:
        self.flashes.append(
            {
                "color": color,
                "alpha": max(8, min(255, int(alpha))),
                "life": max(0.02, float(duration)),
                "duration": max(0.02, float(duration)),
                "additive": bool(additive),
            }
        )

    def update(self, dt: float) -> None:
        if dt <= 0.0 or not self.flashes:
            return
        keep: List[Dict[str, object]] = []
        for flash in self.flashes:
            flash["life"] = float(flash.get("life", 0.0)) - dt
            if float(flash.get("life", 0.0)) > 0.0:
                keep.append(flash)
        self.flashes = keep

    def draw(self, surface: pygame.Surface) -> None:
        for flash in self.flashes:
            life = float(flash.get("life", 0.0))
            duration = max(0.001, float(flash.get("duration", 0.1)))
            fade = clamp(life / duration, 0.0, 1.0)
            color = flash.get("color", (255, 255, 255))
            if not (isinstance(color, tuple) and len(color) == 3):
                color = (255, 255, 255)
            alpha = max(0, int(float(flash.get("alpha", 100)) * fade))
            if alpha <= 0:
                continue
            overlay = pygame.Surface((SCREEN_WIDTH, SCREEN_HEIGHT), pygame.SRCALPHA)
            overlay.fill((color[0], color[1], color[2], alpha))
            if bool(flash.get("additive", True)):
                surface.blit(overlay, (0, 0), special_flags=pygame.BLEND_RGBA_ADD)
            else:
                surface.blit(overlay, (0, 0))

    def clear(self) -> None:
        self.flashes.clear()


class QuestCelebrationVFX:
    """Button-anchored celebration: particles burst from the Complete Quest button."""

    def __init__(self) -> None:
        self.particles: List[Dict[str, float]] = []
        self.active = False
        self.timer = 0.0
        self.btn_rect: Optional[pygame.Rect] = None

    def trigger(self, btn_rect: Optional[pygame.Rect] = None) -> None:
        """Start celebration from the button position."""
        self.active = True
        self.timer = 1.6
        self.particles.clear()
        # Default to screen center if no rect
        if btn_rect:
            cx = btn_rect.centerx
            cy = btn_rect.centery
            self.btn_rect = pygame.Rect(btn_rect)
        else:
            cx, cy = SCREEN_WIDTH // 2, SCREEN_HEIGHT // 2
            self.btn_rect = None
        rng = random.Random()
        # Golden motes rising upward from button
        for _ in range(30):
            self.particles.append({
                "x": float(cx + rng.uniform(-60, 60)),
                "y": float(cy + rng.uniform(-8, 8)),
                "vx": rng.uniform(-20, 20),
                "vy": rng.uniform(-120, -50),
                "life": rng.uniform(0.8, 1.5),
                "max_life": 0.0,
                "size": rng.uniform(2, 4),
                "cr": rng.uniform(220, 255), "cg": rng.uniform(180, 230), "cb": rng.uniform(30, 80),
                "kind": "rise",
                "drift": rng.uniform(-10, 10),
                "phase": rng.uniform(0, 6.28),
            })
        # Sparkle burst outward from button edges
        for _ in range(24):
            angle = rng.uniform(0, 2 * math.pi)
            speed = rng.uniform(60, 180)
            self.particles.append({
                "x": float(cx + math.cos(angle) * 40),
                "y": float(cy + math.sin(angle) * 10),
                "vx": math.cos(angle) * speed,
                "vy": math.sin(angle) * speed * 0.5 - rng.uniform(20, 50),
                "life": rng.uniform(0.5, 1.0),
                "max_life": 0.0,
                "size": rng.uniform(1.5, 3.5),
                "cr": 255, "cg": rng.uniform(220, 255), "cb": rng.uniform(120, 200),
                "kind": "burst",
                "drift": 0.0, "phase": 0.0,
            })
        for p in self.particles:
            p["max_life"] = p["life"]

    def update(self, dt: float) -> None:
        if not self.active:
            return
        self.timer -= dt
        if self.timer <= 0:
            self.active = False
            self.particles.clear()
            return
        keep = []
        for p in self.particles:
            p["life"] -= dt
            if p["life"] <= 0:
                continue
            if p["kind"] == "rise":
                p["x"] += (p["vx"] + math.sin(p["life"] * 4 + p["phase"]) * p["drift"]) * dt
                p["y"] += p["vy"] * dt
            else:
                p["x"] += p["vx"] * dt
                p["y"] += p["vy"] * dt
                p["vx"] *= 0.97
                p["vy"] *= 0.97
            keep.append(p)
        self.particles = keep

    def draw(self, surface: pygame.Surface) -> None:
        if not self.active:
            return
        # Soft glow behind button area during effect
        if self.btn_rect and self.timer > 0.5:
            glow_a = int(50 * min(1.0, (self.timer - 0.5) / 0.5))
            gw, gh = self.btn_rect.width + 40, self.btn_rect.height + 30
            gs = pygame.Surface((gw, gh), pygame.SRCALPHA)
            pygame.draw.ellipse(gs, (255, 220, 80, glow_a), (0, 0, gw, gh))
            surface.blit(gs, (self.btn_rect.centerx - gw // 2, self.btn_rect.centery - gh // 2),
                         special_flags=pygame.BLEND_RGBA_ADD)
        # Particles
        for p in self.particles:
            fade = max(0.0, p["life"] / max(0.01, p["max_life"]))
            alpha = int(230 * fade)
            size = max(1, int(p["size"] * (0.4 + 0.6 * fade)))
            ps = pygame.Surface((size * 2 + 2, size * 2 + 2), pygame.SRCALPHA)
            pygame.draw.circle(ps, (int(p["cr"]), int(p["cg"]), int(p["cb"]), alpha),
                               (size + 1, size + 1), size)
            surface.blit(ps, (int(p["x"]) - size - 1, int(p["y"]) - size - 1),
                         special_flags=pygame.BLEND_RGBA_ADD)


class LevelUpVFX:
    """Minimalist but intense level-up VFX — pillar, ring, rising motes, sparkles."""

    def __init__(self) -> None:
        self.active = False
        self.timer = 0.0
        self.max_time = 3.0
        self.player_level = 0
        self.pillar_particles: List[Dict[str, float]] = []
        self.ring_particles: List[Dict[str, float]] = []
        self.sparkles: List[Dict[str, float]] = []
        self.text_alpha = 0.0
        self.text_scale = 0.0
        self._rng = random.Random()

    def trigger(self, level: int) -> None:
        self.active = True
        self.timer = 0.0
        self.player_level = level
        self.pillar_particles.clear()
        self.ring_particles.clear()
        self.sparkles.clear()
        self.text_alpha = 0.0
        self.text_scale = 0.0
        rng = self._rng
        # Rising golden motes from feet
        for _ in range(60):
            self.pillar_particles.append({
                "ox": rng.uniform(-28, 28),
                "vy": rng.uniform(-180, -400),
                "life": rng.uniform(0.6, 1.8),
                "max_life": 0.0,
                "delay": rng.uniform(0.0, 0.5),
                "size": rng.uniform(2.0, 5.0),
                "cr": rng.uniform(220, 255), "cg": rng.uniform(180, 230), "cb": rng.uniform(40, 100),
                "drift": rng.uniform(-15, 15),
                "phase": rng.uniform(0, 6.28),
            })
        for p in self.pillar_particles:
            p["max_life"] = p["life"]
        # Ring burst particles
        for _ in range(40):
            angle = rng.uniform(0, 2 * math.pi)
            speed = rng.uniform(100, 280)
            self.ring_particles.append({
                "vx": math.cos(angle) * speed,
                "vy": math.sin(angle) * speed * 0.4,
                "life": rng.uniform(0.5, 1.2),
                "max_life": 0.0,
                "delay": rng.uniform(0.2, 0.6),
                "size": rng.uniform(1.5, 4.0),
                "cr": rng.uniform(200, 255), "cg": rng.uniform(200, 255), "cb": rng.uniform(100, 200),
            })
        for p in self.ring_particles:
            p["max_life"] = p["life"]
        # Cross-shaped sparkles
        for _ in range(30):
            self.sparkles.append({
                "ox": rng.uniform(-60, 60),
                "oy": rng.uniform(-120, -20),
                "life": rng.uniform(1.0, 2.5),
                "max_life": 0.0,
                "delay": rng.uniform(0.3, 1.2),
                "twinkle_speed": rng.uniform(6, 14),
                "size": rng.uniform(1.5, 3.5),
                "phase": rng.uniform(0, 6.28),
            })
        for p in self.sparkles:
            p["max_life"] = p["life"]

    def update(self, dt: float) -> None:
        if not self.active:
            return
        self.timer += dt
        if self.timer > self.max_time:
            self.active = False
            return
        t = self.timer
        # Text: smooth scale punch then hold then fade
        if t < 0.4:
            p = t / 0.4
            self.text_scale = 1.0 + 0.3 * math.sin(p * math.pi)
            self.text_alpha = min(255, p * 400)
        elif t < 0.7:
            self.text_scale = 1.0 + 0.05 * math.sin((t - 0.4) / 0.3 * math.pi)
            self.text_alpha = 255
        elif t < 2.2:
            self.text_scale = 1.0
            self.text_alpha = 255
        else:
            fade = (t - 2.2) / 0.8
            self.text_scale = 1.0
            self.text_alpha = max(0, 255 * (1.0 - fade * fade))

    def draw(self, surface: pygame.Surface, px: float, py: float, font: pygame.font.Font) -> None:
        if not self.active:
            return
        t = self.timer
        cx = int(px)
        cy = int(py)
        foot_y = cy + 16

        # === Golden light pillar ===
        if t < 2.0:
            fade_in = min(1.0, t / 0.3)
            fade_out = max(0.0, 1.0 - max(0, t - 1.2) / 0.8)
            pillar_alpha = int(80 * fade_in * fade_out)
            if pillar_alpha > 0:
                pillar_w = 50 + int(20 * math.sin(t * 3))
                pillar_h = 200
                ps = pygame.Surface((pillar_w, pillar_h), pygame.SRCALPHA)
                for row in range(pillar_h):
                    row_t = row / pillar_h
                    a = int(pillar_alpha * (1.0 - row_t) * (0.6 + 0.4 * math.sin(row_t * 6 + t * 4)))
                    w_at_row = int(pillar_w * (0.3 + 0.7 * (1.0 - row_t)))
                    x_off = (pillar_w - w_at_row) // 2
                    pygame.draw.line(ps, (255, 220, 80, max(0, min(255, a))),
                                     (x_off, pillar_h - 1 - row), (x_off + w_at_row, pillar_h - 1 - row))
                surface.blit(ps, (cx - pillar_w // 2, foot_y - pillar_h), special_flags=pygame.BLEND_RGBA_ADD)

        # === Expanding ground ring ===
        if 0.15 < t < 1.5:
            ring_t = (t - 0.15) / 1.35
            ease_t = 1.0 - (1.0 - ring_t) ** 3
            ring_r = int(20 + 120 * ease_t)
            ring_alpha = int(150 * math.sin(ring_t * math.pi))
            ring_h = max(1, int(ring_r * 0.35))
            rs = pygame.Surface((ring_r * 2 + 4, ring_h * 2 + 4), pygame.SRCALPHA)
            col = (255, 230, 100, max(0, min(255, ring_alpha)))
            pygame.draw.ellipse(rs, col, (2, 2, ring_r * 2, ring_h * 2), 2)
            if ring_r > 10:
                inner_col = (255, 240, 150, max(0, min(255, ring_alpha // 2)))
                pygame.draw.ellipse(rs, inner_col, (6, 6, ring_r * 2 - 8, ring_h * 2 - 8), 1)
            surface.blit(rs, (cx - ring_r - 2, foot_y - ring_h - 2), special_flags=pygame.BLEND_RGBA_ADD)

        # === Rising golden motes ===
        for p in self.pillar_particles:
            age = t - p["delay"]
            if age < 0 or age > p["max_life"]:
                continue
            life_t = age / p["max_life"]
            fade = math.sin(life_t * math.pi)
            px2 = cx + p["ox"] + math.sin(age * 3 + p["phase"]) * p["drift"]
            py2 = foot_y + p["vy"] * age
            alpha = int(255 * fade)
            size = max(1, int(p["size"] * (0.5 + 0.5 * fade)))
            ps = pygame.Surface((size * 2 + 2, size * 2 + 2), pygame.SRCALPHA)
            pygame.draw.circle(ps, (int(p["cr"]), int(p["cg"]), int(p["cb"]), alpha),
                               (size + 1, size + 1), size)
            surface.blit(ps, (int(px2) - size - 1, int(py2) - size - 1), special_flags=pygame.BLEND_RGBA_ADD)

        # === Ring burst particles ===
        for p in self.ring_particles:
            age = t - p["delay"]
            if age < 0 or age > p["max_life"]:
                continue
            life_t = age / p["max_life"]
            fade = math.sin(life_t * math.pi)
            rx = cx + p["vx"] * age
            ry = foot_y + p["vy"] * age
            alpha = int(200 * fade)
            size = max(1, int(p["size"] * (0.3 + 0.7 * fade)))
            ps = pygame.Surface((size * 2 + 2, size * 2 + 2), pygame.SRCALPHA)
            pygame.draw.circle(ps, (int(p["cr"]), int(p["cg"]), int(p["cb"]), alpha),
                               (size + 1, size + 1), size)
            surface.blit(ps, (int(rx) - size - 1, int(ry) - size - 1), special_flags=pygame.BLEND_RGBA_ADD)

        # === Twinkling sparkles ===
        for p in self.sparkles:
            age = t - p["delay"]
            if age < 0 or age > p["max_life"]:
                continue
            life_t = age / p["max_life"]
            fade = math.sin(life_t * math.pi)
            twinkle = 0.5 + 0.5 * math.sin(age * p["twinkle_speed"] + p["phase"])
            alpha = int(220 * fade * twinkle)
            if alpha < 5:
                continue
            sx = cx + p["ox"] + math.sin(age * 1.5 + p["phase"]) * 8
            sy = cy + p["oy"] - age * 20
            size = max(1, int(p["size"] * twinkle))
            ss = pygame.Surface((size * 4 + 2, size * 4 + 2), pygame.SRCALPHA)
            sc = (255, 255, 220, alpha)
            center = size * 2 + 1
            pygame.draw.line(ss, sc, (center - size * 2, center), (center + size * 2, center), 1)
            pygame.draw.line(ss, sc, (center, center - size * 2), (center, center + size * 2), 1)
            pygame.draw.circle(ss, (255, 255, 200, min(255, alpha + 30)), (center, center), max(1, size // 2))
            surface.blit(ss, (int(sx) - center, int(sy) - center), special_flags=pygame.BLEND_RGBA_ADD)

        # === "Level X!" text ===
        if self.text_alpha > 5:
            txt = f"Level {self.player_level}!"
            ts = font.render(txt, True, (255, 230, 100))
            if self.text_scale > 0.1 and abs(self.text_scale - 1.0) > 0.01:
                new_w = max(1, int(ts.get_width() * self.text_scale))
                new_h = max(1, int(ts.get_height() * self.text_scale))
                ts = pygame.transform.smoothscale(ts, (new_w, new_h))
            ts_shadow = font.render(txt, True, (40, 20, 0))
            if self.text_scale > 0.1 and abs(self.text_scale - 1.0) > 0.01:
                ts_shadow = pygame.transform.smoothscale(ts_shadow, (ts.get_width(), ts.get_height()))
            alpha_int = max(0, min(255, int(self.text_alpha)))
            ts.set_alpha(alpha_int)
            ts_shadow.set_alpha(max(0, alpha_int - 40))
            tx = cx - ts.get_width() // 2
            float_up = int(20 * min(1.0, self.timer / 0.6))
            ty = cy - 120 - float_up - ts.get_height() // 2
            surface.blit(ts_shadow, (tx + 2, ty + 2))
            surface.blit(ts, (tx, ty))


class CameraDirector:
    def __init__(self, initial: Vector2) -> None:
        self.position = Vector2(initial)
        self.shake_strength = 0.0
        self.shake_time = 0.0
        self.shake_duration = 0.1
        self.seed = random.random() * math.tau

    def jump_to(self, pos: Vector2) -> None:
        self.position = Vector2(pos)
        self.shake_time = 0.0
        self.shake_strength = max(0.0, self.shake_strength * 0.4)

    def impulse(self, strength: float = 4.0, duration: float = 0.12) -> None:
        self.shake_strength = max(self.shake_strength, max(0.0, float(strength)))
        self.shake_duration = max(0.04, float(duration))
        self.shake_time = self.shake_duration

    def update(
        self,
        dt: float,
        target: Vector2,
        world_width: int,
        world_height: int,
        smooth: bool = True,
    ) -> Vector2:
        max_x = max(0.0, float(int(world_width) - SCREEN_WIDTH))
        max_y = max(0.0, float(int(world_height) - SCREEN_HEIGHT))
        goal_x = clamp(float(target.x), 0.0, max_x)
        goal_y = clamp(float(target.y), 0.0, max_y)

        if smooth and dt > 0.0:
            self.position.x = exp_smooth(self.position.x, goal_x, 11.6, dt)
            self.position.y = exp_smooth(self.position.y, goal_y, 10.8, dt)
        else:
            self.position.x = goal_x
            self.position.y = goal_y

        self.position.x = clamp(self.position.x, 0.0, max_x)
        self.position.y = clamp(self.position.y, 0.0, max_y)
        self.shake_time = max(0.0, self.shake_time - max(0.0, dt))
        return self.get_render_position()

    def get_render_position(self) -> Vector2:
        out = Vector2(self.position)
        if self.shake_time <= 0.0 or self.shake_strength <= 0.05:
            return out
        fade = clamp(self.shake_time / max(0.001, self.shake_duration), 0.0, 1.0)
        amp = self.shake_strength * (fade ** 1.15)
        ticks = pygame.time.get_ticks() * 0.045 + self.seed
        out.x += math.sin(ticks * 1.93) * amp
        out.y += math.cos(ticks * 2.31) * amp * 0.78
        return out


class AmbientOverlaySystem:
    def __init__(self) -> None:
        self.rng = random.Random(random.randrange(1_000_000_000))
        self.level = "town"
        self.particles: List[Dict[str, float]] = []
        self.layer = pygame.Surface((SCREEN_WIDTH, SCREEN_HEIGHT), pygame.SRCALPHA)

    def _target_count(self, level: str, cloud_cover: float, precipitation: float, fog_density: float) -> int:
        level_key = str(level).strip().lower()
        if level_key == "ice_biome":
            base = 58
        elif level_key == "wilderness":
            base = 66
        else:
            base = 52
        cloud_bonus = int(clamp(cloud_cover, 0.0, 1.0) * 14.0)
        fog_bonus = int(clamp(fog_density, 0.0, 1.0) * 18.0)
        rain_penalty = int(clamp(precipitation, 0.0, 1.0) * 16.0)
        return int(clamp(float(base + cloud_bonus + fog_bonus - rain_penalty), 26.0, 92.0))

    def _spawn_particle(self, level: str, initial: bool = False) -> Dict[str, float]:
        level_key = str(level).strip().lower()
        if level_key == "town":
            y = self.rng.uniform(-10.0, SCREEN_HEIGHT + 30.0) if initial else self.rng.uniform(SCREEN_HEIGHT + 4.0, SCREEN_HEIGHT + 44.0)
            return {
                "x": self.rng.uniform(-12.0, SCREEN_WIDTH + 12.0),
                "y": y,
                "vx": self.rng.uniform(-10.0, 10.0),
                "vy": -self.rng.uniform(12.0, 34.0),
                "size": self.rng.uniform(1.0, 2.6),
                "alpha": self.rng.uniform(62.0, 132.0),
                "phase": self.rng.uniform(0.0, math.tau),
                "twinkle": self.rng.uniform(1.1, 2.7),
                "mode": 0.0,  # ember
            }
        if level_key == "ice_biome":
            y = self.rng.uniform(-16.0, SCREEN_HEIGHT + 20.0) if initial else self.rng.uniform(-20.0, -4.0)
            return {
                "x": self.rng.uniform(-24.0, SCREEN_WIDTH + 24.0),
                "y": y,
                "vx": self.rng.uniform(-14.0, 14.0),
                "vy": self.rng.uniform(20.0, 54.0),
                "size": self.rng.uniform(1.0, 2.8),
                "alpha": self.rng.uniform(58.0, 142.0),
                "phase": self.rng.uniform(0.0, math.tau),
                "twinkle": self.rng.uniform(0.8, 1.9),
                "mode": 1.0,  # frost
            }
        side_left = self.rng.random() < 0.5
        x = self.rng.uniform(-20.0, SCREEN_WIDTH + 20.0) if initial else (-26.0 if side_left else SCREEN_WIDTH + 26.0)
        return {
            "x": x,
            "y": self.rng.uniform(HORIZON_Y - 26.0, SCREEN_HEIGHT + 30.0),
            "vx": self.rng.uniform(10.0, 40.0) * (1.0 if side_left else -1.0),
            "vy": self.rng.uniform(-6.0, 6.0),
            "size": self.rng.uniform(1.0, 2.2),
            "alpha": self.rng.uniform(46.0, 118.0),
            "phase": self.rng.uniform(0.0, math.tau),
            "twinkle": self.rng.uniform(0.9, 2.2),
            "mode": 2.0,  # pollen/dust
        }

    def update(self, dt: float, level: str, cloud_cover: float, precipitation: float, fog_density: float, wind: float) -> None:
        if dt <= 0.0:
            return
        level_key = str(level).strip().lower()
        target_count = self._target_count(level_key, cloud_cover, precipitation, fog_density)
        if level_key != self.level:
            self.level = level_key
            self.particles.clear()
        while len(self.particles) < target_count:
            self.particles.append(self._spawn_particle(level_key, initial=True))
        if len(self.particles) > target_count:
            del self.particles[target_count:]

        wind_push = float(wind) * 0.065
        for particle in self.particles:
            mode = int(float(particle.get("mode", 0.0)))
            particle["phase"] = (float(particle.get("phase", 0.0)) + float(particle.get("twinkle", 1.0)) * dt) % math.tau
            particle["x"] += (float(particle.get("vx", 0.0)) + wind_push) * dt
            particle["y"] += float(particle.get("vy", 0.0)) * dt
            if mode == 0:
                particle["x"] += math.sin(particle["phase"] * 1.4) * 6.0 * dt
            elif mode == 1:
                particle["x"] += math.sin(particle["phase"] * 1.6) * 8.0 * dt
            else:
                particle["y"] += math.sin(particle["phase"]) * 4.0 * dt

            x = float(particle.get("x", 0.0))
            y = float(particle.get("y", 0.0))
            if mode == 0:
                dead = y < -24.0 or x < -40.0 or x > SCREEN_WIDTH + 40.0
            elif mode == 1:
                dead = y > SCREEN_HEIGHT + 16.0 or x < -34.0 or x > SCREEN_WIDTH + 34.0
            else:
                dead = y < HORIZON_Y - 40.0 or y > SCREEN_HEIGHT + 24.0 or x < -34.0 or x > SCREEN_WIDTH + 34.0
            if dead:
                particle.clear()
                particle.update(self._spawn_particle(level_key, initial=False))

    def draw(
        self,
        surface: pygame.Surface,
        level: str,
        cloud_cover: float,
        precipitation: float,
        fog_density: float,
        day_time: float,
    ) -> None:
        if not self.particles:
            return
        level_key = str(level).strip().lower()
        hour = float(day_time) % 24.0
        if 6.0 <= hour < 18.0:
            night_factor = 0.0
        elif 18.0 <= hour < 20.0:
            night_factor = (hour - 18.0) / 2.0
        elif 5.0 <= hour < 7.0:
            night_factor = 1.0 - (hour - 5.0) / 2.0
        else:
            night_factor = 1.0
        weather_dampen = 1.0 - clamp(float(precipitation), 0.0, 1.0) * 0.38
        fog_boost = 0.9 + clamp(float(fog_density), 0.0, 1.0) * 0.3
        self.layer.fill((0, 0, 0, 0))
        for particle in self.particles:
            mode = int(float(particle.get("mode", 0.0)))
            twinkle = 0.58 + 0.42 * math.sin(float(particle.get("phase", 0.0)))
            alpha = int(float(particle.get("alpha", 70.0)) * twinkle * weather_dampen * fog_boost)
            if alpha <= 8:
                continue
            if level_key == "town":
                light_boost = 0.72 + night_factor * 0.62
                color = (246, 166, 94, int(alpha * light_boost))
            elif level_key == "ice_biome":
                light_boost = 0.86 + night_factor * 0.34 + clamp(float(cloud_cover), 0.0, 1.0) * 0.15
                color = (210, 236, 255, int(alpha * light_boost))
            else:
                light_boost = 0.74 + clamp(float(cloud_cover), 0.0, 1.0) * 0.34
                color = (188, 208, 160, int(alpha * light_boost))

            px = int(float(particle.get("x", 0.0)))
            py = int(float(particle.get("y", 0.0)))
            radius = max(1, int(float(particle.get("size", 1.0))))
            pygame.gfxdraw.filled_circle(self.layer, px, py, radius, color)
            if radius > 1 and mode != 0:
                pygame.gfxdraw.aacircle(self.layer, px, py, radius, color)
        surface.blit(self.layer, (0, 0))


class UltimateContext:
    def __init__(
        self,
        player_get: Any,
        player_set: Any,
        facing_get: Any,
        wolves: List[Dict[str, object]],
        walk_bounds: pygame.Rect,
        obstacles: List[pygame.Rect],
        status_effects: StatusEffectSystem,
        screen_effects: ScreenEffectController,
        damage_numbers: List[Dict[str, object]],
        spell_effects: List[Dict[str, object]],
        set_status: Any,
    ) -> None:
        self._player_get = player_get
        self._player_set = player_set
        self._facing_get = facing_get
        self.wolves = wolves
        self.walk_bounds = walk_bounds
        self.obstacles = obstacles
        self.status_effects = status_effects
        self.screen_effects = screen_effects
        self.damage_numbers = damage_numbers
        self.spell_effects = spell_effects
        self._set_status = set_status

    def player_pos(self) -> Vector2:
        value = self._player_get()
        if isinstance(value, Vector2):
            return Vector2(value)
        return Vector2(0.0, 0.0)

    def player_facing(self) -> int:
        try:
            return 1 if int(self._facing_get()) >= 0 else -1
        except (TypeError, ValueError):
            return 1

    def move_player(self, pos: Vector2) -> None:
        self._player_set(Vector2(pos))

    def status(self, text: str, duration: float = 1.2) -> None:
        self._set_status(text, duration)

    def living_wolves(self) -> List[Dict[str, object]]:
        return [wolf for wolf in self.wolves if float(wolf.get("hp", 0.0)) > 0.0 and isinstance(wolf.get("pos"), Vector2)]

    def find_wolf_by_id(self, wolf_id: int) -> Optional[Dict[str, object]]:
        for wolf in self.wolves:
            if id(wolf) == wolf_id and float(wolf.get("hp", 0.0)) > 0.0:
                return wolf
        return None

    def nearest_wolf(
        self,
        origin: Vector2,
        max_dist: float = 99999.0,
        exclude: Optional[Set[int]] = None,
    ) -> Optional[Dict[str, object]]:
        best: Optional[Dict[str, object]] = None
        best_dist = max(0.0, float(max_dist))
        excluded = exclude if isinstance(exclude, set) else set()
        for wolf in self.wolves:
            if float(wolf.get("hp", 0.0)) <= 0.0 or id(wolf) in excluded:
                continue
            pos_raw = wolf.get("pos")
            if not isinstance(pos_raw, Vector2):
                continue
            dist = Vector2(pos_raw).distance_to(origin)
            if dist > best_dist:
                continue
            best_dist = dist
            best = wolf
        return best

    def wolves_in_radius(self, origin: Vector2, radius: float) -> List[Dict[str, object]]:
        rr = max(0.0, float(radius))
        rr_sq = rr * rr
        found: List[Dict[str, object]] = []
        for wolf in self.wolves:
            if float(wolf.get("hp", 0.0)) <= 0.0:
                continue
            pos_raw = wolf.get("pos")
            if not isinstance(pos_raw, Vector2):
                continue
            if Vector2(pos_raw).distance_squared_to(origin) <= rr_sq:
                found.append(wolf)
        return found

    def damage_wolf(
        self,
        wolf: Dict[str, object],
        amount: float,
        hit_pos: Optional[Vector2] = None,
        gore: float = 1.0,
    ) -> float:
        amount = float(amount)
        if isinstance(self.status_effects, StatusEffectSystem):
            scorched = self.status_effects.consume_effect(self.status_effects.wolf_key(wolf), "scorched")
            if isinstance(scorched, StatusEffect):
                amount *= 1.0 + max(0.0, scorched.potency)
                if isinstance(hit_pos, Vector2):
                    spawn_particle_burst(
                        self.spell_effects,
                        Vector2(hit_pos),
                        (255, 190, 118),
                        (255, 236, 190),
                        count=4,
                        speed_min=40.0,
                        speed_max=120.0,
                        life_min=0.10,
                        life_max=0.28,
                        size_start=2.6,
                        size_end=0.4,
                        spread=math.tau,
                        gravity=-16.0,
                        drag=1.4,
                        vfx_scale=0.8,
                    )
        dealt = damage_wolf_entity(wolf, amount, self.damage_numbers, hit_pos)
        if dealt > 0.0:
            wolf["chasing"] = True
            wolf["aggro_timer"] = max(float(wolf.get("aggro_timer", 0.0)), 1.2)
            if gore > 0.0:
                pos = hit_pos
                if not isinstance(pos, Vector2):
                    pos_raw = wolf.get("pos")
                    if isinstance(pos_raw, Vector2):
                        pos = Vector2(pos_raw)
                if isinstance(pos, Vector2):
                    spawn_blood_splatter(self.spell_effects, pos, intensity=max(0.3, gore))
        return dealt

    def nearest_walkable(self, pos: Vector2, radius: float = PLAYER_COLLISION_RADIUS) -> Vector2:
        return nearest_walkable(Vector2(pos), self.walk_bounds, self.obstacles, float(radius))

    def is_walkable(self, pos: Vector2, radius: float = PLAYER_COLLISION_RADIUS) -> bool:
        return is_walkable(Vector2(pos), self.walk_bounds, self.obstacles, float(radius))

    def push_wolf(self, wolf: Dict[str, object], direction: Vector2, distance: float) -> None:
        pos_raw = wolf.get("pos")
        if not isinstance(pos_raw, Vector2):
            return
        if direction.length_squared() <= 1e-6 or distance <= 1.0:
            return
        target = Vector2(pos_raw) + direction.normalize() * distance
        radius = max(8.0, float(wolf.get("radius", WOLF_COLLISION_RADIUS)))
        wolf["pos"] = nearest_walkable(target, self.walk_bounds, self.obstacles, radius)


class UltimateBase:
    def __init__(
        self,
        spell: Dict[str, object],
        caster_pos: Vector2,
        target_pos: Vector2,
        facing: int,
        bonus_power: float,
        spell_mods: Optional[Dict[str, float]] = None,
        class_damage_mult: float = 1.0,
    ) -> None:
        self.spell = dict(spell)
        self.spell_id = str(spell.get("id", "ultimate"))
        self.name = str(spell.get("name", "Ultimate"))
        self.caster_pos = Vector2(caster_pos)
        self.target_pos = Vector2(target_pos)
        self.facing = 1 if int(facing) >= 0 else -1
        self.bonus_power = float(bonus_power)
        self.mods = dict(spell_mods or {})
        self.damage_scale = max(0.1, float(self.mods.get("damage_mult", 1.0))) * max(0.1, float(class_damage_mult))
        self.radius_scale = max(0.1, float(self.mods.get("radius_mult", 1.0))) * max(0.1, float(self.mods.get("max_radius_mult", 1.0)))
        self.duration_scale = max(0.1, float(self.mods.get("duration_mult", 1.0)))
        self.interval_scale = max(0.2, float(self.mods.get("interval_mult", 1.0)))
        self.base_damage = (float(spell.get("damage", 18.0)) + self.bonus_power * 5.5 + float(self.mods.get("bonus_damage", 0.0))) * self.damage_scale
        self.core_color, self.accent_color, self.shadow_color = spell_vfx_palette(
            self.spell_id,
            spell.get("colors") if isinstance(spell.get("colors"), dict) else {},
        )
        self.emitters: List[ParticleEmitter] = []
        self.elapsed = 0.0
        self.finished = False
        self.movement_mult = 1.0

    def add_emitter(self) -> ParticleEmitter:
        emitter = ParticleEmitter()
        self.emitters.append(emitter)
        return emitter

    def start(self, ctx: UltimateContext) -> None:
        pass

    def update(self, dt: float, ctx: UltimateContext) -> None:
        self.elapsed += max(0.0, dt)
        for emitter in self.emitters:
            emitter.update(dt)

    def draw(self, surface: pygame.Surface, camera: Vector2) -> None:
        for emitter in self.emitters:
            emitter.draw(surface, camera)

    def is_alive(self) -> bool:
        return (not self.finished) or any(emitter.alive() for emitter in self.emitters)


class MageBeamUltimate(UltimateBase):
    def __init__(self, *args: Any, **kwargs: Any) -> None:
        super().__init__(*args, **kwargs)
        self.windup = 0.34
        self.active_time = 0.52 * self.duration_scale
        self.fade_time = 0.24
        self.length = clamp(self.caster_pos.distance_to(self.target_pos), 320.0, 760.0)
        self.width = 34.0 * self.radius_scale
        self.fired = False
        self.hit_ids: Set[int] = set()
        self.emitter = self.add_emitter()

    def _origin_and_end(self, ctx: UltimateContext) -> Tuple[Vector2, Vector2, Vector2]:
        origin = ctx.player_pos() + Vector2(0.0, -26.0)
        aim = self.target_pos - origin
        if aim.length_squared() <= 1e-5:
            aim = Vector2(float(self.facing), 0.0)
        direction = aim.normalize()
        return origin, origin + direction * self.length, direction

    def update(self, dt: float, ctx: UltimateContext) -> None:
        super().update(dt, ctx)
        self.caster_pos = ctx.player_pos() + Vector2(0.0, -26.0)
        origin, end, direction = self._origin_and_end(ctx)
        self.target_pos = Vector2(end)
        if self.elapsed < self.windup:
            if random.random() < 0.8:
                self.emitter.burst(
                    origin + direction * random.uniform(10.0, 40.0),
                    self.core_color,
                    self.accent_color,
                    count=2,
                    speed_min=22.0,
                    speed_max=72.0,
                    life_min=0.12,
                    life_max=0.28,
                    size_start=2.8,
                    size_end=0.5,
                    spread=0.8,
                    direction=direction,
                    gravity=-16.0,
                    drag=1.4,
                    shape="spark",
                )
            return
        if not self.fired:
            self.fired = True
            ctx.screen_effects.flash((236, 218, 178), alpha=92, duration=0.12)
            self.emitter.burst(
                origin,
                self.core_color,
                self.accent_color,
                count=24,
                speed_min=180.0,
                speed_max=360.0,
                life_min=0.16,
                life_max=0.36,
                size_start=4.6,
                size_end=0.6,
                spread=0.42,
                direction=direction,
                drag=1.6,
                shape="spark",
            )
        if self.elapsed <= self.windup + self.active_time:
            beam_radius = self.width * 0.5 + 22.0
            for wolf in ctx.living_wolves():
                wolf_id = id(wolf)
                if wolf_id in self.hit_ids:
                    continue
                pos_raw = wolf.get("pos")
                if not isinstance(pos_raw, Vector2):
                    continue
                if not circle_hits_segment(Vector2(pos_raw), beam_radius, origin, end):
                    continue
                dealt = ctx.damage_wolf(wolf, self.base_damage * 2.5, Vector2(pos_raw), gore=1.35)
                if dealt <= 0.0:
                    continue
                self.hit_ids.add(wolf_id)
                ctx.status_effects.add_effect(
                    ctx.status_effects.wolf_key(wolf),
                    StatusEffect("burn", 3.2, potency=max(4.0, self.base_damage * 0.18), tick_interval=0.55, color=self.accent_color),
                )
                self.emitter.burst(
                    Vector2(pos_raw),
                    self.accent_color,
                    (255, 245, 220),
                    count=12,
                    speed_min=90.0,
                    speed_max=220.0,
                    life_min=0.12,
                    life_max=0.30,
                    size_start=3.6,
                    size_end=0.5,
                    spread=math.tau,
                    gravity=-20.0,
                    drag=1.2,
                    shape="spark",
                )
            for _ in range(3):
                spark_pos = origin.lerp(end, random.uniform(0.15, 1.0))
                self.emitter.burst(
                    spark_pos,
                    self.core_color,
                    self.accent_color,
                    count=2,
                    speed_min=30.0,
                    speed_max=86.0,
                    life_min=0.10,
                    life_max=0.24,
                    size_start=2.4,
                    size_end=0.4,
                    spread=math.tau,
                    gravity=-10.0,
                    drag=1.1,
                    shape="spark",
                )
        elif self.elapsed >= self.windup + self.active_time + self.fade_time:
            self.finished = True

    def draw(self, surface: pygame.Surface, camera: Vector2) -> None:
        if self.finished:
            super().draw(surface, camera)
            return
        draw_surface = pygame.Surface((SCREEN_WIDTH, SCREEN_HEIGHT), pygame.SRCALPHA)
        sx1 = int(self.caster_pos.x - camera.x)
        sy1 = int(self.caster_pos.y - camera.y)
        sx2 = int(self.target_pos.x - camera.x)
        sy2 = int(self.target_pos.y - camera.y)
        if self.elapsed < self.windup:
            ratio = clamp(self.elapsed / max(0.001, self.windup), 0.0, 1.0)
            width = max(2, int(4 + 8 * ratio))
            pygame.draw.line(draw_surface, (*self.accent_color, 90), (sx1, sy1), (sx2, sy2), width)
            pygame.draw.circle(draw_surface, (*self.accent_color, 110), (sx2, sy2), int(18 + 16 * ratio), 2)
        else:
            fade = 1.0
            if self.elapsed > self.windup + self.active_time:
                tail = self.elapsed - (self.windup + self.active_time)
                fade = clamp(1.0 - tail / max(0.001, self.fade_time), 0.0, 1.0)
            outer_w = max(6, int(self.width * fade))
            inner_w = max(2, int(self.width * 0.44 * fade))
            pygame.draw.line(draw_surface, (*self.shadow_color, int(150 * fade)), (sx1, sy1), (sx2, sy2), outer_w + 6)
            pygame.draw.line(draw_surface, (*self.accent_color, int(220 * fade)), (sx1, sy1), (sx2, sy2), outer_w)
            pygame.draw.line(draw_surface, (*self.core_color, int(255 * fade)), (sx1, sy1), (sx2, sy2), inner_w)
            pygame.draw.circle(draw_surface, (*self.accent_color, int(160 * fade)), (sx2, sy2), max(12, int(self.width * 0.65 * fade)))
        surface.blit(draw_surface, (0, 0))
        super().draw(surface, camera)


class MageCataclysmUltimate(UltimateBase):
    def __init__(self, *args: Any, **kwargs: Any) -> None:
        super().__init__(*args, **kwargs)
        self.windup = 0.35
        self.channel_time = 5.0 * self.duration_scale
        self.fade_time = 0.35
        self.start_radius = 70.0 * self.radius_scale
        self.end_radius = 220.0 * self.radius_scale
        self.orbit_speed = 3.1
        self.tick_interval = max(0.08, 0.22 * self.interval_scale)
        self.tick_timer = 0.0
        self.movement_mult = 0.55
        self.elements = ["wind", "fire", "ice", "earth"]
        self.element_emitters: Dict[str, ParticleEmitter] = {name: self.add_emitter() for name in self.elements}
        self.core_emitter = self.add_emitter()
        self.element_colors = {
            "wind": ((204, 234, 255), (120, 176, 214)),
            "fire": ((255, 182, 108), (255, 120, 62)),
            "ice": ((176, 224, 255), (118, 176, 214)),
            "earth": ((168, 136, 96), (94, 76, 54)),
        }
        self.storm_radius = max(70.0, self.end_radius * 0.45)
        self.pull_strength = 26.0 * self.radius_scale

    def start(self, ctx: UltimateContext) -> None:
        ctx.screen_effects.flash((24, 30, 42), alpha=120, duration=0.30, additive=False)
        ctx.status("Elemental Cataclysm unleashed.", 1.4)
        self.core_emitter.burst(
            ctx.player_pos() + Vector2(0.0, -18.0),
            (180, 210, 240),
            (120, 150, 200),
            count=16,
            speed_min=60.0,
            speed_max=160.0,
            life_min=0.18,
            life_max=0.42,
            size_start=3.8,
            size_end=0.6,
            spread=math.tau,
            gravity=-18.0,
            drag=1.2,
            shape="spark",
        )

    def _element_positions(self) -> List[Tuple[str, Vector2]]:
        if self.elapsed <= self.windup:
            progress = 0.0
        else:
            progress = clamp((self.elapsed - self.windup) / max(0.001, self.channel_time), 0.0, 1.0)
        radius = self.start_radius + (self.end_radius - self.start_radius) * progress
        base_angle = self.elapsed * self.orbit_speed
        positions: List[Tuple[str, Vector2]] = []
        count = max(1, len(self.elements))
        for idx, element in enumerate(self.elements):
            ang = base_angle + idx * (math.tau / float(count))
            orbit = Vector2(math.cos(ang), math.sin(ang) * 0.65)
            positions.append((element, self.caster_pos + orbit * radius))
        return positions

    def update(self, dt: float, ctx: UltimateContext) -> None:
        super().update(dt, ctx)
        self.caster_pos = ctx.player_pos() + Vector2(0.0, -18.0)
        if self.elapsed < self.windup:
            if random.random() < 0.6:
                self.core_emitter.burst(
                    self.caster_pos,
                    (214, 236, 255),
                    (126, 160, 210),
                    count=2,
                    speed_min=20.0,
                    speed_max=70.0,
                    life_min=0.12,
                    life_max=0.32,
                    size_start=2.6,
                    size_end=0.4,
                    spread=math.tau,
                    gravity=-16.0,
                    drag=1.4,
                    shape="spark",
                )
            return
        if self.elapsed >= self.windup + self.channel_time + self.fade_time:
            self.finished = True
            return

        positions = self._element_positions()
        swirl_angle = pygame.time.get_ticks() * 0.003
        ring_pos = self.caster_pos + Vector2(math.cos(swirl_angle), math.sin(swirl_angle) * 0.6) * 26.0
        self.core_emitter.burst(
            ring_pos,
            (210, 232, 255),
            (132, 168, 212),
            count=1,
            speed_min=18.0,
            speed_max=60.0,
            life_min=0.14,
            life_max=0.34,
            size_start=2.8,
            size_end=0.4,
            spread=math.tau,
            gravity=-12.0,
            drag=1.5,
            shape="spark",
        )

        for element, pos in positions:
            emitter = self.element_emitters[element]
            core_col, accent_col = self.element_colors[element]
            emitter.burst(
                pos,
                core_col,
                accent_col,
                count=2,
                speed_min=24.0,
                speed_max=90.0,
                life_min=0.16,
                life_max=0.44,
                size_start=3.4,
                size_end=0.6,
                spread=math.tau,
                gravity=-16.0,
                drag=1.3,
            )
            if element == "fire" and random.random() < 0.35:
                meteor_dir = Vector2(1.0, 1.0).normalize()
                start = pos + Vector2(-90.0, -90.0)
                emitter.burst(
                    start,
                    core_col,
                    accent_col,
                    count=2,
                    speed_min=220.0,
                    speed_max=360.0,
                    life_min=0.10,
                    life_max=0.22,
                    size_start=2.6,
                    size_end=0.4,
                    spread=0.32,
                    direction=meteor_dir,
                    gravity=80.0,
                    drag=2.2,
                    shape="spark",
                    streak=18.0,
                )

        self.tick_timer -= dt
        if self.tick_timer <= 0.0:
            self.tick_timer += self.tick_interval
            storm_radius = self.storm_radius
            damage_per_hit = self.base_damage * 0.45
            for element, pos in positions:
                for wolf in ctx.living_wolves():
                    wpos_raw = wolf.get("pos")
                    if not isinstance(wpos_raw, Vector2):
                        continue
                    if Vector2(wpos_raw).distance_squared_to(pos) > storm_radius * storm_radius:
                        continue
                    hit_pos = Vector2(wpos_raw.x, wpos_raw.y)
                    dealt = ctx.damage_wolf(wolf, damage_per_hit, hit_pos, gore=1.1)
                    if dealt <= 0.0:
                        continue
                    if element == "fire":
                        ctx.status_effects.add_effect(
                            ctx.status_effects.wolf_key(wolf),
                            StatusEffect("burn", 2.4, potency=max(3.0, self.base_damage * 0.14), tick_interval=0.55, color=(255, 154, 84)),
                        )
                    elif element == "ice":
                        ctx.status_effects.add_effect(
                            ctx.status_effects.wolf_key(wolf),
                            StatusEffect("freeze", 0.65, potency=1.0, color=(178, 224, 255)),
                        )
                    elif element == "wind":
                        pull_dir = self.caster_pos - hit_pos
                        if pull_dir.length_squared() > 1e-6:
                            ctx.push_wolf(wolf, pull_dir, self.pull_strength)
                    elif element == "earth":
                        ctx.status_effects.add_effect(
                            ctx.status_effects.wolf_key(wolf),
                            StatusEffect("stun", 0.45, potency=1.0, color=(168, 140, 102)),
                        )

    def draw(self, surface: pygame.Surface, camera: Vector2) -> None:
        if self.finished:
            super().draw(surface, camera)
            return
        if self.elapsed < self.windup:
            fade = clamp(self.elapsed / max(0.001, self.windup), 0.0, 1.0)
        elif self.elapsed > self.windup + self.channel_time:
            tail = self.elapsed - (self.windup + self.channel_time)
            fade = clamp(1.0 - tail / max(0.001, self.fade_time), 0.0, 1.0)
        else:
            fade = 1.0

        overlay = pygame.Surface((SCREEN_WIDTH, SCREEN_HEIGHT), pygame.SRCALPHA)
        overlay.fill((8, 10, 16, int(120 * fade)))
        surface.blit(overlay, (0, 0))

        now_ult = pygame.time.get_ticks() * 0.001
        cx_ult = int(self.caster_pos.x - camera.x)
        cy_ult = int(self.caster_pos.y - camera.y)

        # Outer storm vortex ring — swirling energy connecting the elements
        vortex_r = max(40, int(self.storm_radius * 1.3))
        vortex_segs = 32
        for vi in range(vortex_segs):
            v_ang = vi * (math.tau / vortex_segs) + now_ult * 2.5
            v_ang2 = (vi + 1) * (math.tau / vortex_segs) + now_ult * 2.5
            wobble = math.sin(now_ult * 6.0 + vi * 0.8) * 8.0
            r1 = vortex_r + wobble
            r2 = vortex_r + math.sin(now_ult * 6.0 + (vi + 1) * 0.8) * 8.0
            vx1 = cx_ult + int(math.cos(v_ang) * r1)
            vy1 = cy_ult + int(math.sin(v_ang) * r1 * 0.65)
            vx2 = cx_ult + int(math.cos(v_ang2) * r2)
            vy2 = cy_ult + int(math.sin(v_ang2) * r2 * 0.65)
            # Color cycles through elements
            elem_idx = int((v_ang / math.tau * 4) % 4)
            elem_name = self.elements[elem_idx]
            vc, _ = self.element_colors[elem_name]
            v_alpha = max(16, int(60 * fade))
            pygame.draw.line(surface, (vc[0], vc[1], vc[2], v_alpha), (vx1, vy1), (vx2, vy2), 2)

        # Ground scorch/frost ring beneath the storm
        ground_r = max(30, int(vortex_r * 0.7))
        pygame.gfxdraw.filled_circle(surface, cx_ult, cy_ult, ground_r, (40, 30, 50, int(50 * fade)))
        pygame.gfxdraw.aacircle(surface, cx_ult, cy_ult, ground_r, (120, 100, 160, int(80 * fade)))

        positions = self._element_positions()
        for element, pos in positions:
            esx = int(pos.x - camera.x)
            esy = int(pos.y - camera.y)
            core_col, accent_col = self.element_colors[element]

            # Element-specific visuals
            if element == "fire":
                # Flickering flame orb
                flame_r = 18 + int(4 * math.sin(now_ult * 16.0))
                pygame.gfxdraw.filled_circle(surface, esx, esy, flame_r + 8, (255, 80, 20, int(40 * fade)))
                pygame.gfxdraw.filled_circle(surface, esx, esy, flame_r + 4, (255, 140, 40, int(80 * fade)))
                pygame.gfxdraw.filled_circle(surface, esx, esy, flame_r, (core_col[0], core_col[1], core_col[2], int(200 * fade)))
                pygame.gfxdraw.filled_circle(surface, esx, esy - 2, max(3, flame_r - 6), (255, 230, 180, int(220 * fade)))
                # Rising heat wisps
                for wi in range(3):
                    wy = esy - 10 - int((now_ult * 40.0 + wi * 15) % 30)
                    wx = esx + int(math.sin(now_ult * 8.0 + wi * 2.0) * 5)
                    pygame.gfxdraw.filled_circle(surface, wx, wy, 2, (255, 180, 80, int(60 * fade)))
            elif element == "ice":
                # Frozen crystal orb with rotating shards
                ice_r = 16 + int(3 * math.sin(now_ult * 8.0))
                pygame.gfxdraw.filled_circle(surface, esx, esy, ice_r + 8, (80, 140, 220, int(35 * fade)))
                pygame.gfxdraw.filled_circle(surface, esx, esy, ice_r + 3, (140, 200, 255, int(90 * fade)))
                pygame.gfxdraw.filled_circle(surface, esx, esy, ice_r, (core_col[0], core_col[1], core_col[2], int(200 * fade)))
                pygame.gfxdraw.filled_circle(surface, esx - 2, esy - 2, max(2, ice_r // 2), (240, 250, 255, int(200 * fade)))
                # Orbiting ice shards
                for si in range(4):
                    s_ang = now_ult * 4.0 + si * (math.tau / 4)
                    s_x = esx + int(math.cos(s_ang) * (ice_r + 6))
                    s_y = esy + int(math.sin(s_ang) * (ice_r + 6))
                    pygame.draw.line(surface, (200, 235, 255, int(140 * fade)), (s_x - 2, s_y - 3), (s_x + 2, s_y + 3), 2)
            elif element == "wind":
                # Swirling vortex funnel
                wind_r = 16 + int(3 * math.sin(now_ult * 10.0))
                pygame.gfxdraw.filled_circle(surface, esx, esy, wind_r + 10, (140, 190, 230, int(25 * fade)))
                pygame.gfxdraw.filled_circle(surface, esx, esy, wind_r + 4, (core_col[0], core_col[1], core_col[2], int(70 * fade)))
                pygame.gfxdraw.aacircle(surface, esx, esy, wind_r, (core_col[0], core_col[1], core_col[2], int(180 * fade)))
                # Spinning wind arcs
                for ai in range(3):
                    a_ang = now_ult * 7.0 + ai * (math.tau / 3)
                    a_r = wind_r - 2
                    arc_rect = pygame.Rect(esx - a_r, esy - a_r, a_r * 2, a_r * 2)
                    pygame.draw.arc(surface, (220, 240, 255, int(120 * fade)), arc_rect, a_ang, a_ang + 1.2, 2)
            elif element == "earth":
                # Rocky boulder orb with floating debris
                earth_r = 16 + int(2 * math.sin(now_ult * 5.0))
                pygame.gfxdraw.filled_circle(surface, esx, esy, earth_r + 6, (100, 80, 50, int(50 * fade)))
                pygame.gfxdraw.filled_circle(surface, esx, esy, earth_r + 2, (core_col[0], core_col[1], core_col[2], int(180 * fade)))
                pygame.gfxdraw.filled_circle(surface, esx, esy, earth_r, (accent_col[0], accent_col[1], accent_col[2], int(210 * fade)))
                # Stone texture lines
                for li in range(3):
                    lx = esx - earth_r + 4 + li * (earth_r * 2 // 4)
                    pygame.draw.line(surface, (80, 60, 40, int(100 * fade)), (lx, esy - earth_r // 2), (lx + 2, esy + earth_r // 2), 1)
                # Floating rock fragments
                for fi in range(3):
                    f_ang = now_ult * 2.5 + fi * 2.1
                    f_r = earth_r + 8 + int(math.sin(now_ult * 3.0 + fi) * 4)
                    fx_p = esx + int(math.cos(f_ang) * f_r)
                    fy_p = esy + int(math.sin(f_ang) * f_r) - int(math.sin(now_ult * 4.0 + fi * 1.3) * 3)
                    pygame.draw.rect(surface, (accent_col[0], accent_col[1], accent_col[2], int(140 * fade)),
                        pygame.Rect(fx_p - 2, fy_p - 2, 4, 3))

            # Lightning arc connecting elements to caster
            arc_alpha = max(12, int(40 * fade * (0.5 + 0.5 * math.sin(now_ult * 12.0 + hash(element) * 0.01))))
            arc_steps = 5
            prev_pt = (cx_ult, cy_ult)
            for ai in range(arc_steps + 1):
                a_frac = ai / arc_steps
                ax = int(cx_ult + (esx - cx_ult) * a_frac)
                ay = int(cy_ult + (esy - cy_ult) * a_frac)
                if 0 < ai < arc_steps:
                    ax += int(math.sin(now_ult * 20.0 + ai * 3.0 + hash(element) * 0.01) * 8)
                    ay += int(math.cos(now_ult * 18.0 + ai * 2.7 + hash(element) * 0.01) * 6)
                pygame.draw.line(surface, (accent_col[0], accent_col[1], accent_col[2], arc_alpha), prev_pt, (ax, ay), 1)
                prev_pt = (ax, ay)

        # Central caster aura — pulsing energy core
        aura_pulse = 0.6 + 0.4 * math.sin(now_ult * 6.0)
        aura_r = int(22 * aura_pulse)
        pygame.gfxdraw.filled_circle(surface, cx_ult, cy_ult, aura_r + 8, (180, 200, 240, int(30 * fade)))
        pygame.gfxdraw.filled_circle(surface, cx_ult, cy_ult, aura_r, (220, 230, 255, int(80 * fade)))
        pygame.gfxdraw.aacircle(surface, cx_ult, cy_ult, aura_r + 4, (200, 220, 255, int(100 * fade)))

        super().draw(surface, camera)


class RogueTeleportUltimate(UltimateBase):
    def __init__(self, *args: Any, **kwargs: Any) -> None:
        super().__init__(*args, **kwargs)
        self.route_ids: List[int] = []
        self.windup = 0.12
        self.strike_interval = max(0.08, 0.16 * self.interval_scale)
        self.next_strike_time = self.windup
        self.strike_index = 0
        self.final_burst_done = False
        self.smoke = self.add_emitter()

    def start(self, ctx: UltimateContext) -> None:
        candidates = [
            wolf for wolf in ctx.living_wolves()
            if isinstance(wolf.get("pos"), Vector2)
            and Vector2(wolf["pos"]).distance_to(self.target_pos) <= 520.0
        ]
        if not candidates:
            candidates = [
                wolf for wolf in ctx.living_wolves()
                if isinstance(wolf.get("pos"), Vector2)
                and Vector2(wolf["pos"]).distance_to(ctx.player_pos()) <= 420.0
            ]
        max_hits = max(2, 4 + int(round(float(self.mods.get("projectile_count_bonus", 0.0)))))
        chosen: List[Dict[str, object]] = []
        pivot = Vector2(self.target_pos)
        while candidates and len(chosen) < max_hits:
            nxt = min(candidates, key=lambda wolf: Vector2(wolf["pos"]).distance_to(pivot))
            candidates.remove(nxt)
            chosen.append(nxt)
            pivot = Vector2(nxt["pos"])
        self.route_ids = [id(wolf) for wolf in chosen]
        self.smoke.burst(
            ctx.player_pos() + Vector2(0.0, -10.0),
            self.accent_color,
            self.shadow_color,
            count=22,
            speed_min=80.0,
            speed_max=190.0,
            life_min=0.18,
            life_max=0.44,
            size_start=4.6,
            size_end=0.7,
            spread=math.tau,
            gravity=-24.0,
            drag=1.2,
        )

    def update(self, dt: float, ctx: UltimateContext) -> None:
        super().update(dt, ctx)
        self.caster_pos = ctx.player_pos() + Vector2(0.0, -8.0)
        if self.strike_index < len(self.route_ids) and self.elapsed >= self.next_strike_time:
            target = ctx.find_wolf_by_id(self.route_ids[self.strike_index])
            self.next_strike_time += self.strike_interval
            self.strike_index += 1
            if isinstance(target, dict):
                start_pos = ctx.player_pos()
                pos_raw = target.get("pos")
                if isinstance(pos_raw, Vector2):
                    target_pos = Vector2(pos_raw)
                    away = start_pos - target_pos
                    if away.length_squared() <= 1e-6:
                        away = Vector2(float(-self.facing), 0.0)
                    blink_pos = ctx.nearest_walkable(target_pos + away.normalize() * 54.0)
                    ctx.move_player(blink_pos)
                    self.caster_pos = Vector2(blink_pos.x, blink_pos.y - 8.0)
                    dealt = ctx.damage_wolf(target, self.base_damage * 1.55, target_pos, gore=1.45)
                    if dealt > 0.0:
                        ctx.status_effects.add_effect(ctx.status_effects.wolf_key(target), StatusEffect("stun", 0.55, potency=1.0, color=self.shadow_color))
                    slash_dir = target_pos - blink_pos
                    if slash_dir.length_squared() <= 1e-6:
                        slash_dir = Vector2(float(self.facing), 0.0)
                    self.smoke.burst(
                        start_pos + Vector2(0.0, -8.0),
                        self.shadow_color,
                        self.accent_color,
                        count=12,
                        speed_min=70.0,
                        speed_max=180.0,
                        life_min=0.12,
                        life_max=0.32,
                        size_start=3.8,
                        size_end=0.5,
                        spread=math.tau,
                        gravity=-16.0,
                        drag=1.4,
                    )
                    self.smoke.burst(
                        target_pos + Vector2(0.0, -8.0),
                        (242, 236, 255),
                        self.accent_color,
                        count=14,
                        speed_min=120.0,
                        speed_max=280.0,
                        life_min=0.10,
                        life_max=0.24,
                        size_start=3.6,
                        size_end=0.5,
                        spread=0.65,
                        direction=slash_dir,
                        drag=1.8,
                        shape="spark",
                    )
                    ctx.screen_effects.flash((90, 74, 118), alpha=32, duration=0.08)
        if not self.final_burst_done and self.strike_index >= len(self.route_ids) and self.elapsed >= self.next_strike_time:
            self.final_burst_done = True
            burst_pos = ctx.player_pos() + Vector2(0.0, -8.0)
            hit_any = False
            for wolf in ctx.wolves_in_radius(ctx.player_pos(), 116.0 * self.radius_scale):
                pos_raw = wolf.get("pos")
                if not isinstance(pos_raw, Vector2):
                    continue
                dealt = ctx.damage_wolf(wolf, self.base_damage * 0.9, Vector2(pos_raw), gore=1.0)
                if dealt <= 0.0:
                    continue
                hit_any = True
                ctx.status_effects.add_effect(ctx.status_effects.wolf_key(wolf), StatusEffect("slow", 1.8, potency=0.22, color=self.accent_color))
            self.smoke.burst(
                burst_pos,
                (230, 220, 255),
                self.accent_color,
                count=24,
                speed_min=140.0,
                speed_max=320.0,
                life_min=0.14,
                life_max=0.34,
                size_start=4.4,
                size_end=0.6,
                spread=math.tau,
                gravity=-18.0,
                drag=1.3,
                shape="spark",
            )
            if hit_any:
                ctx.screen_effects.flash((128, 98, 180), alpha=48, duration=0.10)
        if self.final_burst_done and self.elapsed >= self.next_strike_time + 0.18:
            self.finished = True

    def draw(self, surface: pygame.Surface, camera: Vector2) -> None:
        if self.finished:
            super().draw(surface, camera)
            return
        if self.elapsed < self.windup:
            sx = int(self.caster_pos.x - camera.x)
            sy = int(self.caster_pos.y - camera.y)
            ring = max(10, int(14 + 22 * clamp(self.elapsed / max(0.001, self.windup), 0.0, 1.0)))
            pygame.gfxdraw.aacircle(surface, sx, sy, ring, (*self.accent_color, 148))
            pygame.gfxdraw.aacircle(surface, sx, sy, max(6, ring - 8), (*self.shadow_color, 112))
        super().draw(surface, camera)


class RangerStormUltimate(UltimateBase):
    def __init__(self, *args: Any, **kwargs: Any) -> None:
        super().__init__(*args, **kwargs)
        self.center = Vector2(self.target_pos)
        self.radius = 148.0 * self.radius_scale
        self.windup = 0.32
        self.storm_time = 2.3 * self.duration_scale
        self.spawn_interval = max(0.06, 0.12 * self.interval_scale)
        self.spawn_timer = self.windup
        self.arrows: List[Dict[str, object]] = []
        self.emitter = self.add_emitter()

    def _spawn_arrow(self) -> None:
        angle = random.uniform(0.0, math.tau)
        dist = self.radius * math.sqrt(random.random())
        impact = self.center + Vector2(math.cos(angle), math.sin(angle)) * dist
        start = impact + Vector2(random.uniform(-120.0, 120.0), -320.0 - random.uniform(0.0, 160.0))
        self.arrows.append(
            {
                "start": start,
                "end": impact,
                "travel": random.uniform(0.20, 0.34),
                "t": 0.0,
            }
        )

    def update(self, dt: float, ctx: UltimateContext) -> None:
        super().update(dt, ctx)
        if self.elapsed >= self.windup and self.elapsed <= self.windup + self.storm_time:
            self.spawn_timer -= dt
            while self.spawn_timer <= 0.0:
                self._spawn_arrow()
                if random.random() < 0.28 + max(0.0, float(self.mods.get("projectile_count_bonus", 0.0))) * 0.08:
                    self._spawn_arrow()
                self.spawn_timer += self.spawn_interval
        keep_arrows: List[Dict[str, object]] = []
        for arrow in self.arrows:
            arrow["t"] = float(arrow.get("t", 0.0)) + dt / max(0.05, float(arrow.get("travel", 0.25)))
            if float(arrow["t"]) >= 1.0:
                impact = arrow.get("end")
                if isinstance(impact, Vector2):
                    hit_any = False
                    for wolf in ctx.wolves_in_radius(impact, 60.0 * self.radius_scale):
                        pos_raw = wolf.get("pos")
                        if not isinstance(pos_raw, Vector2):
                            continue
                        dealt = ctx.damage_wolf(wolf, self.base_damage * 1.08, Vector2(pos_raw), gore=0.9)
                        if dealt <= 0.0:
                            continue
                        hit_any = True
                        ctx.status_effects.add_effect(
                            ctx.status_effects.wolf_key(wolf),
                            StatusEffect("slow", 2.2, potency=0.34, color=self.accent_color),
                        )
                    self.emitter.burst(
                        impact,
                        self.core_color,
                        self.accent_color,
                        count=16,
                        speed_min=90.0,
                        speed_max=220.0,
                        life_min=0.10,
                        life_max=0.28,
                        size_start=3.6,
                        size_end=0.5,
                        spread=math.tau,
                        gravity=16.0,
                        drag=1.6,
                        shape="spark",
                    )
                    self.emitter.burst(
                        impact,
                        (246, 236, 198),
                        (164, 132, 68),
                        count=10,
                        speed_min=60.0,
                        speed_max=140.0,
                        life_min=0.14,
                        life_max=0.32,
                        size_start=3.2,
                        size_end=0.5,
                        spread=math.tau,
                        gravity=-14.0,
                        drag=1.2,
                    )
                    if hit_any:
                        ctx.screen_effects.flash((196, 174, 110), alpha=28, duration=0.08)
                continue
            keep_arrows.append(arrow)
        self.arrows = keep_arrows
        if self.elapsed <= self.windup + self.storm_time and random.random() < 0.35:
            self.emitter.burst(
                self.center + Vector2(random.uniform(-self.radius * 0.75, self.radius * 0.75), random.uniform(-self.radius * 0.3, self.radius * 0.3)),
                self.accent_color,
                self.shadow_color,
                count=2,
                speed_min=12.0,
                speed_max=48.0,
                life_min=0.12,
                life_max=0.28,
                size_start=2.6,
                size_end=0.4,
                spread=math.tau,
                gravity=-10.0,
                drag=1.1,
            )
        if self.elapsed > self.windup + self.storm_time and not self.arrows:
            self.finished = True

    def draw(self, surface: pygame.Surface, camera: Vector2) -> None:
        if self.finished:
            super().draw(surface, camera)
            return
        overlay = pygame.Surface((SCREEN_WIDTH, SCREEN_HEIGHT), pygame.SRCALPHA)
        cx = int(self.center.x - camera.x)
        cy = int(self.center.y - camera.y)
        if self.elapsed < self.windup + self.storm_time:
            pulse = 0.76 + 0.24 * math.sin(pygame.time.get_ticks() * 0.012)
            radius = int(self.radius * pulse)
            pygame.draw.circle(overlay, (*self.accent_color, 92), (cx, cy), radius, 2)
            pygame.draw.circle(overlay, (*self.core_color, 44), (cx, cy), max(14, int(radius * 0.45)), 1)
        for arrow in self.arrows:
            start = arrow.get("start")
            end = arrow.get("end")
            if not isinstance(start, Vector2) or not isinstance(end, Vector2):
                continue
            t = clamp(float(arrow.get("t", 0.0)), 0.0, 1.0)
            pos = start.lerp(end, t)
            sx = int(pos.x - camera.x)
            sy = int(pos.y - camera.y)
            tail = pos.lerp(start, 0.18)
            tx = int(tail.x - camera.x)
            ty = int(tail.y - camera.y)
            pygame.draw.line(overlay, (*self.core_color, 196), (sx, sy), (tx, ty), 2)
            pygame.gfxdraw.filled_circle(overlay, sx, sy, 3, (*self.accent_color, 216))
        surface.blit(overlay, (0, 0))
        super().draw(surface, camera)


class NecromancerSummonUltimate(UltimateBase):
    def __init__(self, *args: Any, **kwargs: Any) -> None:
        super().__init__(*args, **kwargs)
        self.rise_time = 0.38
        self.active_time = 5.8 * self.duration_scale
        self.pos = Vector2(self.target_pos)
        self.target_id: Optional[int] = None
        self.attack_cd = 0.0
        self.emitter = self.add_emitter()

    def start(self, ctx: UltimateContext) -> None:
        self.pos = ctx.nearest_walkable(self.target_pos, radius=24.0)
        self.emitter.burst(
            self.pos,
            self.accent_color,
            self.shadow_color,
            count=20,
            speed_min=70.0,
            speed_max=180.0,
            life_min=0.18,
            life_max=0.42,
            size_start=4.2,
            size_end=0.6,
            spread=math.tau,
            gravity=-24.0,
            drag=1.2,
        )

    def update(self, dt: float, ctx: UltimateContext) -> None:
        super().update(dt, ctx)
        if self.elapsed < self.rise_time:
            if random.random() < 0.6:
                self.emitter.burst(
                    self.pos + Vector2(random.uniform(-22.0, 22.0), random.uniform(-10.0, 10.0)),
                    self.accent_color,
                    (235, 228, 212),
                    count=2,
                    speed_min=18.0,
                    speed_max=60.0,
                    life_min=0.14,
                    life_max=0.30,
                    size_start=2.6,
                    size_end=0.4,
                    spread=math.tau,
                    gravity=-14.0,
                    drag=1.0,
                )
            return
        self.attack_cd = max(0.0, self.attack_cd - dt)
        target = ctx.find_wolf_by_id(self.target_id) if isinstance(self.target_id, int) else None
        if not isinstance(target, dict):
            target = ctx.nearest_wolf(self.pos, max_dist=520.0)
            self.target_id = id(target) if isinstance(target, dict) else None
        hover_target = ctx.player_pos() + Vector2(float(ctx.player_facing()) * 54.0, -18.0)
        if isinstance(target, dict):
            pos_raw = target.get("pos")
            if isinstance(pos_raw, Vector2):
                desired = Vector2(pos_raw) + Vector2(0.0, -20.0)
                travel = desired - self.pos
                if travel.length_squared() > 1e-6:
                    self.pos += travel.normalize() * min(travel.length(), 280.0 * dt)
                if self.pos.distance_to(desired) <= 62.0 and self.attack_cd <= 0.0:
                    self.attack_cd = max(0.32, 0.72 * self.interval_scale)
                    hit_any = False
                    for wolf in ctx.wolves_in_radius(Vector2(pos_raw), 94.0 * self.radius_scale):
                        wolf_pos_raw = wolf.get("pos")
                        if not isinstance(wolf_pos_raw, Vector2):
                            continue
                        dealt = ctx.damage_wolf(wolf, self.base_damage * 1.3, Vector2(wolf_pos_raw), gore=1.2)
                        if dealt <= 0.0:
                            continue
                        hit_any = True
                        ctx.status_effects.add_effect(ctx.status_effects.wolf_key(wolf), StatusEffect("freeze", 0.50, potency=1.0, color=self.accent_color))
                    self.emitter.burst(
                        Vector2(pos_raw),
                        self.accent_color,
                        (236, 228, 246),
                        count=18,
                        speed_min=90.0,
                        speed_max=220.0,
                        life_min=0.14,
                        life_max=0.34,
                        size_start=3.8,
                        size_end=0.5,
                        spread=math.tau,
                        gravity=-18.0,
                        drag=1.2,
                        shape="spark",
                    )
                    if hit_any:
                        ctx.screen_effects.flash((118, 94, 158), alpha=30, duration=0.08)
        else:
            drift = hover_target - self.pos
            if drift.length_squared() > 1e-6:
                self.pos += drift.normalize() * min(drift.length(), 180.0 * dt)
        if random.random() < 0.5:
            self.emitter.burst(
                self.pos + Vector2(random.uniform(-16.0, 16.0), random.uniform(-18.0, 14.0)),
                self.accent_color,
                self.shadow_color,
                count=2,
                speed_min=18.0,
                speed_max=54.0,
                life_min=0.12,
                life_max=0.26,
                size_start=2.4,
                size_end=0.4,
                spread=math.tau,
                gravity=-10.0,
                drag=1.1,
            )
        if self.elapsed >= self.rise_time + self.active_time:
            self.finished = True

    def draw(self, surface: pygame.Surface, camera: Vector2) -> None:
        if self.finished:
            super().draw(surface, camera)
            return
        sx = int(self.pos.x - camera.x)
        sy = int(self.pos.y - camera.y)
        phase = pygame.time.get_ticks() * 0.008
        body = pygame.Surface((90, 110), pygame.SRCALPHA)
        pygame.draw.ellipse(body, (*self.shadow_color, 84), pygame.Rect(16, 12, 58, 82))
        pygame.draw.ellipse(body, (*self.accent_color, 112), pygame.Rect(24, 20, 42, 66), 2)
        for idx in range(4):
            yy = 32 + idx * 12
            pygame.draw.line(body, (*self.core_color, 128), (30, yy), (60, yy), 1)
        for idx in range(3):
            ang = phase + idx * (math.tau / 3.0)
            px = 45 + int(math.cos(ang) * 24)
            py = 38 + int(math.sin(ang) * 14)
            pygame.gfxdraw.filled_circle(body, px, py, 3, (*self.accent_color, 156))
        surface.blit(body, (sx - body.get_width() // 2, sy - body.get_height() // 2))
        super().draw(surface, camera)


class WarriorDashUltimate(UltimateBase):
    def __init__(self, *args: Any, **kwargs: Any) -> None:
        super().__init__(*args, **kwargs)
        direction = self.target_pos - self.caster_pos
        if direction.length_squared() <= 1e-5:
            direction = Vector2(float(self.facing), 0.0)
        self.direction = direction.normalize()
        self.windup = 0.18
        self.travel_left = 380.0 * self.radius_scale
        self.dash_speed = 1680.0
        self.shockwave_time = 0.26
        self.in_shockwave = False
        self.hit_ids: Set[int] = set()
        self.wave_hit_ids: Set[int] = set()
        self.shock_origin = Vector2(self.caster_pos)
        self.emitter = self.add_emitter()

    def update(self, dt: float, ctx: UltimateContext) -> None:
        super().update(dt, ctx)
        self.caster_pos = ctx.player_pos()
        if self.elapsed < self.windup:
            if random.random() < 0.7:
                self.emitter.burst(
                    self.caster_pos + Vector2(0.0, -8.0),
                    self.core_color,
                    self.accent_color,
                    count=2,
                    speed_min=24.0,
                    speed_max=84.0,
                    life_min=0.10,
                    life_max=0.26,
                    size_start=3.0,
                    size_end=0.4,
                    spread=0.6,
                    direction=self.direction,
                    gravity=20.0,
                    drag=1.4,
                    shape="spark",
                )
            return
        if not self.in_shockwave:
            start_pos = ctx.player_pos()
            step = min(self.travel_left, self.dash_speed * dt)
            desired = start_pos + self.direction * step
            if not ctx.is_walkable(desired):
                desired = ctx.nearest_walkable(start_pos + self.direction * max(18.0, step * 0.3))
                step = desired.distance_to(start_pos)
            if step > 0.01:
                ctx.move_player(desired)
                self.caster_pos = Vector2(desired)
                self.travel_left = max(0.0, self.travel_left - step)
                self.shock_origin = Vector2(desired)
                for wolf in ctx.living_wolves():
                    wolf_id = id(wolf)
                    if wolf_id in self.hit_ids:
                        continue
                    pos_raw = wolf.get("pos")
                    if not isinstance(pos_raw, Vector2):
                        continue
                    if not circle_hits_segment(Vector2(pos_raw), 54.0, start_pos, desired):
                        continue
                    dealt = ctx.damage_wolf(wolf, self.base_damage * 1.7, Vector2(pos_raw), gore=1.45)
                    if dealt > 0.0:
                        self.hit_ids.add(wolf_id)
                        ctx.status_effects.add_effect(ctx.status_effects.wolf_key(wolf), StatusEffect("stun", 0.65, potency=1.0, color=self.accent_color))
                        ctx.push_wolf(wolf, self.direction, 36.0)
                self.emitter.burst(
                    desired + Vector2(0.0, -10.0),
                    self.core_color,
                    self.accent_color,
                    count=4,
                    speed_min=60.0,
                    speed_max=160.0,
                    life_min=0.10,
                    life_max=0.24,
                    size_start=3.2,
                    size_end=0.5,
                    spread=0.7,
                    direction=self.direction,
                    gravity=26.0,
                    drag=1.6,
                    shape="spark",
                )
            if self.travel_left <= 0.0 or step <= 0.01:
                self.in_shockwave = True
                self.elapsed = self.windup
                ctx.screen_effects.flash((214, 168, 110), alpha=46, duration=0.08)
                self.emitter.burst(
                    self.shock_origin + Vector2(0.0, -6.0),
                    self.accent_color,
                    self.shadow_color,
                    count=18,
                    speed_min=80.0,
                    speed_max=220.0,
                    life_min=0.14,
                    life_max=0.34,
                    size_start=4.2,
                    size_end=0.6,
                    spread=math.tau,
                    gravity=34.0,
                    drag=1.4,
                    shape="spark",
                )
            return
        wave_progress = clamp((self.elapsed - self.windup) / max(0.001, self.shockwave_time), 0.0, 1.0)
        cone_len = 220.0 * wave_progress * self.radius_scale
        for wolf in ctx.living_wolves():
            wolf_id = id(wolf)
            if wolf_id in self.wave_hit_ids:
                continue
            pos_raw = wolf.get("pos")
            if not isinstance(pos_raw, Vector2):
                continue
            rel = Vector2(pos_raw) - self.shock_origin
            dist = rel.length()
            if dist <= 1e-5 or dist > cone_len:
                continue
            if rel.normalize().dot(self.direction) < 0.46:
                continue
            dealt = ctx.damage_wolf(wolf, self.base_damage * 1.15, Vector2(pos_raw), gore=1.1)
            if dealt <= 0.0:
                continue
            self.wave_hit_ids.add(wolf_id)
            ctx.status_effects.add_effect(ctx.status_effects.wolf_key(wolf), StatusEffect("stun", 0.45, potency=1.0, color=self.core_color))
        if self.elapsed >= self.windup + self.shockwave_time:
            self.finished = True

    def draw(self, surface: pygame.Surface, camera: Vector2) -> None:
        if self.finished:
            super().draw(surface, camera)
            return
        overlay = pygame.Surface((SCREEN_WIDTH, SCREEN_HEIGHT), pygame.SRCALPHA)
        if not self.in_shockwave and self.elapsed < self.windup:
            sx = int(self.caster_pos.x - camera.x)
            sy = int(self.caster_pos.y - camera.y - 8.0)
            ex = int(sx + self.direction.x * 110.0)
            ey = int(sy + self.direction.y * 110.0)
            pygame.draw.line(overlay, (*self.accent_color, 110), (sx, sy), (ex, ey), 4)
        if self.in_shockwave:
            progress = clamp((self.elapsed - self.windup) / max(0.001, self.shockwave_time), 0.0, 1.0)
            length = 220.0 * progress * self.radius_scale
            origin = self.shock_origin
            left = rotate_vec(self.direction, -0.88) * length
            right = rotate_vec(self.direction, 0.88) * length
            center = self.direction * length
            pts = [
                (int(origin.x - camera.x), int(origin.y - camera.y)),
                (int(origin.x + left.x - camera.x), int(origin.y + left.y - camera.y)),
                (int(origin.x + center.x - camera.x), int(origin.y + center.y - camera.y)),
                (int(origin.x + right.x - camera.x), int(origin.y + right.y - camera.y)),
            ]
            pygame.draw.polygon(overlay, (*self.accent_color, 72), pts)
            pygame.draw.lines(overlay, (*self.core_color, 166), False, pts[1:], 3)
        surface.blit(overlay, (0, 0))
        super().draw(surface, camera)


class PaladinTransformationUltimate(UltimateBase):
    def __init__(self, *args: Any, **kwargs: Any) -> None:
        super().__init__(*args, **kwargs)
        self.total_time = 5.4 * self.duration_scale
        self.pulse_interval = max(0.20, 0.60 * self.interval_scale)
        self.pulse_timer = 0.06
        self.shield_amount = 40.0 + self.base_damage * 1.9
        self.buff_applied = False
        self.pulse_flash = 0.0
        self.pulse_dir = Vector2(float(self.facing), 0.0)
        self.emitter = self.add_emitter()

    def start(self, ctx: UltimateContext) -> None:
        ctx.screen_effects.flash((244, 224, 170), alpha=72, duration=0.12)

    def update(self, dt: float, ctx: UltimateContext) -> None:
        super().update(dt, ctx)
        self.caster_pos = ctx.player_pos()
        if not self.buff_applied:
            self.buff_applied = True
            ctx.status_effects.add_effect(
                ctx.status_effects.PLAYER_KEY,
                StatusEffect("shield", self.total_time, potency=self.shield_amount, color=self.accent_color),
            )
            ctx.status("Ascendant Aegis shields you in radiant fire.", 1.6)
        self.pulse_timer -= dt
        self.pulse_flash = max(0.0, self.pulse_flash - dt)
        player_pos = ctx.player_pos()
        if random.random() < 0.85:
            self.emitter.burst(
                player_pos + Vector2(random.uniform(-22.0, 22.0), random.uniform(-50.0, -10.0)),
                self.core_color,
                self.accent_color,
                count=2,
                speed_min=16.0,
                speed_max=44.0,
                life_min=0.14,
                life_max=0.34,
                size_start=2.6,
                size_end=0.4,
                spread=math.tau,
                gravity=-22.0,
                drag=1.2,
                shape="diamond",
            )
        if self.pulse_timer <= 0.0:
            self.pulse_timer += self.pulse_interval
            target = ctx.nearest_wolf(player_pos, max_dist=460.0)
            if isinstance(target, dict) and isinstance(target.get("pos"), Vector2):
                aim = Vector2(target["pos"]) - player_pos
                if aim.length_squared() > 1e-6:
                    self.pulse_dir = aim.normalize()
            else:
                self.pulse_dir = Vector2(float(ctx.player_facing()), 0.0)
            hit_any = False
            cone_range = 250.0 * self.radius_scale
            for wolf in ctx.living_wolves():
                pos_raw = wolf.get("pos")
                if not isinstance(pos_raw, Vector2):
                    continue
                rel = Vector2(pos_raw) - player_pos
                dist = rel.length()
                if dist <= 1e-5 or dist > cone_range:
                    continue
                if rel.normalize().dot(self.pulse_dir) < 0.42:
                    continue
                dealt = ctx.damage_wolf(wolf, self.base_damage * 1.05, Vector2(pos_raw), gore=0.95)
                if dealt <= 0.0:
                    continue
                hit_any = True
                ctx.status_effects.add_effect(
                    ctx.status_effects.wolf_key(wolf),
                    StatusEffect("burn", 2.6, potency=max(3.5, self.base_damage * 0.14), tick_interval=0.50, color=self.core_color),
                )
            self.pulse_flash = 0.22
            self.emitter.burst(
                player_pos + self.pulse_dir * 20.0,
                self.core_color,
                self.accent_color,
                count=16,
                speed_min=80.0,
                speed_max=220.0,
                life_min=0.10,
                life_max=0.28,
                size_start=3.4,
                size_end=0.5,
                spread=0.96,
                direction=self.pulse_dir,
                drag=1.5,
                shape="spark",
            )
            if hit_any:
                ctx.screen_effects.flash((234, 216, 138), alpha=36, duration=0.08)
        if self.elapsed >= self.total_time:
            self.finished = True

    def draw(self, surface: pygame.Surface, camera: Vector2) -> None:
        if self.finished:
            super().draw(surface, camera)
            return
        sx = int(self.caster_pos.x - camera.x)
        sy = int(self.caster_pos.y - camera.y)
        overlay = pygame.Surface((SCREEN_WIDTH, SCREEN_HEIGHT), pygame.SRCALPHA)
        halo_r = 34 + int(6 * math.sin(pygame.time.get_ticks() * 0.012))
        pygame.gfxdraw.aacircle(overlay, sx, sy - 16, halo_r, (*self.accent_color, 142))
        pygame.gfxdraw.aacircle(overlay, sx, sy - 16, max(12, halo_r - 10), (*self.core_color, 112))
        if self.pulse_flash > 0.0:
            length = 210.0 * clamp(self.pulse_flash / 0.22, 0.0, 1.0) * self.radius_scale
            left = rotate_vec(self.pulse_dir, -0.92) * length
            right = rotate_vec(self.pulse_dir, 0.92) * length
            center = self.pulse_dir * length
            pts = [
                (sx, sy - 8),
                (sx + int(left.x), sy - 8 + int(left.y)),
                (sx + int(center.x), sy - 8 + int(center.y)),
                (sx + int(right.x), sy - 8 + int(right.y)),
            ]
            pygame.draw.polygon(overlay, (*self.core_color, 74), pts)
            pygame.draw.lines(overlay, (*self.accent_color, 156), False, pts[1:], 3)
        surface.blit(overlay, (0, 0))
        super().draw(surface, camera)


ULTIMATE_CLASS_MAP: Dict[str, Any] = {
    "mage": MageCataclysmUltimate,
    "rogue": RogueTeleportUltimate,
    "ranger": RangerStormUltimate,
    "necromancer": NecromancerSummonUltimate,
    "warrior": WarriorDashUltimate,
    "paladin": PaladinTransformationUltimate,
}


def create_ultimate_for_class(
    class_id: str,
    spell: Dict[str, object],
    caster_pos: Vector2,
    target_pos: Vector2,
    facing: int,
    bonus_power: float,
    spell_mods: Optional[Dict[str, float]] = None,
    class_damage_mult: float = 1.0,
) -> Optional[UltimateBase]:
    ultimate_cls = ULTIMATE_CLASS_MAP.get(str(class_id))
    if ultimate_cls is None:
        return None
    return ultimate_cls(spell, caster_pos, target_pos, facing, bonus_power, spell_mods, class_damage_mult)

def character_selection_screen(
    screen: pygame.Surface,
    clock: pygame.time.Clock,
    saves: List[Dict],
    class_visuals: Dict[str, Dict[str, Union[pygame.Surface, str]]],
    fonts: Dict[str, pygame.font.Font],
) -> Optional[int]:
    """
    Displays character selection.
    Returns:
        index of selected save (0..N)
        -1 for 'Create New'
        None for 'Quit'
    """
    title_font = fonts["title"]
    info_font = fonts["info"]
    node_font = fonts["node"]
    tiny_font = fonts["tiny"]
    
    selected_idx = 0 if saves else -1

    # Ensure OS cursor is visible on this screen — run_session hides it for
    # the custom in-game cursor, and re-entering the menu used to leave the
    # cursor invisible, making character creation effectively unusable.
    pygame.mouse.set_visible(True)

    while True:
        # Reassert cursor visibility every frame — guards against SDL on
        # Windows silently dropping the first set_visible(True) when the
        # window is still receiving initial focus events (fresh launch bug).
        if not pygame.mouse.get_visible():
            pygame.mouse.set_visible(True)
        screen.fill((12, 14, 18))
        draw_vertical_gradient(screen, pygame.Rect(0, 0, SCREEN_WIDTH, SCREEN_HEIGHT), (8, 10, 16), (24, 28, 36))
        
        # Title
        title_s = title_font.render("Select Character", True, (220, 210, 190))
        screen.blit(title_s, (SCREEN_WIDTH // 2 - title_s.get_width() // 2, 40))
        
        # Character List
        list_w = 400
        list_x = 100
        list_y = 120
        
        # "Create New" slot
        create_rect = pygame.Rect(list_x, list_y, list_w, 60)
        hover = create_rect.collidepoint(pygame.mouse.get_pos())
        sel = (selected_idx == -1)
        
        pygame.draw.rect(screen, (40, 50, 40) if sel else ((30, 34, 30) if hover else (20, 22, 24)), create_rect, border_radius=8)
        pygame.draw.rect(screen, (120, 200, 120) if sel else (60, 80, 60), create_rect, 2 if sel else 1, border_radius=8)
        create_s = node_font.render("+ Create New Character", True, (180, 220, 180) if sel else (140, 160, 140))
        screen.blit(create_s, (create_rect.centerx - create_s.get_width() // 2, create_rect.centery - create_s.get_height() // 2))
        
        # Existing saves
        for i, save in enumerate(saves):
            rect = pygame.Rect(list_x, list_y + 80 + i * 70, list_w, 60)
            is_sel = (i == selected_idx)
            is_hover = rect.collidepoint(pygame.mouse.get_pos())
            
            bg = (50, 44, 40) if is_sel else ((36, 32, 34) if is_hover else (26, 24, 26))
            border = (220, 180, 100) if is_sel else (80, 80, 90)
            
            pygame.draw.rect(screen, bg, rect, border_radius=8)
            pygame.draw.rect(screen, border, rect, 2 if is_sel else 1, border_radius=8)
            
            name = str(save.get("player_name", "Unknown"))
            cls_id = normalize_class_id(save.get("class", "rogue"))
            cls = str(CLASS_ARCHETYPES.get(cls_id, {}).get("name", cls_id.title()))
            lvl = int(save.get("player_level", 1))
            
            name_s = node_font.render(name, True, (230, 220, 200) if is_sel else (180, 180, 190))
            meta_s = info_font.render(f"Level {lvl} {cls}", True, (160, 150, 120) if is_sel else (120, 120, 130))
            
            screen.blit(name_s, (rect.left + 20, rect.top + 8))
            screen.blit(meta_s, (rect.left + 20, rect.bottom - 24))

        # Preview Panel (Right side)
        preview_rect = pygame.Rect(SCREEN_WIDTH - 500, 120, 360, 500)
        draw_ornate_panel(screen, preview_rect)
        
        if selected_idx >= 0 and selected_idx < len(saves):
            save = saves[selected_idx]
            cls_id = normalize_class_id(save.get("class", "rogue"))
            visual = resolve_class_visual_entry(class_visuals, cls_id, lvl)
            sprite = visual.get("sprite")
            if isinstance(sprite, pygame.Surface):
                # Scale up for preview
                scale = 3
                w, h = sprite.get_width() * scale, sprite.get_height() * scale
                scaled = pygame.transform.scale(sprite, (w, h))
                screen.blit(scaled, (preview_rect.centerx - w // 2, preview_rect.centery - h // 2 - 40))
            
            p_name = node_font.render(str(save.get("player_name", "Hero")), True, (240, 220, 180))
            cls_name = str(CLASS_ARCHETYPES.get(cls_id, {}).get("name", cls_id.title()))
            p_cls = info_font.render(f"Level {save.get('player_level', 1)} {cls_name}", True, (180, 170, 160))
            p_zone = info_font.render("Raven Hollow", True, (140, 140, 150))
            
            screen.blit(p_name, (preview_rect.centerx - p_name.get_width() // 2, preview_rect.bottom - 120))
            screen.blit(p_cls, (preview_rect.centerx - p_cls.get_width() // 2, preview_rect.bottom - 90))
            screen.blit(p_zone, (preview_rect.centerx - p_zone.get_width() // 2, preview_rect.bottom - 60))
            
            play_btn = pygame.Rect(preview_rect.centerx - 80, preview_rect.bottom + 30, 160, 40)
            phover = play_btn.collidepoint(pygame.mouse.get_pos())
            draw_ui_button(screen, play_btn, hovered=phover, text="Enter World", font=node_font)
            
            delete_btn = pygame.Rect(preview_rect.centerx - 60, play_btn.bottom + 16, 120, 30)
            dhover = delete_btn.collidepoint(pygame.mouse.get_pos())
            pygame.draw.rect(screen, (60, 20, 20) if dhover else (40, 10, 10), delete_btn, border_radius=6)
            pygame.draw.rect(screen, (180, 60, 60) if dhover else (120, 40, 40), delete_btn, 1, border_radius=6)
            del_s = tiny_font.render("Delete", True, (220, 160, 160))
            screen.blit(del_s, (delete_btn.centerx - del_s.get_width() // 2, delete_btn.centery - del_s.get_height() // 2))

        elif selected_idx == -1:
            # New Character Preview
            hint = info_font.render("Create a new hero to begin your journey.", True, (160, 160, 170))
            screen.blit(hint, (preview_rect.centerx - hint.get_width() // 2, preview_rect.centery))
            
            create_btn = pygame.Rect(preview_rect.centerx - 80, preview_rect.bottom + 30, 160, 40)
            chover = create_btn.collidepoint(pygame.mouse.get_pos())
            draw_ui_button(screen, create_btn, hovered=chover, text="Create", font=node_font, color=(120, 220, 120))

        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                return None
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_ESCAPE:
                    return None
                if event.key == pygame.K_RETURN:
                    return selected_idx
            if event.type == pygame.MOUSEBUTTONDOWN:
                if event.button == 1:
                    # Check list clicks
                    if create_rect.collidepoint(event.pos):
                        selected_idx = -1
                    for i in range(len(saves)):
                        r = pygame.Rect(list_x, list_y + 80 + i * 70, list_w, 60)
                        if r.collidepoint(event.pos):
                            selected_idx = i
                    
                    # Check button clicks
                    if selected_idx >= 0 and selected_idx < len(saves):
                        play_btn = pygame.Rect(preview_rect.centerx - 80, preview_rect.bottom + 30, 160, 40)
                        if play_btn.collidepoint(event.pos):
                            return selected_idx
                        delete_btn = pygame.Rect(preview_rect.centerx - 60, play_btn.bottom + 16, 120, 30)
                        if delete_btn.collidepoint(event.pos):
                            saves.pop(selected_idx)
                            save_all_saves(saves)
                            if selected_idx >= len(saves):
                                selected_idx = max(-1, len(saves) - 1)
                            if not saves:
                                selected_idx = -1
                    elif selected_idx == -1:
                        create_btn = pygame.Rect(preview_rect.centerx - 80, preview_rect.bottom + 30, 160, 40)
                        if create_btn.collidepoint(event.pos):
                            return selected_idx

        pygame.display.flip()
        clock.tick_busy_loop(FPS)


INTRO_CINEMATIC_DEFAULT_FINAL_CAPTION = (
    "You came to Sangeroasa for your own reasons. Gold, truth, vengeance, faith — the valley does not care."
)

INTRO_CINEMATIC_CLASS_FINAL_CAPTIONS: Dict[str, str] = {
    "mage": "Ley-lines bleed beneath this valley. The wolves carry traces of what you came to study.",
    "ranger": "Somewhere in these woods, your trail ends where your sibling's vanished.",
    "rogue": "A bounty brought you here. Someone in Sangeroasa still owes a debt in blood.",
    "necromancer": "The veil is thin in this valley. Wolf-spirits cross it, and you came to master what slips through.",
    "warrior": "You came for monsters, not mercy. Sangeroasa has plenty of both.",
    "paladin": "Your order sent an envoy who never returned. You came to finish what faith began.",
}


def play_intro_cinematic(
    screen: pygame.Surface,
    clock: pygame.time.Clock,
    fonts: Dict[str, pygame.font.Font],
    town_surface: pygame.Surface,
    wilderness_surface: pygame.Surface,
    player_name: str,
    player_class: str,
    start_level: str,
    start_pos: Vector2,
    audio: Optional[GameAudio] = None,
) -> str:
    title_font = fonts["title"]
    body_font = fonts["dialog_text"]
    tiny_font = fonts["tiny"]

    def resolve_final_caption(raw_class: object) -> str:
        key = str(raw_class).strip().lower()
        if key in INTRO_CINEMATIC_CLASS_FINAL_CAPTIONS:
            return INTRO_CINEMATIC_CLASS_FINAL_CAPTIONS[key]
        for class_id, class_data in CLASS_ARCHETYPES.items():
            class_name = str(class_data.get("name", "")).strip().lower()
            if key and key == class_name:
                return INTRO_CINEMATIC_CLASS_FINAL_CAPTIONS.get(class_id, INTRO_CINEMATIC_DEFAULT_FINAL_CAPTION)
        return INTRO_CINEMATIC_DEFAULT_FINAL_CAPTION

    start_level_norm = "wilderness" if str(start_level).strip().lower() == "wilderness" else "town"
    if isinstance(start_pos, Vector2):
        entry_pos = Vector2(start_pos)
    else:
        entry_pos = Vector2(WORLD_WIDTH * 0.5, HORIZON_Y + 760)

    display_name = str(player_name).strip() or "Traveler"
    final_caption = resolve_final_caption(player_class)

    # Per-shot script and timing are centralized for easy tuning.
    shots: List[Dict[str, object]] = [
        {
            "world": "town",
            "focus": Vector2(WORLD_WIDTH * 0.5, HORIZON_Y + 260),
            "drift": Vector2(240.0, 20.0),
            "duration": 3.6,
            "headline": "Sangeroasa",
            "caption": "Old stone. Dim lanterns. A cathedral built over older bones. In Sangeroasa, every alley keeps a secret.",
        },
        {
            "world": "town",
            "focus": Vector2(WORLD_WIDTH * 0.5 - 260.0, HORIZON_Y + 770),
            "drift": Vector2(320.0, -26.0),
            "duration": 3.4,
            "headline": "Raven Hollow",
            "caption": "The gate district never truly sleeps. Merchants, guards, and refugees all pass through — if the dark lets them.",
        },
        {
            "world": "wilderness",
            "focus": Vector2(WILDERNESS_WIDTH * 0.5, HORIZON_Y + 980),
            "drift": Vector2(-420.0, 42.0),
            "duration": 3.8,
            "headline": "The Wilderness",
            "caption": "Beyond the walls, wolf packs rule the trails. Pelts, bones, and venom buy survival — if you return alive.",
        },
        {
            "world": start_level_norm,
            "focus": Vector2(entry_pos),
            "drift": Vector2(180.0, 0.0),
            "duration": 3.8,
            "headline": display_name,
            "caption": final_caption,
        },
    ]

    vignette = pygame.Surface((SCREEN_WIDTH, SCREEN_HEIGHT), pygame.SRCALPHA)
    for i in range(0, 66):
        alpha = int(1 + (i / 65.0) * 4.0)
        rect = pygame.Rect(i, i, SCREEN_WIDTH - i * 2, SCREEN_HEIGHT - i * 2)
        if rect.width > 0 and rect.height > 0:
            pygame.draw.rect(vignette, (0, 0, 0, alpha), rect, width=2, border_radius=26)

    shot_idx = 0
    shot_t = 0.0
    total_t = 0.0
    fade_in_s = 1.05
    current_music_track = ""

    while shot_idx < len(shots):
        clock.tick_busy_loop(FPS)
        dt = FRAME_DT
        total_t += dt
        shot_t += dt

        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                return "QUIT"
            if event.type == pygame.KEYDOWN and event.key in (pygame.K_ESCAPE, pygame.K_RETURN, pygame.K_SPACE):
                return "DONE"
            if event.type == pygame.MOUSEBUTTONDOWN and event.button in (1, 3):
                return "DONE"

        shot = shots[shot_idx]
        duration = max(0.4, float(shot.get("duration", 3.5)))
        if shot_t >= duration:
            shot_t -= duration
            shot_idx += 1
            continue

        world_name = str(shot.get("world", "town")).strip().lower()
        if world_name == "wilderness":
            level_surface = wilderness_surface if isinstance(wilderness_surface, pygame.Surface) else None
            world_w = WILDERNESS_WIDTH
            world_h = WILDERNESS_HEIGHT
            target_track = "wilderness"
        else:
            level_surface = town_surface if isinstance(town_surface, pygame.Surface) else None
            world_w = WORLD_WIDTH
            world_h = WORLD_HEIGHT
            target_track = "town"

        if isinstance(audio, GameAudio) and current_music_track != target_track:
            # TODO: add dedicated one-shot bell/wind cinematic stingers when unique ambience assets are available.
            audio.ensure_level_theme(target_track, force=True)
            current_music_track = target_track

        focus_raw = shot.get("focus")
        focus = Vector2(focus_raw) if isinstance(focus_raw, Vector2) else Vector2(world_w * 0.5, world_h * 0.5)
        drift_raw = shot.get("drift")
        drift = Vector2(drift_raw) if isinstance(drift_raw, Vector2) else Vector2(0, 0)
        t = clamp(shot_t / duration, 0.0, 1.0)
        ease = 0.5 - 0.5 * math.cos(math.pi * t)
        cam_focus = (focus - drift * 0.5).lerp(focus + drift * 0.5, ease)

        cam_x = clamp(cam_focus.x - SCREEN_WIDTH * 0.5, 0, max(0, world_w - SCREEN_WIDTH))
        cam_y = clamp(cam_focus.y - SCREEN_HEIGHT * 0.56, 0, max(0, world_h - SCREEN_HEIGHT))

        if isinstance(level_surface, pygame.Surface):
            screen.blit(level_surface, (-int(cam_x), -int(cam_y)))
        else:
            draw_vertical_gradient(screen, pygame.Rect(0, 0, SCREEN_WIDTH, SCREEN_HEIGHT), (8, 10, 16), (22, 26, 36))

        tint = pygame.Surface((SCREEN_WIDTH, SCREEN_HEIGHT), pygame.SRCALPHA)
        tint.fill((8, 10, 16, 118))
        screen.blit(tint, (0, 0))
        screen.blit(vignette, (0, 0))

        letterbox_t = clamp(total_t / 0.65, 0.0, 1.0)
        bar_h = int(78 * letterbox_t)
        if bar_h > 0:
            pygame.draw.rect(screen, (0, 0, 0), pygame.Rect(0, 0, SCREEN_WIDTH, bar_h))
            pygame.draw.rect(screen, (0, 0, 0), pygame.Rect(0, SCREEN_HEIGHT - bar_h, SCREEN_WIDTH, bar_h))

        edge_fade_s = 0.9
        shot_fade = min(1.0, shot_t / edge_fade_s, (duration - shot_t) / edge_fade_s)
        shot_fade = clamp(shot_fade, 0.0, 1.0)

        panel = pygame.Rect(86, SCREEN_HEIGHT - 212, SCREEN_WIDTH - 172, 134)
        panel_surface = pygame.Surface((panel.width, panel.height), pygame.SRCALPHA)
        pygame.draw.rect(panel_surface, (6, 8, 12, int(196 * shot_fade)), panel_surface.get_rect(), border_radius=12)
        pygame.draw.rect(panel_surface, (176, 146, 102, int(220 * shot_fade)), panel_surface.get_rect(), width=1, border_radius=12)
        screen.blit(panel_surface, panel.topleft)

        headline = str(shot.get("headline", ""))
        caption = str(shot.get("caption", ""))
        txt_alpha = int(255 * shot_fade)

        title_s = title_font.render(headline, True, (238, 220, 188))
        title_s.set_alpha(txt_alpha)
        screen.blit(title_s, (panel.left + 22, panel.top + 10))

        lines = wrap_text_lines(body_font, caption, panel.width - 44, max_lines=3)
        line_y = panel.top + 64
        for line in lines:
            line_s = body_font.render(line, True, (214, 216, 224))
            line_s.set_alpha(txt_alpha)
            screen.blit(line_s, (panel.left + 22, line_y))
            line_y += line_s.get_height() + 4

        hint_s = tiny_font.render("Esc / Space / Enter / Click to skip", True, (164, 172, 188))
        hint_s.set_alpha(int(220 * shot_fade))
        screen.blit(hint_s, (SCREEN_WIDTH - hint_s.get_width() - 16, SCREEN_HEIGHT - 28))

        if total_t < fade_in_s:
            fade_in = pygame.Surface((SCREEN_WIDTH, SCREEN_HEIGHT), pygame.SRCALPHA)
            fade_in.fill((0, 0, 0, int(255 * (1.0 - total_t / fade_in_s))))
            screen.blit(fade_in, (0, 0))

        transition_alpha = int(255 * (1.0 - shot_fade))
        if transition_alpha > 0:
            fade_between = pygame.Surface((SCREEN_WIDTH, SCREEN_HEIGHT), pygame.SRCALPHA)
            fade_between.fill((0, 0, 0, transition_alpha))
            screen.blit(fade_between, (0, 0))

        pygame.display.flip()

    return "DONE"


def run_session(
    screen: pygame.Surface,
    clock: pygame.time.Clock,
    audio: GameAudio,
    fonts: Dict[str, pygame.font.Font],
    assets: Dict[str, object],
    character_data: Dict,
    save_callback: object, # Callable
) -> str:
    """
    Runs the main game loop for a specific character.
    Returns "MENU" to go back to character selection, or "QUIT".
    """
    # Unpack fonts
    font = fonts["main"]
    ui_font = fonts["ui"]
    tiny_font = fonts["tiny"]
    dialog_name_font = fonts["dialog_name"]
    dialog_text_font = fonts["dialog_text"]
    skill_title_font = fonts["skill_title"]
    skill_node_font = fonts["node"]
    skill_info_font = fonts["info"]
    npc_name_font = fonts["npc_name"]

    # Unpack assets
    rogue_choices = assets["rogue_choices"]
    class_visuals = assets["class_visuals"]
    town_surface = assets["town_surface"]
    town_obstacles = assets["town_obstacles"]
    town_canals = assets["town_canals"]
    town_house_overlays = assets.get("town_house_overlays", [])
    town_foliage_anim: list = assets.get("town_foliage_anim", [])
    wilderness_surface = assets["wilderness_surface"]
    wilderness_obstacles = assets["wilderness_obstacles"]
    wilderness_spawn_points = assets["wilderness_spawn_points"]
    ice_surface = assets.get("ice_surface")
    ice_obstacles: List[pygame.Rect] = list(assets.get("ice_obstacles", []))
    ice_spawn_points: List[Vector2] = list(assets.get("ice_spawn_points", []))
    ice_predators: List[Dict[str, object]] = list(assets.get("ice_predators", []))
    ice_passives: List[Dict[str, object]] = list(assets.get("ice_passives", []))
    town_walk_bounds = assets["town_walk_bounds"]
    wilderness_walk_bounds = assets["wilderness_walk_bounds"]
    ice_walk_bounds: pygame.Rect = assets.get("ice_walk_bounds", pygame.Rect(70, HORIZON_Y + 92, ICE_WIDTH - 140, ICE_HEIGHT - (HORIZON_Y + 172)))
    spell_icons = assets["spell_icons"]
    external_item_library = assets["external_item_library"]
    predator_archetypes = assets["predator_archetypes"]
    prey_archetypes = assets["prey_archetypes"]
    vendor_archetypes = assets["vendor_archetypes"]

    town_road_rects: list = assets.get("town_road_rects", [])
    town_farm_pens: list = assets.get("town_farm_pens", [])
    fire_frames = assets.get("fire_frames", [])
    lpc_wolf_frames = assets.get("lpc_wolf_frames")
    town_chimney_tops: List[Tuple[int, int]] = list(assets.get("town_chimney_tops", []))
    level_decor_assets = assets.get("level_decor_assets")
    if not isinstance(level_decor_assets, dict):
        level_decor_assets = load_level_decor_assets()
        assets["level_decor_assets"] = level_decor_assets
    level_decor_layout = assets.get("level_decor_layout")
    if not isinstance(level_decor_layout, dict):
        level_decor_layout = load_level_decor_layout()
        assets["level_decor_layout"] = level_decor_layout

    # Load character data
    selected_class = normalize_class_id(character_data.get("class", "rogue"))
    character_data["class"] = selected_class
    player_name = str(character_data.get("player_name", "Hero"))
    
    active_class = CLASS_ARCHETYPES[selected_class]
    active_spellbook = class_spellbook(selected_class)
    full_class_spellbook = list(CLASS_ARCHETYPES[selected_class].get("spellbook", []))
    active_skill_tree = class_skill_tree(selected_class)
    active_stats = class_combat_stats(selected_class)
    active_passive = class_passive_data(selected_class)
    passive_effects = class_passive_effects(selected_class)
    passive_name = str(active_passive.get("name", "Class Passive"))
    passive_damage_mult = max(0.1, float(passive_effects.get("damage_mult", 1.0)))
    passive_mana_regen_mult = max(0.1, float(passive_effects.get("mana_regen_mult", 1.0)))
    passive_mana_cost_mult = max(0.1, float(passive_effects.get("mana_cost_mult", 1.0)))
    passive_spell_cooldown_mult = max(0.1, float(passive_effects.get("spell_cooldown_mult", 1.0)))
    passive_basic_cooldown_mult = max(0.1, float(passive_effects.get("basic_cooldown_mult", 1.0)))
    passive_move_speed_mult = max(0.1, float(passive_effects.get("move_speed_mult", 1.0)))
    passive_incoming_damage_mult = max(0.1, float(passive_effects.get("incoming_damage_mult", 1.0)))

    selected_entry: Dict[str, object] = {}
    player_sprite = rogue_choices[0].get("sprite")
    player_sprite_left = rogue_choices[0].get("sprite_left")
    player_anim_frames: Optional[Dict[str, Dict[str, List[pygame.Surface]]]] = None
    player_anim_fps: Dict[str, float] = {}
    player_anim_durations: Dict[str, float] = {}
    
    gothic_cursor_surface, gothic_cursor_hotspot = build_gothic_cursor()
    pouch_cursor_surface, pouch_cursor_hotspot = build_pouch_cursor()
    vendor_shop_icon = build_vendor_shop_icon()
    # Build red X delete cursor
    _del_cur_sz = 28
    delete_cursor_surface = pygame.Surface((_del_cur_sz, _del_cur_sz), pygame.SRCALPHA)
    _dc_c = _del_cur_sz // 2
    pygame.draw.circle(delete_cursor_surface, (180, 30, 30, 180), (_dc_c, _dc_c), 12, 2)
    pygame.draw.line(delete_cursor_surface, (220, 40, 40, 230), (_dc_c - 7, _dc_c - 7), (_dc_c + 7, _dc_c + 7), 3)
    pygame.draw.line(delete_cursor_surface, (220, 40, 40, 230), (_dc_c + 7, _dc_c - 7), (_dc_c - 7, _dc_c + 7), 3)
    delete_cursor_hotspot = (_dc_c, _dc_c)
    pygame.mouse.set_visible(False)

    day_night = DayNightCycle()
    status_effects = StatusEffectSystem()
    screen_effects = ScreenEffectController()
    level_up_vfx = LevelUpVFX()

    external_by_rarity: Dict[str, List[Dict[str, object]]] = {
        "common": [],
        "rare": [],
        "epic": [],
        "legendary": [],
    }
    for ext_item in external_item_library:
        rarity = item_rarity(ext_item)
        if rarity in external_by_rarity:
            external_by_rarity[rarity].append(ext_item)

    cooldowns = {str(spell["id"]): 0.0 for spell in active_spellbook}
    spell_global_cooldown = 0.0
    mana_regen_lock_timer = 0.0
    spell_effects: List[Dict[str, object]] = []
    summoned_skeletons: List[Dict[str, object]] = []
    active_ultimates: List[UltimateBase] = []
    damage_numbers: List[Dict[str, object]] = []
    selected_spell_idx = 0
    spell_slot_keybinds: List[int] = [
        pygame.K_q, pygame.K_w, pygame.K_e, pygame.K_r, pygame.K_t,
        pygame.K_1, pygame.K_2, pygame.K_3,
    ]
    keybind_editing_slot: int = -1   # -1 = not editing; 0-7 = slot being rebound
    _spell_bar_slot_rects: List[pygame.Rect] = []  # updated each frame by draw_spell_bar

    # Load progress from character_data
    unlocked_skills: Set[str] = set(str(s) for s in character_data.get("unlocked_skills", []))
    if not unlocked_skills:
        unlocked_skills = set(str(node) for node in active_class.get("starter_skills", []))
        
    skill_points = int(character_data.get("skill_points", 4))
    skill_hover: Optional[str] = None
    skill_node_rects: Dict[str, pygame.Rect] = {}

    wolves_slain = int(character_data.get("wolves_slain", 0))
    player_level = max(1, int(character_data.get("player_level", 1)))
    player_xp = float(character_data.get("player_xp", 0.0))
    player_xp_next = float(xp_required_for_level(player_level))
    wolf_respawn_timer = 0.0
    passive_respawn_timer = 0.0
    passive_target_count = 220
    player_anim_timer = 0.0
    player_gold = int(character_data.get("gold", 0))
    damage_boost_timer = 0.0   # seconds remaining for Blacksmith buff
    shop_open: Optional[str] = None  # role of vendor whose shop is open

    # Level-up perk selection
    perk_choice_pending: bool = False
    perk_choices: List[Dict[str, object]] = []
    perk_hover_idx: int = -1

    # All possible perks pool
    ALL_PERKS: List[Dict[str, object]] = [
        {"id": "hp",      "name": "Vitality",       "desc": "Max HP +25",         "col": (200, 80, 80)},
        {"id": "mana",    "name": "Arcane Flow",     "desc": "Max Mana +25",       "col": (80, 130, 220)},
        {"id": "regen",   "name": "Mana Spring",     "desc": "Mana Regen +2/s",    "col": (100, 180, 240)},
        {"id": "speed",   "name": "Swift Feet",      "desc": "Move Speed +8%",     "col": (120, 220, 140)},
        {"id": "dmg",     "name": "Combat Edge",     "desc": "Spell Power +10%",   "col": (240, 150, 60)},
        {"id": "hp_regen","name": "Iron Blood",      "desc": "Regen 2 HP/s passively", "col": (220, 80, 100)},
        {"id": "sp",      "name": "Insight",         "desc": "+2 Skill Points",    "col": (200, 160, 240)},
        {"id": "gold",    "name": "Merchant's Eye",  "desc": "+30 Gold",           "col": (220, 200, 80)},
    ]

    # Fishing system state
    fishing_active: bool = False
    fishing_timer: float = 0.0        # countdown for catch window
    fishing_bar_pos: float = 0.5      # 0..1 position of moving target on bar
    fishing_bar_vel: float = 0.8      # speed of target movement
    fishing_catch_zone: float = 0.0   # left edge of catch zone 0..1
    fishing_result: str = ""          # "success" | "fail" | ""
    fishing_result_timer: float = 0.0
    passive_hp_regen: float = 0.0     # bonus from "iron blood" perk (HP/s)

    # Must be defined before refresh_player_visuals (captured as free variable)
    equipped_items: Dict[str, Dict[str, object]] = {
        k: clone_item_data(v) for k, v in character_data.get("equipped_items", {}).items()
    }

    base_player_sprite: Optional[pygame.Surface] = None
    base_player_sprite_left: Optional[pygame.Surface] = None
    base_player_anim_frames: Optional[Dict[str, Dict[str, List[pygame.Surface]]]] = None
    player_equip_tint: Optional[pygame.Surface] = None
    player_equip_tint_left: Optional[pygame.Surface] = None

    def refresh_player_visuals() -> None:
        nonlocal selected_entry, player_sprite, player_sprite_left, player_anim_frames, player_anim_fps, player_anim_durations, base_player_sprite, base_player_sprite_left, base_player_anim_frames, player_equip_tint, player_equip_tint_left
        selected_entry = resolve_class_visual_entry(class_visuals, selected_class, player_level, rogue_choices[0])

        sprite_candidate = selected_entry.get("sprite")
        sprite_left_candidate = selected_entry.get("sprite_left")
        fallback_entry = rogue_choices[0]
        fallback_sprite = fallback_entry.get("sprite")
        fallback_sprite_left = fallback_entry.get("sprite_left")

        _base_right = sprite_candidate if isinstance(sprite_candidate, pygame.Surface) else fallback_sprite
        _base_left  = sprite_left_candidate if isinstance(sprite_left_candidate, pygame.Surface) else fallback_sprite_left

        # Store clean COPIES of base sprites so originals are never corrupted
        base_player_sprite       = _base_right.copy() if isinstance(_base_right, pygame.Surface) else _base_right
        base_player_sprite_left  = _base_left.copy() if isinstance(_base_left, pygame.Surface) else _base_left

        # Clear stale sprite hue caches (Python reuses object ids)
        _SPRITE_HUE_CACHE.clear()
        _CLOTH_HUE_CACHE.clear()

        # Apply equipment chromakey on the right-facing sprite, then flip for left.
        _cls_color = CLASS_PALETTES.get(selected_class, CLASS_PALETTES.get("default", {})).get("primary", (160, 160, 180))
        player_sprite       = build_equipped_sprite(base_player_sprite, equipped_items, _cls_color)
        player_sprite_left  = pygame.transform.flip(player_sprite, True, False)

        # Tint overlays disabled — chromakey is baked into the sprite now.
        player_equip_tint      = None
        player_equip_tint_left = None

        frames_candidate = selected_entry.get("anim_frames")
        # Deep-copy base frames so re-equipping always starts from clean originals
        if isinstance(frames_candidate, dict):
            base_player_anim_frames = _deep_copy_anim_frames(frames_candidate)
        else:
            base_player_anim_frames = None

        # Apply equipment recoloring to every animation frame
        if isinstance(base_player_anim_frames, dict):
            player_anim_frames = build_equipped_anim_frames(base_player_anim_frames, equipped_items, _cls_color)
        else:
            player_anim_frames = None

        fps_candidate = selected_entry.get("anim_fps")
        player_anim_fps = dict(fps_candidate) if isinstance(fps_candidate, dict) else {}

        durations_candidate = selected_entry.get("anim_durations")
        player_anim_durations = dict(durations_candidate) if isinstance(durations_candidate, dict) else {}

    def refresh_palette_swap() -> None:
        """Re-run only the palette-swap step (fast path: no anim reload)."""
        nonlocal player_sprite, player_sprite_left, player_anim_frames, player_equip_tint, player_equip_tint_left
        _SPRITE_HUE_CACHE.clear()
        _CLOTH_HUE_CACHE.clear()
        _cls_color = CLASS_PALETTES.get(selected_class, CLASS_PALETTES.get("default", {})).get("primary", (160, 160, 180))
        if isinstance(base_player_sprite, pygame.Surface):
            player_sprite      = build_equipped_sprite(base_player_sprite,      equipped_items, _cls_color)
            player_sprite_left = build_equipped_sprite(base_player_sprite_left, equipped_items, _cls_color)
            player_equip_tint      = None
            player_equip_tint_left = None
        # Recolor animation frames from clean base copies
        if isinstance(base_player_anim_frames, dict):
            player_anim_frames = build_equipped_anim_frames(base_player_anim_frames, equipped_items, _cls_color)

    refresh_player_visuals()

    # ── Crafting & Quest state ─────────────────────────────────────────────────
    materials: Dict[str, int] = {str(k): int(v) for k, v in character_data.get("materials", {}).items()}
    item_inventory: List[Optional[Dict]] = [None] * HOTBAR_SLOT_COUNT  # fixed 4-slot potion bar
    backpack_inventory: List[Dict] = []       # overflow consumables
    
    # Load inventories
    for i, d in enumerate(character_data.get("item_inventory", [])):
        if i < HOTBAR_SLOT_COUNT:
            item_inventory[i] = clone_item_data(d) if d else None
    for d in character_data.get("backpack_inventory", []):
        if len(backpack_inventory) < BACKPACK_SLOT_COUNT:
            entry = clone_item_data(d)
            if not item_is_food(entry):
                backpack_inventory.append(entry)
    for i in range(HOTBAR_SLOT_COUNT):
        if item_is_food(item_inventory[i]):
            item_inventory[i] = None
    # New characters start with 4 health potions + Book of Teleportation
    if not character_data.get("item_inventory") and not character_data.get("backpack_inventory"):
        for i in range(4):
            item_inventory[i] = {"id": f"starter_hp_{i}", "name": "Health Potion", "effect": "hp_60",
                "icon": (19, 1), "color": (200, 60, 60), "rarity": "common",
                "item_type": "consumable", "equip_slot": "", "desc": "Restores 60 HP."}
        backpack_inventory.append(dict(TELEPORT_BOOK_ITEM))
    # Ensure existing characters also have the Book of Teleportation
    _has_teleport_book = any(
        str(s.get("id", "") if s else "") == "book_of_teleportation"
        for s in list(item_inventory) + list(backpack_inventory)
    )
    if not _has_teleport_book:
        backpack_inventory.append(dict(TELEPORT_BOOK_ITEM))
        
    quest_states: Dict[str, str] = dict(character_data.get("quest_states", {}))
    quest_progress: Dict[str, List[int]] = {k: list(v) for k, v in character_data.get("quest_progress", {}).items()}
    
    show_crafting = False
    show_professions = False
    show_professions = False
    show_quest_log = False
    quest_actions_from_vendor = False
    quest_vendor_role: Optional[str] = None
    show_character = False

    # ── Delete-item confirmation dialog (WoW-style "type DELETE") ─────────────
    delete_confirm_item: Optional[Dict[str, object]] = None   # item pending deletion
    delete_confirm_source: str = ""   # "backpack:N" or "equip:slot"
    delete_confirm_typed: str = ""    # what the player has typed so far

    crafting_selected: Optional[str] = character_data.get("selected_recipe")
    selected_profession = str(character_data.get("selected_profession", PROFESSION_ORDER[0] if PROFESSION_ORDER else "alchemy"))
    
    profession_state: Dict[str, Dict[str, float]] = {
        pid: {"skill": 1.0, "xp": 0.0, "crafted": 0.0} for pid in PROFESSION_ORDER
    }
    saved_prof = character_data.get("profession_state", {})
    for pid, val in saved_prof.items():
        if pid in profession_state:
            profession_state[pid] = val

    dialogue_flags: Set[str] = set(character_data.get("dialogue_flags", []))
    character_data["dialogue_flags"] = dialogue_flags
            
    quest_selected: Optional[str] = None         # selected quest id in quest log
    crafting_rects: Dict[str, pygame.Rect] = {}
    profession_tab_rects: Dict[str, pygame.Rect] = {}
    profession_craft_rect = pygame.Rect(0, 0, 0, 0)
    quest_rects: Dict[str, pygame.Rect] = {}
    speed_boost_timer = 0.0
    potion_last_used_ms: int = 0   # ms timestamp of last potion use (anti-repeat guard)
    show_spellbook: bool = False   # WoW-style spellbook overlay toggle [N]
    spellbook_tab: str = "class"   # active tab: "class" | "passive" | "general"
    bonus_max_hp = float(character_data.get("bonus_max_hp", 0.0))
